-- Poems batch 241
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('4b2224a1-867b-47bf-a93c-03e413b75fea','送北征人','釋文珦','宋','宋诗','song-poetry','','[]','與君俱是客，那復送君行。',48,'全唐诗/poet.song.219000.json','["與君俱是客，那復送君行。", "未卜重逢日，難爲欲別情。", "露花皆遠淚，風葉是愁聲。", "到日寒應極，脩途七十程。"]'),
('8b9090f1-e7be-4ebb-b8c5-e02c866fc8ae','休糧僧','釋文珦','宋','宋诗','song-poetry','','[]','禪貌如冰雪，禪心去町畦。',48,'全唐诗/poet.song.219000.json','["禪貌如冰雪，禪心去町畦。", "休糧烟火絕，養氣語言低。", "空室無關鑰，隨身止杖藜。", "不曾遊聚落，終老只山棲。"]'),
('7150121e-fae0-4acb-93b3-d8f9cc9ccb50','送極太初住鄞江寶嚴','釋文珦','宋','宋诗','song-poetry','','[]','閫相招惟重，邦人望亦濃。',48,'全唐诗/poet.song.219000.json','["閫相招惟重，邦人望亦濃。", "欲開新象教，應掃舊狐蹤。", "烟水浮缾錫，雲山應皷鐘。", "寶嚴初變土，遥想雨花重。"]'),
('a4d1f110-99c5-4357-bb50-3fe634853a08','送雅上人自鄞歸杭','釋文珦','宋','宋诗','song-poetry','','[]','之子幡然別，何人伴寂寥。',48,'全唐诗/poet.song.219000.json','["之子幡然別，何人伴寂寥。", "相從非世道，獨去是寒朝。", "目送孤帆遠，魂隨曉浪消。", "重來須定約，莫待隔江招。"]'),
('c3eb7a83-0249-4ff9-939b-87d81471d8d4','野僧','釋文珦','宋','宋诗','song-poetry','','[]','野僧塵慮盡，住在最深峰。',48,'全唐诗/poet.song.219000.json','["野僧塵慮盡，住在最深峰。", "庭樹巢孤鶴，崖湫宅老龍。", "瀑綃懸百尺，雲幌羃千重。", "靜裏玄機發，登樓夜擊鐘。"]'),
('bf1ae931-e3b1-461a-9b16-363570c843c3','送杞上人歸於潛山','釋文珦','宋','宋诗','song-poetry','','[]','同鄉唯子在，欲別意何如。',48,'全唐诗/poet.song.219000.json','["同鄉唯子在，欲別意何如。", "歸路青苔遠，還家白露初。", "山光圍古邑，溪影渡寒魚。", "須爲過星渚，高風似二疏。"]'),
('2a897a9a-37e4-4dad-b787-1f58f3b6af47','送僧','釋文珦','宋','宋诗','song-poetry','','[]','空山草木秋，相送古原頭。',48,'全唐诗/poet.song.219000.json','["空山草木秋，相送古原頭。", "倦客難爲別，寒蛩替說愁。", "舊房深翠壁，歸路隔滄洲。", "後夜多明月，相思爲上樓。"]'),
('03c18725-cc1b-4de4-9503-ad55f70da1f9','候禽','釋文珦','宋','宋诗','song-poetry','','[]','候禽來報我，春已到園林。',48,'全唐诗/poet.song.219000.json','["候禽來報我，春已到園林。", "凍解通泉脈，風和動草心。", "由來增齒臘，翻是促光陰。", "其可陪人事，衰遲已不任。"]'),
('d1056fe4-d516-4bd6-bc2a-81d7eba25368','竹居','釋文珦','宋','宋诗','song-poetry','','[]','簷外竹珊珊，空房住一間。',48,'全唐诗/poet.song.219000.json','["簷外竹珊珊，空房住一間。", "無人曾到此，老子有餘閑。", "土蝕銅罇綠，苔滋粉壁斑。", "於焉自成樂，遮莫笑癡頑。"]'),
('860ef2e2-4d01-4b16-8aca-0bbb34b84569','懷別越中友人','釋文珦','宋','宋诗','song-poetry','','[]','白首蒼山裏，生涯舊已空。',48,'全唐诗/poet.song.219000.json','["白首蒼山裏，生涯舊已空。", "別離人易遠，江海意無窮。", "夜月悲新蛩，秋烟落斷鴻。", "遥思來往處，朝暮有樵風。"]'),
('393051f3-1b28-4f5a-b7b0-7e607459bfc1','山中秋日懷友','釋文珦','宋','宋诗','song-poetry','','[]','庭樹涼飈入，西山爽氣多。',48,'全唐诗/poet.song.219000.json','["庭樹涼飈入，西山爽氣多。", "獨行清澗曲，閒詠紫芝歌。", "野饌甘黄獨，山衣足薜蘿。", "幽人同此好，何事不相過。"]'),
('eacf0749-8abb-4010-a591-7b8ba35481bc','夜坐','釋文珦','宋','宋诗','song-poetry','','[]','孤蟾如鑑明，照我坐寒更。',48,'全唐诗/poet.song.219000.json','["孤蟾如鑑明，照我坐寒更。", "列宿光芒淡，滿林風露清。", "人行守犬吠，猿過宿禽驚。", "靜趣憑誰會，忘言對短檠。"]'),
('7086e0b3-4e86-429b-9069-3c6a736eee39','古寺','釋文珦','宋','宋诗','song-poetry','','[]','古寺居深處，隨緣掃一房。',48,'全唐诗/poet.song.219000.json','["古寺居深處，隨緣掃一房。", "本圖依水石，因得避炎涼。", "皓鶴巢松潔，青蟲蠹橘香。", "但教終遠俗，貧賤亦何妨。"]'),
('a64a12ca-9b30-4033-9740-cc3e0ee28f91','雪霽','釋文珦','宋','宋诗','song-poetry','','[]','靜寄向空林，於今歲月深。',48,'全唐诗/poet.song.219000.json','["靜寄向空林，於今歲月深。", "因知閒趣味，嬾與俗浮沉。", "霽雪千峰玉，朝陽萬樹金。", "是吾真富貴，不覺動微吟。"]'),
('cc04d696-c989-4df3-9098-5dcb33fdd80a','爲言以道賦巖隠','釋文珦','宋','宋诗','song-poetry','','[]','隠者心常靜，山林迹易安。',48,'全唐诗/poet.song.219000.json','["隠者心常靜，山林迹易安。", "幾年靈運屐，九轉葛玄丹。", "石圃菁苗在，崖房桂影寒。", "豈知塵世窄，萬事雜悲歡。"]'),
('0f06deef-5b72-4215-a762-cbb0c5466768','湖亭','釋文珦','宋','宋诗','song-poetry','','[]','湖波方瀰瀰，柳影自珊珊。',48,'全唐诗/poet.song.219000.json','["湖波方瀰瀰，柳影自珊珊。", "有客坐終日，城中無此閒。", "鳥飛明鏡裏，人語翠帷間。", "月下清尤甚，今宵擬不還。"]'),
('9524bc29-4163-413e-9ed7-84d59829a50e','行止吟','釋文珦','宋','宋诗','song-poetry','','[]','行止定如何，江湖歲月多。',48,'全唐诗/poet.song.219000.json','["行止定如何，江湖歲月多。", "情真疑近傲，語直似傷和。", "野饌甘藜藿，山衣愛薜蘿。", "因同田父熟，學得飯牛歌。"]'),
('e7639ae4-04b0-4fdb-a8d7-efb9ad2efb6f','中殿功德永壽寺産紫芝','釋文珦','宋','宋诗','song-poetry','','[]','厚德孰能名，靈芝自化成。',48,'全唐诗/poet.song.219000.json','["厚德孰能名，靈芝自化成。", "人間無此種，天上合分莖。", "紫蓋隨王母，彤雲表帝京。", "僊家多服餌，鸞鶴共長生。"]'),
('653893ed-b91e-4074-9501-76264b1236a5','聞似道入相因賦詩','釋文珦','宋','宋诗','song-poetry','','[]','盛德方爲貴，虛名底用高。',48,'全唐诗/poet.song.219000.json','["盛德方爲貴，虛名底用高。", "異時游蕩子，今日儗蕭曹。", "紅粉催身朽，清霜入鬢牢。", "勢窮人事改，槐棘等蓬蒿。"]'),
('4b46e648-604f-4dcf-8bbf-542d18315d7a','靜中','釋文珦','宋','宋诗','song-poetry','','[]','靜中觀世道，一一總非真。',48,'全唐诗/poet.song.219000.json','["靜中觀世道，一一總非真。", "齟齬英賢詘，依馮鄙賤伸。", "狂瀾乘颶勢，枯木借藤春。", "何似都忘著，沈潛自養神。"]'),
('fb9996e7-5ed6-4b77-90fc-367f72e065d2','山中道士居','釋文珦','宋','宋诗','song-poetry','','[]','寂寂老僊家，蒼山一逕斜。',48,'全唐诗/poet.song.219000.json','["寂寂老僊家，蒼山一逕斜。", "還丹延日月，洞府足煙霞。", "野鶴千年壽，靈桃幾度花。", "豈知人世上，塵事亂如麻。"]'),
('c693fa81-c1b4-4e19-8f95-418310281ba9','贈孤山道士','釋文珦','宋','宋诗','song-poetry','','[]','多年於此住，賣藥但資身。',48,'全唐诗/poet.song.219000.json','["多年於此住，賣藥但資身。", "窗冷梅花月，門閒柳樹春。", "水妖愁使術，山鶴伴朝真。", "果欲求仙道，惟應自養神。"]'),
('e733302a-6c39-487a-8621-645cb5762ca9','過山家','釋文珦','宋','宋诗','song-poetry','','[]','世外無塵累，幽居趣味長。',48,'全唐诗/poet.song.219000.json','["世外無塵累，幽居趣味長。", "深蹊竹影薄，小圃藥苗香。", "水氣浮溪壁，山風掃石牀。", "頻來從此始，莫怪老夫狂。"]'),
('4a480bbb-0bf5-4fd6-8f1b-d00731345761','野步','釋文珦','宋','宋诗','song-poetry','','[]','野步任吾情，深村復遠坰。',48,'全唐诗/poet.song.219000.json','["野步任吾情，深村復遠坰。", "陂塘波瀰瀰，坡壟麥青青。", "竈婦知蠶性，田夫識地形。", "牧兒尤可喜，記得相牛經。"]'),
('69df14e6-9dbb-4d7e-90ea-50c9c8b123c6','春日野步','釋文珦','宋','宋诗','song-poetry','','[]','春色在筇履，山前山後行。',48,'全唐诗/poet.song.219000.json','["春色在筇履，山前山後行。", "野花隨處發，林鳥百般聲。", "幽徑遥通寺，清流可濯纓。", "村翁忽相值，又得盡閒情。"]'),
('fdb50750-91a3-438c-b444-994887414ce1','野步即事','釋文珦','宋','宋诗','song-poetry','','[]','疊巘復平原，行行足力煩。',48,'全唐诗/poet.song.219000.json','["疊巘復平原，行行足力煩。", "野程難較里，旅食蹔依村。", "棗熟兒童聚，禾收鳥鵲喧。", "徘徊顧風景，不覺念丘園。"]'),
('cac370de-54ef-4d98-9252-e30640a72aec','開襟','釋文珦','宋','宋诗','song-poetry','','[]','開襟坐石床，豈是俗肝腸。',48,'全唐诗/poet.song.219000.json','["開襟坐石床，豈是俗肝腸。", "月露寒秋氣，天風生夜涼。", "禽猿四山寂，松桂滿林香。", "萬事不相接，誰知幽興長。"]'),
('262433ba-fe2c-491a-8f3c-fce6dbe4d8fb','山中雪','釋文珦','宋','宋诗','song-poetry','','[]','中宵霰雪零，寒氣曉來凝。',48,'全唐诗/poet.song.219000.json','["中宵霰雪零，寒氣曉來凝。", "崖樹當中折，山池到底冰。", "芎糜强食肉，松火勝添繒。", "籬戶牢關上，何人喚得譍。"]'),
('d3516291-c47a-4f29-8b4a-b58156dc013b','送僧之華亭','釋文珦','宋','宋诗','song-poetry','','[]','忽爾來相別，携琴便出關。',48,'全唐诗/poet.song.219000.json','["忽爾來相別，携琴便出關。", "此行離日下，何事到雲間。", "郭外遥通海，舟前少見山。", "應思舊棲處，樵屋過秋閒。"]'),
('de1a7be3-2833-4f94-8d83-55f7f6f3f2ab','送襄錦二上人之鄞','釋文珦','宋','宋诗','song-poetry','','[]','春風湖上別，携手欲何之。',48,'全唐诗/poet.song.219000.json','["春風湖上別，携手欲何之。", "細問重來日，那曾有定期。", "舟行江路永，錫掛海峰遲。", "若有東南使，相逢即寄詩。"]'),
('ebd76a9e-093d-4ae3-9bc7-582515805a60','寄西山嵩雪庭','釋文珦','宋','宋诗','song-poetry','','[]','支遁還山去，翛然世外心。',48,'全唐诗/poet.song.219000.json','["支遁還山去，翛然世外心。", "不曾離磵壑，長是愛雲林。", "馬放秋場靜，龍眠夜井深。", "山林如許到，早晚亦相尋。"]'),
('1ccd4e5b-2c01-4444-adea-d22b4822f593','贈隠僧','釋文珦','宋','宋诗','song-poetry','','[]','高僧成獨往，古路少人過。',48,'全唐诗/poet.song.219000.json','["高僧成獨往，古路少人過。", "切柏貞心在，看山靜意多。", "清鐘生響答，空翠與雲和。", "不解相隨住，其如白髮何。"]'),
('d96eacea-4abe-40a3-b871-6911b2923bea','酬源上人見寄','釋文珦','宋','宋诗','song-poetry','','[]','自從相別後，聞過海邦居。',48,'全唐诗/poet.song.219000.json','["自從相別後，聞過海邦居。", "不得陪鄉話，空煩寄遠書。", "林聲隨雨散，溪影度雲虛。", "若遂東遊計，終朝到子廬。"]'),
('0c16c905-3e78-41c8-b9eb-bbdad7f4dcf9','送僧之湖南','釋文珦','宋','宋诗','song-poetry','','[]','交遊星散盡，之子復南行。',48,'全唐诗/poet.song.219000.json','["交遊星散盡，之子復南行。", "惜別悲楊柳，相思寄杜蘅。", "好山須駐錫，惡路莫貪程。", "近得湘中信，湘中寇未平。"]'),
('8d5d186b-af62-4454-9489-658da45cbf1b','哭復荆山','釋文珦','宋','宋诗','song-poetry','','[]','分講南山日，人推學問精。',48,'全唐诗/poet.song.219000.json','["分講南山日，人推學問精。", "彌綸八教網，堅實五言城。", "願力生前重，聲華滅後清。", "家山孤塔在，過者敬如生。"]'),
('88435416-228f-443d-a8f4-bb37ce1cafcd','送敬從可上人','釋文珦','宋','宋诗','song-poetry','','[]','愛君心似我，十載共隨緣。',48,'全唐诗/poet.song.219000.json','["愛君心似我，十載共隨緣。", "離別從茲始，音書何處傳。", "嶺雲迷晚寺，江水入春田。", "遥憶歸棲後，松門獨夜禪。"]'),
('3e22009a-9bc7-4c81-b452-e796fb2377de','鄞中送坦上人歸故里','釋文珦','宋','宋诗','song-poetry','','[]','白雲相見初，而子獨知予。',48,'全唐诗/poet.song.219000.json','["白雲相見初，而子獨知予。", "世態易翻覆，道交難間疏。", "三江同遠棹，此日晚離袪。", "莫放音書絕，東來有鯉魚。"]'),
('f0250967-dace-4105-a138-c6166787e306','送僧歸日本','釋文珦','宋','宋诗','song-poetry','','[]','遠人仍遠別，把手話江臯。',48,'全唐诗/poet.song.219000.json','["遠人仍遠別，把手話江臯。", "積水三韓路，西風八月濤。", "海門山似粒，洋嶼樹如毛。", "他日難通信，想思夢寐勞。"]'),
('9f0f844b-46d2-4d57-b8b2-8bd8e63745bc','天目禪師歸梁渚舊隠','釋文珦','宋','宋诗','song-poetry','','[]','聞師歸渚上，欲盡百年間。',48,'全唐诗/poet.song.219000.json','["聞師歸渚上，欲盡百年間。", "獨鶴知難侶，孤雲不易攀。", "龍盂經幾綴，虎錫上重環。", "禪子多求法，玄門爲啟關。"]'),
('988057cd-a34d-4a8e-9160-fc2d35bec280','孤山懷圓法師','釋文珦','宋','宋诗','song-poetry','','[]','湖水繞孤峰，知曾住此中。',48,'全唐诗/poet.song.219000.json','["湖水繞孤峰，知曾住此中。", "既傷遺塔變，重惜講臺空。", "鵝護晴池乳，鷹呼古樹風。", "唯聞林處士，清節與師同。"]'),
('afffdc1b-3cc9-422e-acff-93deca07a460','持律僧','釋文珦','宋','宋诗','song-poetry','','[]','堅持先佛戒，不染世間緣。',48,'全唐诗/poet.song.219000.json','["堅持先佛戒，不染世間緣。", "過午都忘食，終年只坐禪。", "可曾焚蠹木，長是濾蟲泉。", "何日能相見，同君話五篇。"]'),
('e963ee2d-f831-49a9-8aed-68134b75b210','贈隠僧','釋文珦','宋','宋诗','song-poetry','','[]','禪居既高靜，道氣尤凄清。',48,'全唐诗/poet.song.219000.json','["禪居既高靜，道氣尤凄清。", "不識市朝路，深諳猨鳥情。", "田衣聯槲葉，山火燎松明。", "自說歸棲後，柴門罷送迎。"]'),
('4150ae8e-e07a-4668-b66f-619ad8f6feb3','秋日懷新敬二上人','釋文珦','宋','宋诗','song-poetry','','[]','所知惟二仲，不見意何如。',48,'全唐诗/poet.song.219000.json','["所知惟二仲，不見意何如。", "別後雲山阻，傳來信息虛。", "黍粱收露下，草木變霜餘。", "應有悲秋作，何曾一寄予。"]'),
('c083724a-68f1-4014-8347-90a679958178','霅城重會修蘋州','釋文珦','宋','宋诗','song-poetry','','[]','江湖身不定，十載別年兄。',48,'全唐诗/poet.song.219000.json','["江湖身不定，十載別年兄。", "忽爾重逢面，翻疑是隔生。", "濕雲行有路，細雨落無聲。", "惆悵還分手，扁舟出郡城。"]'),
('d6f73b5c-9040-4a29-bbaf-cf9195e78d8a','太白山老僧','釋文珦','宋','宋诗','song-poetry','','[]','二十里松陰，居來不厭深。',48,'全唐诗/poet.song.219000.json','["二十里松陰，居來不厭深。", "雲迷歸日路，山是暮年心。", "水黑龍移井，風腥虎過林。", "消除萬事盡，時或動微吟。"]'),
('ff838c64-3e7a-4936-b197-17c9c0cf23c7','贈苦行僧','釋文珦','宋','宋诗','song-poetry','','[]','泯然諸念盡，木食貌常羸。',48,'全唐诗/poet.song.219000.json','["泯然諸念盡，木食貌常羸。", "林下身雖老，人間事不知。", "持經被艾衲，禮像爇楓脂。", "不是忘形者，終難學爾爲。"]'),
('e5614bae-417e-4a8b-b769-a6310c7eabf4','追送奎上人還鄞','釋文珦','宋','宋诗','song-poetry','','[]','隨緣遊上國，興盡即言行。',48,'全唐诗/poet.song.219000.json','["隨緣遊上國，興盡即言行。", "今日不辭我，他宵還夢兄。", "出山雲滿橐，歸路水兼程。", "無奈汀洲畔，春風草又生。"]'),
('45616407-4e6f-4bb6-a570-1fd5e3484553','送鑑上人還故山','釋文珦','宋','宋诗','song-poetry','','[]','偶隨流水出，不礙滯人間。',48,'全唐诗/poet.song.219000.json','["偶隨流水出，不礙滯人間。", "道樹多年別，空門此日還。", "瀑飛春澗浄，雲度曉窗閒。", "後會應難定，相思桂滿山。"]'),
('8c351441-419d-40e9-b130-fc5bae703c7a','寄天台萬年淮海禪席','釋文珦','宋','宋诗','song-poetry','','[]','四海今淮海，中年主萬年。',48,'全唐诗/poet.song.219000.json','["四海今淮海，中年主萬年。", "虛空曾悟性，文字不離禪。", "靈瀑煎茶浄，寒株拾菌鮮。", "無由親道話，夢繞石橋煙。"]'),
('f936a470-f604-4912-aa0e-2f7753099993','送極上人歸永嘉','釋文珦','宋','宋诗','song-poetry','','[]','心憶東嘉郡，殘年別上都。',48,'全唐诗/poet.song.219000.json','["心憶東嘉郡，殘年別上都。", "住房拋疏鈔，歸橐带缾盂。", "劚凍江船澀，侵星野飯孤。", "高堂見慈母，驚怪長髭鬚。"]'),
('dd8a96b4-922b-4320-9c15-f10bbca74e41','送通嗣法書僧歸隆興','釋文珦','宋','宋诗','song-poetry','','[]','一千餘里路，知爲爾師行。',48,'全唐诗/poet.song.219000.json','["一千餘里路，知爲爾師行。", "晚嶠踏雲影，春江聞浪聲。", "相逢知有約，又別似無情。", "莫話傳衣事，北宗人恐爭。"]'),
('e7a6ad23-34a5-4f03-a67d-f7868ae1264b','送僧行古歸越','釋文珦','宋','宋诗','song-poetry','','[]','孤雲無定跡，興至即難留。',48,'全唐诗/poet.song.219000.json','["孤雲無定跡，興至即難留。", "獨往經秦望，相期隠沃洲。", "雪晴分去路，風急阻行舟。", "舊住如相問，惟煩話旅遊。"]'),
('13dd27c1-3623-40de-89e8-671a4ed84164','郊行遣興','釋文珦','宋','宋诗','song-poetry','','[]','節序易推遷，行行感暮年。',48,'全唐诗/poet.song.219000.json','["節序易推遷，行行感暮年。", "麥雲黄冒隴，柳浪綠浮川。", "倦鳥猶知返，飄蓬最可憐。", "故鄉無舊業，何計賦歸田。"]'),
('dbf8893b-59f8-484b-b62f-5bf3cc6c5d70','真樂  其一','釋文珦','宋','宋诗','song-poetry','','[]','人皆有所樂，此樂獨吾真。',48,'全唐诗/poet.song.219000.json','["人皆有所樂，此樂獨吾真。", "一靜滅萬慮，空房無點塵。", "雪清梅骨骼，烟養竹精神。", "羈絏徒千丈，難拘散誕身。"]'),
('649dd714-f86e-48ac-bbdd-369e34e18b11','真樂  其二','釋文珦','宋','宋诗','song-poetry','','[]','歲律又將窮，山房四壁空。',48,'全唐诗/poet.song.219000.json','["歲律又將窮，山房四壁空。", "水雲蹤不異，松柏性元同。", "睡起蹲鴟熟，香消貝葉終。", "誰知真樂事，却在寂寥中。"]'),
('101d165d-e4d2-4aee-a91a-67da288580d0','題故人溪亭','釋文珦','宋','宋诗','song-poetry','','[]','石泉清浸檻，終日遠囂紛。',48,'全唐诗/poet.song.219000.json','["石泉清浸檻，終日遠囂紛。", "境與禪心會，源從靜處分。", "亂峰寒蔽日，斷壁晝生雲。", "向此長棲止，何人得似君。"]'),
('0ca30ba1-4bff-4578-9070-5f40d4bcdd0d','東湖北崦人家','釋文珦','宋','宋诗','song-poetry','','[]','柴門映石柟，茅屋似僧庵。',48,'全唐诗/poet.song.219000.json','["柴門映石柟，茅屋似僧庵。", "蠶候家人熟，耕時父老諳。", "設罝當兔徑，添竹護魚潭。", "賽雨鳴簫皷，迎神向水南。"]'),
('fb5df85f-6425-4189-beab-81387307c416','江上人家','釋文珦','宋','宋诗','song-poetry','','[]','江人遂生理，社甕足新醅。',48,'全唐诗/poet.song.219000.json','["江人遂生理，社甕足新醅。", "家有兒童樂，門無官吏來。", "潮生漁市合，風便客帆開。", "水廟迎神罷，喧喧皷笛迴。"]'),
('d30df2e2-d8ee-4a15-89a0-b6f150c491cf','冬日山崦人家','釋文珦','宋','宋诗','song-poetry','','[]','曲崦人家少，謀生各自安。',48,'全唐诗/poet.song.219000.json','["曲崦人家少，謀生各自安。", "墾耕因地力，墐塞禦天寒。", "獵火明深嶠，漁梁露淺灘。", "老翁知客醉，語不到悲歡。"]'),
('cfe715f0-f9f8-453c-8520-614243af1752','溪上野人家','釋文珦','宋','宋诗','song-poetry','','[]','隔水兩三家，荆扉带郭斜。',48,'全唐诗/poet.song.219000.json','["隔水兩三家，荆扉带郭斜。", "春風喧燕雀，時雨足桑麻。", "翁媼皆垂白，衣冠不尚華。", "烏蓬船一隻，出入渡頭沙。"]'),
('878549dd-a36b-486d-96e3-4ef38c91d56c','向樂古移居山中','釋文珦','宋','宋诗','song-poetry','','[]','高懷厭古市，買屋住深峰。',48,'全唐诗/poet.song.219000.json','["高懷厭古市，買屋住深峰。", "束帛不可聘，世人那易逢。", "故家遺石皷，好景對金鐘。", "得句憑誰會，長歌慰井龍。"]'),
('3c7a5ed6-c126-4382-8ccd-c04fc897e2de','贈牛羊司范月谿','釋文珦','宋','宋诗','song-poetry','','[]','莫嫌司職小，先聖亦曾爲。',48,'全唐诗/poet.song.219000.json','["莫嫌司職小，先聖亦曾爲。", "蕃息更何事，蕭閒且賦詩。", "爾牲誠具止，爾牧自來思。", "考牧宣王雅，應拈短笛吹。"]'),
('1b9c626a-38c1-4dab-abd5-972f09bc8bbb','贈山友','釋文珦','宋','宋诗','song-poetry','','[]','此地長依止，人間境亦偏。',48,'全唐诗/poet.song.219000.json','["此地長依止，人間境亦偏。", "壁蘿斜引蔓，崖竹倒垂鞭。", "野鶴通秋夢，妖狐恐夜禪。", "願來相伴住，解脫世間緣。"]'),
('3f0074a0-fd85-44da-8a12-8d90cb0ffd12','贈林隠君','釋文珦','宋','宋诗','song-poetry','','[]','閒居已二毛，破屋翳蓬蒿。',48,'全唐诗/poet.song.219000.json','["閒居已二毛，破屋翳蓬蒿。", "短笛清風在，長吟白雪高。", "籬腰懸瓠小，柳癭繫船牢。", "自是嫌機事，寧持抱甕勞。"]'),
('cf42c6e2-e254-4301-a24d-8911a02543d2','贈同志','釋文珦','宋','宋诗','song-poetry','','[]','忘情三十載，曾不厭頑疏。',48,'全唐诗/poet.song.219000.json','["忘情三十載，曾不厭頑疏。", "白石能同煮，青山亦共居。", "猨聲依樹樂，鳥影入雲虛。", "聞道黄精熟，相呼又荷鉏。"]'),
('b3d09b12-3637-4bd8-a32d-d230b6303a63','春遊','釋文珦','宋','宋诗','song-poetry','','[]','風和宿雨晴，幽屨出柴荆。',48,'全唐诗/poet.song.219000.json','["風和宿雨晴，幽屨出柴荆。", "好鳥各相語，野花如有情。", "心閒何用隠，身健豈須名。", "今日不行樂，真成孤此生。"]'),
('a604f57e-44f1-41c8-a777-e061bc468f74','幽處','釋文珦','宋','宋诗','song-poetry','','[]','幽處絕煩喧，白雲常在門。',48,'全唐诗/poet.song.219000.json','["幽處絕煩喧，白雲常在門。", "高歌動澗壑，空境外乾坤。", "洗眼菖蒲水，輕身枸杞根。", "閒中存至樂，難與俗人言。"]'),
('da25ce2d-94e2-4474-8721-8ffda02447ef','野處','釋文珦','宋','宋诗','song-poetry','','[]','野處日多暇，扶藜信脚行。',48,'全唐诗/poet.song.219000.json','["野處日多暇，扶藜信脚行。", "荒原寒鴨陣，深巷午雞聲。", "隨地有幽事，閒人無滯情。", "歸來新月上，照我入柴荆。"]'),
('722332bc-55b8-43d6-9d10-f9d94f8219fc','山中吟','釋文珦','宋','宋诗','song-poetry','','[]','山林雖寂寞，亦可息塵勞。',48,'全唐诗/poet.song.219000.json','["山林雖寂寞，亦可息塵勞。", "野食分猿果，寒衣補毳袍。", "雲蹤常散誕，松貌極孤高。", "賦詠隨吾意，無心更擬騷。"]'),
('a3887063-f552-48b8-8633-43448dec0e96','蓬戶','釋文珦','宋','宋诗','song-poetry','','[]','蓬戶何須啟，年來已絕交。',48,'全唐诗/poet.song.219000.json','["蓬戶何須啟，年來已絕交。", "色空原自了，玄白任渠嘲。", "琴譜添新曲，書囊屏舊抄。", "摶風九萬里，安隠愧枝巢。"]'),
('cb3ab86f-e10c-4800-bcdd-4a5bad6924c2','有客','釋文珦','宋','宋诗','song-poetry','','[]','有客老柴荆，終辭世上名。',48,'全唐诗/poet.song.219000.json','["有客老柴荆，終辭世上名。", "因貧諸事省，無位一身輕。", "水月通禪意，山雲寄野情。", "草衣兼木食，亦足了餘生。"]'),
('1a5d8466-5427-4d27-b635-9701d91af313','立冬日野外行吟','釋文珦','宋','宋诗','song-poetry','','[]','吟行不憚遥，風景盡堪抄。',48,'全唐诗/poet.song.219000.json','["吟行不憚遥，風景盡堪抄。", "天水清相入，秋冬氣始交。", "飲虹消海曲，宿鴈下塘坳。", "歸去須乘月，松門許夜敲。"]'),
('e1aeada0-824d-40e3-9431-dcfc2fa1f7ba','塵表','釋文珦','宋','宋诗','song-poetry','','[]','塵表多年住，身閒人事稀。',48,'全唐诗/poet.song.219000.json','["塵表多年住，身閒人事稀。", "或時聯敝衲，終日掩柴扉。", "野鶴惟孤唳，寒鴉作陣飛。", "物情從自異，於我總忘機。"]'),
('09aac882-96b3-4ed7-b351-43d73d8ced18','題杲東軒闍維齒不壞輪珠變金色','釋文珦','宋','宋诗','song-poetry','','[]','全德寡知音，浮漚亦易沉。',48,'全唐诗/poet.song.219000.json','["全德寡知音，浮漚亦易沉。", "終因三昧火，始驗一生心。", "講齒猶存玉，輪珠自化金。", "幾多空掩胾，遺臭在山林。"]'),
('d8b90549-1a79-46d5-8d64-a3899ebddd0d','秋分前三日偶成','釋文珦','宋','宋诗','song-poetry','','[]','秋光幾一半，在候已無雷。',48,'全唐诗/poet.song.219000.json','["秋光幾一半，在候已無雷。", "顥氣凝爲露，嘉禾秀出胎。", "燕銜餘暑去，蟲喚嫩寒來。", "泡影非能久，流光又苦催。"]'),
('f7e5b588-3883-430c-81fb-a01cfa85fc74','朱靜佳挽詞','釋文珦','宋','宋诗','song-poetry','','[]','詩有盛唐風，人稱一代雄。',48,'全唐诗/poet.song.219000.json','["詩有盛唐風，人稱一代雄。", "朱絃終自直，白簡豈能公。", "官到升朝止，身隨過電空。", "傷心千里馬，力盡畏塗中。"]'),
('967e1716-e534-418a-81cb-aa5af424d971','殘燈','釋文珦','宋','宋诗','song-poetry','','[]','殘燈閃閃青，蟋蟀怨空庭。',48,'全唐诗/poet.song.219000.json','["殘燈閃閃青，蟋蟀怨空庭。", "骨老似難睡，夢寒還易醒。", "凄涼生倦枕，沆瀣入疏櫺。", "起視東方白，唯餘三兩星。"]'),
('af2db952-ccd2-42a6-a18b-550c9a6ac382','山中暑月','釋文珦','宋','宋诗','song-poetry','','[]','城市如煁竈，輸茲山水鄉。',48,'全唐诗/poet.song.219000.json','["城市如煁竈，輸茲山水鄉。", "松深不見日，瀑近自生涼。", "靜裏疑秋至，吟邊喜晝長。", "蕉衣與紈扇，皆棄在空箱。"]'),
('84756f30-66e5-4812-8e51-156502fbcc03','時當末伏暑氣愈隆老者殊不能堪而舊業荒殘清凉石室無由歸隠因賦是詩','釋文珦','宋','宋诗','song-poetry','','[]','踽踽復睘睘，誰知遠客情。',48,'全唐诗/poet.song.219000.json','["踽踽復睘睘，誰知遠客情。", "衰齡餘六甲，酷暑畏三庚。", "舊業今何有，秋衣亦未成。", "東鄰弄羌管，休作斷腸聲。"]'),
('53f19eeb-fc7f-43b9-87dd-ce48b3cdf0c1','桐州先師塔','釋文珦','宋','宋诗','song-poetry','','[]','耿介絕依憑，清虛尚飲冰。',48,'全唐诗/poet.song.219000.json','["耿介絕依憑，清虛尚飲冰。", "悟明中觀論，度越小乘僧。", "夢已三生破，神應九品陞。", "法門誰得髓，石塔冷孤燈。"]'),
('505d1e39-4aa8-4464-aceb-09466e429c8e','秋日','釋文珦','宋','宋诗','song-poetry','','[]','秋氣清如此，閒蹤信所如。',48,'全唐诗/poet.song.219000.json','["秋氣清如此，閒蹤信所如。", "因窮流水脈，偶到野僧居。", "地遠囂紛息，山回響答虛。", "幾人來不得，老死向塵車。"]'),
('0409043c-1f5f-47c6-9845-b886b92a11c4','秋懷','釋文珦','宋','宋诗','song-poetry','','[]','西風吹客襟，客正白頭吟。',48,'全唐诗/poet.song.219000.json','["西風吹客襟，客正白頭吟。", "無復歡娛意，惟傷遲暮心。", "飲虹明遠浦，饑鶻下荒林。", "日月不相貸，人生那易禁。"]'),
('fa0249f3-9169-4fdd-bbf2-5213a92c56cc','田父','釋文珦','宋','宋诗','song-poetry','','[]','田父秉耒耜，東郊生意繁。',48,'全唐诗/poet.song.219000.json','["田父秉耒耜，東郊生意繁。", "風和土脈應，雨過水花渾。", "麥隴抽新穗，秧疇腐宿根。", "春耕易爲力，歡笑語兒孫。"]'),
('63ec7ce3-c04e-42f8-8980-bd267b537ee4','旅懷','釋文珦','宋','宋诗','song-poetry','','[]','客路何當極，家林久未還。',48,'全唐诗/poet.song.219000.json','["客路何當極，家林久未還。", "只今明鏡裏，又覺鬢毛斑。", "夜雨添春水，寒雲沒曉山。", "彊吟無好思，佳句也應慳。"]'),
('fb1cdfba-3ab8-4719-9d9a-f796924199fb','綠陰滿院','釋文珦','宋','宋诗','song-poetry','','[]','一年花信過，滿院綠陰多。',48,'全唐诗/poet.song.219000.json','["一年花信過，滿院綠陰多。", "老子於中住，新鶑每到歌。", "蕭閒遺世慮，清浄合天和。", "好是孤雲性，誰能管得他。"]'),
('5e046b18-a97c-45e3-80d3-24bdeb92b9a5','出戶','釋文珦','宋','宋诗','song-poetry','','[]','出戶逢幽客，相携過別村。',48,'全唐诗/poet.song.219000.json','["出戶逢幽客，相携過別村。", "凍開泥徑滑，橋斷石星存。", "雲起難知處，泉流自有源。", "老農心甚適，耕鑿長兒孫。"]'),
('31efbe69-4555-4f6c-949b-517ede32065c','心鏡','釋文珦','宋','宋诗','song-poetry','','[]','不存分別見，真是與盲同。',48,'全唐诗/poet.song.219000.json','["不存分別見，真是與盲同。", "常以身爲觀，因知色即空。", "無生方會道，取相未成功。", "此意吾嘗得，皆歸心鏡中。"]'),
('5aabc466-a8fd-41a0-9649-9d90c9634091','古柏','釋文珦','宋','宋诗','song-poetry','','[]','庭前雙柏子，曾入祖師禪。',48,'全唐诗/poet.song.219000.json','["庭前雙柏子，曾入祖師禪。", "黛色參天古，貞心比石堅。", "材堪舟楫用，名在邶鄘篇。", "歲晚冰霜裏，清標獨蔚然。"]'),
('faa15d99-1acd-4ed5-a6c9-860a5c164e16','初春賡李篔房韻','釋文珦','宋','宋诗','song-poetry','','[]','飄零長是客，節物更催人。',48,'全唐诗/poet.song.219000.json','["飄零長是客，節物更催人。", "前日方辭臘，今朝又得辛。", "一天回暖氣，九陌動遊塵。", "心愛青藜杖，多年伴老身。"]'),
('46c3bffd-36d6-48b1-a96f-49bddf08fb60','忘歸','釋文珦','宋','宋诗','song-poetry','','[]','久作餘英客，溪山似有緣。',48,'全唐诗/poet.song.219000.json','["久作餘英客，溪山似有緣。", "柳堤便野步，竹寺稱幽禪。", "結伴尋沙鷺，忘歸笑杜鵑。", "翛然繩檢外，頗覺勝神仙。"]'),
('057709a5-adec-42f2-ab0a-d45f983e66cc','酬友人見寄','釋文珦','宋','宋诗','song-poetry','','[]','山房一事無，開篋理殘書。',48,'全唐诗/poet.song.219000.json','["山房一事無，開篋理殘書。", "習氣嗟難斷，閒情爲折除。", "菊籬秋爛熳，楓徑意蕭疎。", "忽枉瑶華贈，知君又起予。"]'),
('c54b5e42-c8eb-4447-8164-0f8862e16997','酬李篔房見寄','釋文珦','宋','宋诗','song-poetry','','[]','修篔古君子，谿上有清風。',48,'全唐诗/poet.song.219000.json','["修篔古君子，谿上有清風。", "直節應難並，高標自不同。", "嬋娟消俗慮，培養見深功。", "愛此黄鐘管，傳聲到谷中。"]'),
('cabab2dc-f824-46af-a5b9-e2c4ed648283','野老  其一','釋文珦','宋','宋诗','song-poetry','','[]','野老一身輕，於今野趣成。',48,'全唐诗/poet.song.219000.json','["野老一身輕，於今野趣成。", "交遊木上座，疏闊楮先生。", "溪甑炊菰米，山巵咀菊英。", "林園道子好，時復到柴荆。"]'),
('becf73bf-635a-4367-be09-2a194c607bd5','野老  其二','釋文珦','宋','宋诗','song-poetry','','[]','溪頭逢野老，邀我過橋東。',48,'全唐诗/poet.song.219000.json','["溪頭逢野老，邀我過橋東。", "牛卧閒田上，雞鳴村巷中。", "豆乾霜腹飽，蓮倒露房空。", "鄰里交相命，桃源風景同。"]'),
('f6b78a2a-c2a4-49c9-9b5c-a2278a1cff49','老去  其一','釋文珦','宋','宋诗','song-poetry','','[]','老去寡交游，孤吟倚石樓。',48,'全唐诗/poet.song.219000.json','["老去寡交游，孤吟倚石樓。", "風生雲漸散，虹見雨初收。", "蒼莽天將暮，凄清氣似秋。", "玄猿慰岑寂，長嘯碧峰頭。"]'),
('252c7a46-111b-414f-9af7-d6a01abcd574','老去  其二','釋文珦','宋','宋诗','song-poetry','','[]','老去玄衣敝，歸來白屋寒。',48,'全唐诗/poet.song.219000.json','["老去玄衣敝，歸來白屋寒。", "故書多散失，時事轉艱難。", "背日松慳長，經霜菊盡乾。", "鄰翁猶念舊，扶杖數相看。"]'),
('62780c17-07e1-4b9d-b200-7f341f384de0','竹坡舊隠','釋文珦','宋','宋诗','song-poetry','','[]','路轉新塘曲，舟通別墅幽。',48,'全唐诗/poet.song.219000.json','["路轉新塘曲，舟通別墅幽。", "覺華嚴佛地，梵放雜漁謳。", "秔稌連疇晚，菱渠四澤秋。", "竹坡今不作，清淚落菟裘。"]'),
('d2a16096-1dbc-409c-a634-6e1ebf88715d','隠居','釋文珦','宋','宋诗','song-poetry','','[]','隠居那用名，名沒隠方成。',48,'全唐诗/poet.song.219000.json','["隠居那用名，名沒隠方成。", "交絕身常定，心安病不生。", "山肴珍白蕈，野飯美青精。", "回視人間世，何如戲一棚。"]'),
('24548b84-015d-4ae0-b8e0-135a4c2358ab','嚴維石端研詩','釋文珦','宋','宋诗','song-poetry','','[]','端溪下巖石，縋鑿出重淵。',48,'全唐诗/poet.song.219000.json','["端溪下巖石，縋鑿出重淵。", "溫澤非人力，精華得自然。", "龍涎紫霞聚，鵒眼碧光圓。", "玉德終無變，斯文萬古傳。"]'),
('ad359c56-7f20-4a48-ae28-27b86f5ce32d','稻熟而遭巨浸以詩傷之','釋文珦','宋','宋诗','song-poetry','','[]','九秋禾正熟，三日雨滂沱。',48,'全唐诗/poet.song.219000.json','["九秋禾正熟，三日雨滂沱。", "畎畝黄雲失，溝塍白水多。", "豈知民已病，猶苦賦重科。", "父子難相保，流離可奈何。"]'),
('0a77c42b-13ab-4bed-8f68-df409fef1b25','咏梅  其一','釋文珦','宋','宋诗','song-poetry','','[]','仙姿孤潔甚，不與衆芳期。',48,'全唐诗/poet.song.219000.json','["仙姿孤潔甚，不與衆芳期。", "的皪臨寒澗，凄清闖短籬。", "祗愁風作惡，最與雪相宜。", "野叟心偏愛，莓苔古怪枝。"]'),
('2b13da12-ae7d-42a3-b0a7-bb5edb87d1ba','咏梅  其二','釋文珦','宋','宋诗','song-poetry','','[]','萬木凋零盡，知經幾度霜。',48,'全唐诗/poet.song.219000.json','["萬木凋零盡，知經幾度霜。", "獨餘冰玉質，薰得夢魂香。", "影入清泉瘦，聲傳畫角長。", "每因春爛熳，惆悵失孤芳。"]'),
('81f4f55f-230a-4796-8eb6-ef0bc0114b9c','咏梅  其三','釋文珦','宋','宋诗','song-poetry','','[]','怪怪復奇奇，照溪三兩枝。',48,'全唐诗/poet.song.219000.json','["怪怪復奇奇，照溪三兩枝。", "首陽清骨骼，姑射靜丰姿。", "桃李應非伍，松筠素有期。", "憑他伴幽寂，玉笛且休吹。"]'),
('ce7f1c2c-c214-4fed-989c-6fa2fc8d047c','冬日','釋文珦','宋','宋诗','song-poetry','','[]','交因貧盡絕，嬾與病相兼。',48,'全唐诗/poet.song.219000.json','["交因貧盡絕，嬾與病相兼。", "客裏朱顔失，吟中白髮添。", "衲衣冬未補，霜氣夜來嚴。", "坐待朝曦上，支離曝短簷。"]'),
('18245a9b-8446-4396-82be-115d34b70c3d','元日作是歲除夕立春','釋文珦','宋','宋诗','song-poetry','','[]','臘窮春自至，四序遞相延。',48,'全唐诗/poet.song.219000.json','["臘窮春自至，四序遞相延。", "玄髮成華髮，添年是減年。", "嶰筒灰已動，象魏法初懸。", "吾獨存吾道，凝然不受遷。"]'),
('a9adb8ba-49da-4a9d-ba2f-e7bd2f3e5783','錢塘江潮','釋文珦','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','初聞萬馬聲，漸覺似長城。',48,'全唐诗/poet.song.219000.json','["初聞萬馬聲，漸覺似長城。", "遠自三山起，高連兩岸平。", "淩風添怒勢，映日作虛明。", "若是吳胥魄，如何渡越兵。"]'),
('e75c4496-4e5e-484c-a26d-811e7a34bc28','農父','釋文珦','宋','宋诗','song-poetry','','[]','農家逢樂歲，歡笑自村村。',48,'全唐诗/poet.song.219000.json','["農家逢樂歲，歡笑自村村。", "麰麥黄鋪野，桑麻綠映門。", "簄梁收鰋鯉，圈柵足雞豚。", "古廟高楓下，迎神皷笛喧。"]'),
('04e7cb79-db53-4ba5-9e68-62aa2cbefdb6','暮春書懷','釋文珦','宋','宋诗','song-poetry','','[]','青春還又暮，草樹各相高。',48,'全唐诗/poet.song.219000.json','["青春還又暮，草樹各相高。", "細雨啼姑惡，微風飛伯勞。", "壯懷消白髮，隱跡寄玄袍。", "萬事何須計，人生各有遭。"]'),
('fcf1e80b-9b3e-4068-928e-6bab59f489df','嬾出','釋文珦','宋','宋诗','song-poetry','','[]','年衰常嬾出，經歲坐衡茅。',48,'全唐诗/poet.song.219000.json','["年衰常嬾出，經歲坐衡茅。", "適俗無新韻，因貧失故交。", "厨空鳴蟋蟀，簷靜落蠨蛸。", "獨有吟詩癖，如今亦盡拋。"]'),
('8164cf98-bf91-4f9e-97bb-df27a2eaf2ca','衡茅','釋文珦','宋','宋诗','song-poetry','','[]','衡茅隠翠層，聊以盡殘形。',48,'全唐诗/poet.song.219000.json','["衡茅隠翠層，聊以盡殘形。", "得性非常道，忘言是此經。", "孤標松落落，晚節竹青青。", "此外非吾事，來言總不聽。"]'),
('967f252b-2646-46c1-b547-6027e6aa9c68','偃息','釋文珦','宋','宋诗','song-poetry','','[]','偃息冷雲邊，悠然白已玄。',48,'全唐诗/poet.song.219000.json','["偃息冷雲邊，悠然白已玄。", "動時皆物役，靜處是吾天。", "虛牖延蘿月，連筒引竹泉。", "心期終不出，就此了餘年。"]'),
('c2b8506b-97a2-4009-9b90-fd50d7496fc4','息影','釋文珦','宋','宋诗','song-poetry','','[]','息影塵埃表，安心靜默間。',48,'全唐诗/poet.song.219000.json','["息影塵埃表，安心靜默間。", "若爲消白日，長是對青山。", "流水欲窮處，野猿相與還。", "孤雲時起滅，未必似余閒。"]'),
('edc8fd3a-b1d0-414e-92b6-dbefa6af72bf','秋日禪房','釋文珦','宋','宋诗','song-poetry','','[]','絕巘秋光裏，禪房夜氣清。',48,'全唐诗/poet.song.219000.json','["絕巘秋光裏，禪房夜氣清。", "天風吹鶴夢，山月照猿聲。", "性懶諸緣絕，身閒四體輕。", "生來自蕭散，不是彊遺名。"]'),
('7a0c56fd-2546-4e41-946f-6ad728b7646d','農戶','釋文珦','宋','宋诗','song-poetry','','[]','農戶竹林西，茅簷傍水低。',48,'全唐诗/poet.song.219000.json','["農戶竹林西，茅簷傍水低。", "黄雞四五隻，青韭兩三畦。", "社甕醅堪漉，秋田秫又齊。", "老翁留客住，爲具任山妻。"]'),
('d854fbf3-b49a-4e82-947d-5776c10370dc','農居','釋文珦','宋','宋诗','song-poetry','','[]','農居深且僻，城市不相聞。',48,'全唐诗/poet.song.219000.json','["農居深且僻，城市不相聞。", "草路縱橫入，柴門向背分。", "兒童知放牧，父老念耕耘。", "但願桑麻長，勤勞豈足云。"]'),
('b622dcdb-e610-49fd-92d4-b4a7227f858f','山房','釋文珦','宋','宋诗','song-poetry','','[]','山房孟冬月，獨坐對殘缸。',48,'全唐诗/poet.song.219000.json','["山房孟冬月，獨坐對殘缸。", "侍者嫌貧去，詩魔以靜降。", "霜威寒透衲，月色碎穿窗。", "萬法皆非侶，令人憶老龐。"]'),
('520b3a98-27f5-4e7a-b691-08f8bf3f419b','空中','釋文珦','宋','宋诗','song-poetry','','[]','空中窴至理，彼我兩俱忘。',48,'全唐诗/poet.song.219000.json','["空中窴至理，彼我兩俱忘。", "自有心如鐵，寧嫌鬢似霜。", "清泉隨澗遠，古屋入雲長。", "此是吾安處，陶然樂未央。"]'),
('f65ba427-0af3-4420-b634-81ea4fdea771','物我','釋文珦','宋','宋诗','song-poetry','','[]','物我兩俱忘，隤然入道鄉。',48,'全唐诗/poet.song.219000.json','["物我兩俱忘，隤然入道鄉。", "空爲真命脈，靜是悟肝腸。", "竹月光零亂，松風韻短長。", "色聲皆妙契，曾不費思量。"]'),
('cd94889f-47d7-407c-abce-b41e87eb16e8','樗櫟','釋文珦','宋','宋诗','song-poetry','','[]','樗櫟非時用，悠悠任散材。',48,'全唐诗/poet.song.219000.json','["樗櫟非時用，悠悠任散材。", "自歸孤嶂下，已是十年來。", "世慮消除盡，閒門少得開。", "相過但清話，嬾不置茶杯。"]'),
('a9d79c97-a922-41c6-ad67-e9ec541b20c7','身老','釋文珦','宋','宋诗','song-poetry','','[]','身老心仍懶，深棲樂此園。',48,'全唐诗/poet.song.219000.json','["身老心仍懶，深棲樂此園。", "飲冰難變節，卧雪不開門。", "八尺藜牀輭，三重紙被溫。", "傷懷惟一事，凍破石陶尊。"]'),
('27ddd024-2796-4cc1-84cc-eb29da11ff14','吾心','釋文珦','宋','宋诗','song-poetry','','[]','吾心偏向靜，物外寄柴荆。',48,'全唐诗/poet.song.219000.json','["吾心偏向靜，物外寄柴荆。", "山意深方好，溪源遠自清。", "餘生惟欠死，衆慮已皆平。", "隠者宜無迹，人休問姓名。"]'),
('b7a0e136-d75a-4aa3-99de-d6bc1385bb1a','夜氣','釋文珦','宋','宋诗','song-poetry','','[]','夜氣正冥冥，閒人夢已醒。',48,'全唐诗/poet.song.219000.json','["夜氣正冥冥，閒人夢已醒。", "上方風磬斷，小室雨燈青。", "照鏡諸心靜，忘緣四體寧。", "勝他名利客，騎馬戴寒星。"]'),
('0b9e4cc2-d8d5-435c-b8c5-06293567c3b2','老人','釋文珦','宋','宋诗','song-poetry','','[]','老人方外人，觀物又觀身。',48,'全唐诗/poet.song.219000.json','["老人方外人，觀物又觀身。", "得性無今古，隨時亦故新。", "梅容微笑臘，柳意暗藏春。", "除是同懷者，知予此語真。"]'),
('0bad5e1f-a936-4caa-8e0c-90289dd6684a','永晝','釋文珦','宋','宋诗','song-poetry','','[]','永晝絕將迎，禪房似水清。',48,'全唐诗/poet.song.219000.json','["永晝絕將迎，禪房似水清。", "可曾留長物，頗以厭虛名。", "日正樓無影，風迴樹有聲。", "吟章久不弄，今日偶然成。"]'),
('bd7b3710-5cf4-4a75-a1be-506d5953d3e7','爲商隠賦篔房','釋文珦','宋','宋诗','song-poetry','','[]','斯篔非俗本，清韻古今同。',48,'全唐诗/poet.song.219000.json','["斯篔非俗本，清韻古今同。", "渭上曾千畝，房邊又一叢。", "月生金散亂，風過玉玲瓏。", "勁節尤宜晚，青青雨露中。"]'),
('064feaaa-29c3-4442-8704-41e85d79b93f','一身','釋文珦','宋','宋诗','song-poetry','','[]','一身誰與偕，病骨老窮崖。',48,'全唐诗/poet.song.219000.json','["一身誰與偕，病骨老窮崖。", "春雨苔封徑，秋風葉滿階。", "翦雲成隠服，煮石當清齋。", "樵客時相過，言予有好懷。"]'),
('18b538b5-1267-4300-a57e-3ede9efc97df','山園叢桂新蘗將抽陳葉皆隕感而成詠','釋文珦','宋','宋诗','song-poetry','','[]','草木隨時變，由來不少停。',48,'全唐诗/poet.song.219000.json','["草木隨時變，由來不少停。", "新萌將欲吐，陳葉已先零。", "便可知浮世，無由固此形。", "保常同醉夢，曾有幾人醒。"]'),
('31bfbd1e-a59e-43ab-870b-269b77082b68','室空','釋文珦','宋','宋诗','song-poetry','','[]','室空無侍者，坐卧一團蒲。',48,'全唐诗/poet.song.219000.json','["室空無侍者，坐卧一團蒲。", "但見朝還暮，焉知榮與枯。", "山心便寂寞，天籟聽喁于。", "雲外幽人好，時來問老夫。"]'),
('19b11d30-f244-4c24-a4e4-2846922c1793','晨步','釋文珦','宋','宋诗','song-poetry','','[]','茅堂清潄罷，隨意涉西陵。',48,'全唐诗/poet.song.219000.json','["茅堂清潄罷，隨意涉西陵。", "茅屋冰千柱，高峰雪一稜。", "水渾潮已長，霞淡日初昇。", "更欲過前浦，漁舟喚不譍。"]'),
('ef9a1a95-60f1-487f-80f8-796a60e3e2e1','調琴','釋文珦','宋','宋诗','song-poetry','','[]','羣動夜中息，霜清月滿林。',48,'全唐诗/poet.song.219000.json','["羣動夜中息，霜清月滿林。", "野僧無俗事，幽興寄瑶琴。", "澹澹思歸操，悠悠太古心。", "希聲在自得，不必爲知音。"]'),
('f29ed0ae-c9a2-46aa-a8c7-bad12f329002','郊行','釋文珦','宋','宋诗','song-poetry','','[]','陋室隨緣住，空山信意行。',48,'全唐诗/poet.song.219000.json','["陋室隨緣住，空山信意行。", "何須稱隠逸，且復謝將迎。", "古木青猨性，孤烟白鳥程。", "由來各有適，豈必用浮名。"]'),
('4504d037-9944-4013-9571-29ab880f9450','乘興','釋文珦','宋','宋诗','song-poetry','','[]','乘興不拘程，悠悠任意行。',48,'全唐诗/poet.song.219000.json','["乘興不拘程，悠悠任意行。", "小溪橫木渡，何寺遠鐘聲。", "野菜抽心起，山花照眼明。", "幽禽亦堪愛，多解自呼名。"]'),
('d6dabaae-73cd-4865-b909-29490cc5e7b0','歸來','釋文珦','宋','宋诗','song-poetry','','[]','世變今如此，吾心復背時。',48,'全唐诗/poet.song.219000.json','["世變今如此，吾心復背時。", "皇皇無所與，去去欲何之。", "獨木橋難渡，三叉路可疑。", "歸來差自好，猨鶴舊相知。"]'),
('d5eeb46e-d608-4bca-89de-d4faa835342f','夜讀太玄','釋文珦','宋','宋诗','song-poetry','','[]','虛室冷雲邊，消閒讀太玄。',48,'全唐诗/poet.song.219000.json','["虛室冷雲邊，消閒讀太玄。", "未須求甚解，聊復竟餘篇。", "夜永殘膏薄，天高列宿懸。", "有蓍還懶揲，休咎已俱捐。"]'),
('cc89554f-16fd-48f2-b7fa-d56505570cbe','年來','釋文珦','宋','宋诗','song-poetry','','[]','年來已絕交，孤憩竹間寮。',48,'全唐诗/poet.song.219000.json','["年來已絕交，孤憩竹間寮。", "境寂身逾嬾，神安息自調。", "雲開山意靜，風止樹聲消。", "自足全無樂，誰能問市朝。"]'),
('e29a0dd4-0192-45ca-a60f-5d217fd12902','世路','釋文珦','宋','宋诗','song-poetry','','[]','世路古來難，深居息萬端。',48,'全唐诗/poet.song.219000.json','["世路古來難，深居息萬端。", "道因無欲勝，山不厭人看。", "石碓寒流淺，畬田遠燒殘。", "未嫌生意少，老子自能安。"]'),
('62f4d838-d0d7-40b6-8aa8-5161d6040bfe','臘月立春雪後谿行偶作','釋文珦','宋','宋诗','song-poetry','','[]','踽踽白頭人，江湖寡所親。',48,'全唐诗/poet.song.219000.json','["踽踽白頭人，江湖寡所親。", "故鄉千里念，閏歲兩番春。", "北雪歌黄竹，東風變綠蘋。", "此中來往熟，不問自知津。"]'),
('54433983-8fc7-4788-b79e-89de9a53b926','春日病起','釋文珦','宋','宋诗','song-poetry','','[]','暮景交朋盡，何人問死生。',48,'全唐诗/poet.song.219000.json','["暮景交朋盡，何人問死生。", "卧於蝸室底，看得鵲巢成。", "緣絕門常靜，心空疾漸平。", "又思扶杖出，溪上聽泉聲。"]'),
('1e14dd9b-840e-4f56-85fb-be5b0c6fc02d','朽質','釋文珦','宋','宋诗','song-poetry','','[]','朽質任浮沉，都無住著心。',48,'全唐诗/poet.song.219000.json','["朽質任浮沉，都無住著心。", "未凴三窟兔，得似九臯禽。", "煮石清泉潔，眠雲翠壁深。", "生來有詩癖，老去亦忘吟。"]'),
('a8331d12-1e45-4679-a993-036bbb78d1c7','梅柟','釋文珦','宋','宋诗','song-poetry','','[]','梅柟三四樹，手種近巖房。',48,'全唐诗/poet.song.219000.json','["梅柟三四樹，手種近巖房。", "始見條抽綠，俄驚葉隕黄。", "物情殊易變，身世豈能常。", "且盡修心法，休傳却死方。"]'),
('4f62293a-418f-4113-8b31-b44d71555f4b','地僻','釋文珦','宋','宋诗','song-poetry','','[]','地僻鄰居少，蕭條獨掩關。',48,'全唐诗/poet.song.219000.json','["地僻鄰居少，蕭條獨掩關。", "還因萬事拙，分得一生閒。", "野水皆歸壑，孤雲不離山。", "白鷗知我性，渾不怪疎頑。"]'),
('45860477-500f-4fdd-9160-ea9bd798eea9','堪歎','釋文珦','宋','宋诗','song-poetry','','[]','堪歎是衰年，年年白髮添。',48,'全唐诗/poet.song.219000.json','["堪歎是衰年，年年白髮添。", "客身窮鬼狎，古道俗人嫌。", "當作凌霄鶴，休爲上竹鮎。", "到頭歸去好，祇合效陶潛。"]'),
('b58cc775-90e8-45fe-99c2-8175b1bd790d','忘己','釋文珦','宋','宋诗','song-poetry','','[]','身榮如美疢，身退是良方。',48,'全唐诗/poet.song.219000.json','["身榮如美疢，身退是良方。", "雲月皆成趣，悲歡不入腸。", "閑門清晝永，宴坐綠陰涼。", "昔者惟忘物，今焉己亦忘。"]'),
('c4941f95-af91-4a78-b04f-55c669131e4f','山林古松','釋文珦','宋','宋诗','song-poetry','','[]','古松形甚怪，得性在山林。',48,'全唐诗/poet.song.219000.json','["古松形甚怪，得性在山林。", "偃蓋盤空老，流脂入地深。", "青霜曾換骨，野火誤燒心。", "材大誠難用，良工亦漫尋。"]'),
('fa44bc72-5aeb-46eb-8fde-abbcb527b078','閒房','釋文珦','宋','宋诗','song-poetry','','[]','閒房近竺岑，四面是清陰。',48,'全唐诗/poet.song.219000.json','["閒房近竺岑，四面是清陰。", "涉物皆成趣，無因廢得吟。", "蛇蟠枯樹腹，雀乳古亭心。", "倘或遊人見，猶疑隠欠深。"]'),
('d6e0c452-4936-4d27-bdee-b8dbc7157584','幽步','釋文珦','宋','宋诗','song-poetry','','[]','僻好唯泉石，深居任草萊。',48,'全唐诗/poet.song.219000.json','["僻好唯泉石，深居任草萊。", "寧辭幽步遠，且放好懷開。", "綠樹鶑求友，青坡雉應媒。", "因逢道人語，月出始能回。"]'),
('9e92018a-c853-43e7-92da-b10f523da692','晚步','釋文珦','宋','宋诗','song-poetry','','[]','秋色徧西原，行吟野興存。',48,'全唐诗/poet.song.219000.json','["秋色徧西原，行吟野興存。", "坂田通堰熟，溪水度灘喧。", "宿鳥分投樹，歸牛各認村。", "幽居乘夜返，松月在衡門。"]'),
('0825c244-1ef0-4640-96ab-7491612ec08f','賡李篔房韻','釋文珦','宋','宋诗','song-poetry','','[]','故國頻關夢，春深一到來。',48,'全唐诗/poet.song.219000.json','["故國頻關夢，春深一到來。", "却因風景異，便棹雨舟回。", "其可忘諸夏，真堪賦七哀。", "天居曾入處，滿目是寒苔。"]'),
('e4fd356f-886b-492c-82bd-a717ed3122f3','曝背','釋文珦','宋','宋诗','song-poetry','','[]','老知身是患，萬事不關心。',48,'全唐诗/poet.song.219000.json','["老知身是患，萬事不關心。", "曝背茅簷下，孤猨時一吟。", "白雲同去住，青壁共幽深。", "小嶺尤堪隠，難尋支道林。"]'),
('42921c84-3f97-41de-893f-ab4f1ebfacb9','焙茶','釋文珦','宋','宋诗','song-poetry','','[]','異荈雲邊得，山房手自烘。',48,'全唐诗/poet.song.219000.json','["異荈雲邊得，山房手自烘。", "頗思同陸羽，全覺似盧仝。", "孤閲當先破，仙靈更可通。", "蓬萊知遠近，我欲便乘風。"]'),
('21ad7245-b783-4fc7-896f-d9a76e906ee5','秋夜月下獨吟','釋文珦','宋','宋诗','song-poetry','','[]','看月倚修桐，寥寥夜正中。',48,'全唐诗/poet.song.219000.json','["看月倚修桐，寥寥夜正中。", "西郊金氣肅，南陸火雲空。", "繞樹徒憐鵲，傳書未有鴻。", "浩歌誰與和，禪意自相通。"]'),
('e0a75437-b7f8-42c3-9900-2810ce7c9d83','秋懷','釋文珦','宋','宋诗','song-poetry','','[]','寂寥誰共語，白髮對寒流。',48,'全唐诗/poet.song.219000.json','["寂寥誰共語，白髮對寒流。", "往事渾疑夢，餘生祇似浮。", "青蟲鳴向夕，玄鳥去因秋。", "故友滄江外，茫茫不可求。"]'),
('9d32afab-159b-404a-9367-236ab524867f','種植','釋文珦','宋','宋诗','song-poetry','','[]','種植有良法，曾聞老圃辭。',48,'全唐诗/poet.song.219000.json','["種植有良法，曾聞老圃辭。", "靈苗如已茂，惡草自然萎。", "根本須培養，生枯勿顧思。", "修身亦如此，於理足堪推。"]'),
('d9c1226e-9d89-4634-8a7d-2e7ae3281646','閒居','釋文珦','宋','宋诗','song-poetry','','[]','影不落人間，空門斷往還。',48,'全唐诗/poet.song.219000.json','["影不落人間，空門斷往還。", "心如灰已死，身與石同頑。", "洗耳清𣂏瀑，搘筇靜對山。", "老僧閒甚富，誰欲賈予閒。"]'),
('23f96239-aae7-421a-9958-a7713cd52f93','荒徑  其一','釋文珦','宋','宋诗','song-poetry','','[]','荒徑入林微，蓬廬客到稀。',48,'全唐诗/poet.song.219000.json','["荒徑入林微，蓬廬客到稀。", "苔痕侵藥裹，山色冷吟衣。", "蚯蚓耕泥起，蜻蜓點水飛。", "坐來忘萬事，靜看宿雲歸。"]'),
('47ed5465-609a-49ea-8960-adf0e82ce0cd','荒徑  其二','釋文珦','宋','宋诗','song-poetry','','[]','幽徑任蓬蒿，衡門閉亦牢。',48,'全唐诗/poet.song.219000.json','["幽徑任蓬蒿，衡門閉亦牢。", "駒寒宜在谷，鶴倦懶鳴皋。", "老樹根流髓，重崖石長膏。", "樵童更閒靜，聽我讀離騷。"]'),
('c9aa3de7-775c-4049-b5d5-ae1bb2bda848','深居','釋文珦','宋','宋诗','song-poetry','','[]','湖海同流盡，深居獨繫匏。',48,'全唐诗/poet.song.219000.json','["湖海同流盡，深居獨繫匏。", "已全忘疏鈔，亦不事推敲。", "水石爲清供，烟霞作澹交。", "隨行一枝錫，高掛在松梢。"]'),
('6631ec12-43a7-4326-8831-1a94f3b8fde6','孤蹤','釋文珦','宋','宋诗','song-poetry','','[]','孤踪不擇地，陵上即安陵。',48,'全唐诗/poet.song.219000.json','["孤踪不擇地，陵上即安陵。", "聊自存吾道，其他無異能。", "禪衣皆芰製，齋鉢但藜蒸。", "更喜交游絕，閒房冷似冰。"]'),
('29824e10-6e40-4d3a-ba2d-1ba005166096','嘉况','釋文珦','宋','宋诗','song-poetry','','[]','嘉况日因仍，山翁樂豈勝。',48,'全唐诗/poet.song.219000.json','["嘉况日因仍，山翁樂豈勝。", "自知梅已熟，人報麥初登。", "外患忘饑渴，中心散滯凝。", "超然出天地，不止似壺冰。"]'),
('58c3c933-9195-441b-95f5-3d2eeaa1a42d','喜故人來訪共論易','釋文珦','宋','宋诗','song-poetry','','[]','讀書無與娛，日夕友猿狙。',48,'全唐诗/poet.song.219000.json','["讀書無與娛，日夕友猿狙。", "喜悅深交至，參同未畫初。", "語邊驚鬼魅，句裏得真儒。", "茲事忘來久，因君又起予。"]'),
('e4bfb0a6-95c7-45c5-9d9b-15bf9b6e9858','螢火','釋文珦','宋','宋诗','song-poetry','','[]','爾質非天賦，唯從腐草生。',48,'全唐诗/poet.song.219000.json','["爾質非天賦，唯從腐草生。", "細微曾未覺，變化亦難明。", "自照光寧遠，羣飛體更輕。", "空教征戍婦，容易動離情。"]'),
('552fc7ef-2b5a-4f05-b2d7-5d6313def18d','自愛','釋文珦','宋','宋诗','song-poetry','','[]','衣裳唯毳衲，飲啄祇簞瓢。',48,'全唐诗/poet.song.219000.json','["衣裳唯毳衲，飲啄祇簞瓢。", "翻爲生涯薄，能令世慮消。", "寒花香不遠，病木葉先凋。", "自愛秋風裏，雲山共寂寥。"]'),
('a335d986-96b4-4ccb-a543-1cd9a6638de6','梅雨','釋文珦','宋','宋诗','song-poetry','','[]','梅雨無時下，霖淫一月餘。',48,'全唐诗/poet.song.219000.json','["梅雨無時下，霖淫一月餘。", "重陰迷早晚，常課廢經書。", "衣潤無由曝，園荒亦欠鋤。", "堯天舜日遠，懷抱若爲舒。"]'),
('b4ba1d8d-b79c-4202-bdc6-d75ed32783ff','世外','釋文珦','宋','宋诗','song-poetry','','[]','世外多幽勝，塵樊豈足云。',48,'全唐诗/poet.song.219000.json','["世外多幽勝，塵樊豈足云。", "泉聲長似樂，山氣自成雲。", "觀象知羲易，安禪悟竺墳。", "貴交休見憶，已與鹿麋羣。"]'),
('f0e2cdf2-982b-49f5-a6d0-41422e481a76','物外','釋文珦','宋','宋诗','song-poetry','','[]','物外煙霞古，幽深斷送迎。',48,'全唐诗/poet.song.219000.json','["物外煙霞古，幽深斷送迎。", "聵僧唯反聽，啼鳥自春聲。", "望嶽山心靜，臨池水觀成。", "豈知趨世者，終日但營營。"]'),
('47e9a731-5f86-4269-9238-be907c1179e3','惜別','釋文珦','宋','宋诗','song-poetry','','[]','風濤晚未止，鼓枻欲何之。',48,'全唐诗/poet.song.219000.json','["風濤晚未止，鼓枻欲何之。", "穉齒便相識，暮年成別離。", "水香浮浦樹，月露滿江蘺。", "明日空凝佇，茫茫無處期。"]'),
('422d7317-cec9-41be-bbf2-037f432ae255','哀理樗散','釋文珦','宋','宋诗','song-poetry','','[]','樗散本靈種，根於廣莫鄉。',48,'全唐诗/poet.song.219000.json','["樗散本靈種，根於廣莫鄉。", "繁陰深雨露，怪節老風霜。", "幸自忘封植，何須較短長。", "世交多未達，爲子重悲傷。"]'),
('d2f1b8dd-7538-4c2b-b020-2563829305cc','哀梅麓樓寺丞  其一','釋文珦','宋','宋诗','song-poetry','','[]','散逸羲皇上，風流晉宋間。',48,'全唐诗/poet.song.219000.json','["散逸羲皇上，風流晉宋間。", "金蓮推寓直，玉筍竟虛班。", "名在方爲重，身榮等是閒。", "知心千古月，耿耿照泉關。"]'),
('2e515744-ad4d-4648-9267-3e5d51f575d9','哀梅麓樓寺丞  其二','釋文珦','宋','宋诗','song-poetry','','[]','道與時人背，多因得所深。',48,'全唐诗/poet.song.219000.json','["道與時人背，多因得所深。", "文章千古印，忠孝一生心。", "棘冷難承澤，梅殘祇在林。", "空門翻有淚，斷斷是知音。"]'),
('00cedf8b-ed4b-4d7e-b0c6-ef436983dfc7','哀梅麓樓寺丞  其三','釋文珦','宋','宋诗','song-poetry','','[]','寄酒全清達，論交不世情。',48,'全唐诗/poet.song.219000.json','["寄酒全清達，論交不世情。", "遠猷期變俗，直氣反傷生。", "屬纊無妻子，營墳尚弟兄。", "九原那可作，腸斷買山盟。"]'),
('27034b54-4c43-484d-9ec1-b9de9ed605f0','詠梅戲效晚唐體','釋文珦','宋','宋诗','song-poetry','','[]','古今人共愛，不獨是林逋。',48,'全唐诗/poet.song.219000.json','["古今人共愛，不獨是林逋。", "樹老枝方怪，花開葉已無。", "月中香冷澹，雪後意清孤。", "長憶山房外，臨溪有一株。"]'),
('52038e49-e5d9-4087-a9af-4c92a0f53ca2','辛巳仲冬二日冬至孟冬晦日偶成  其一','釋文珦','宋','宋诗','song-poetry','','[]','天地一陰陽，推遷見短長。',48,'全唐诗/poet.song.219000.json','["天地一陰陽，推遷見短長。", "後朝方反復，此月謾稱良。", "萍梗餘浮迹，桑榆借晚光。", "有龜還懶卜，唯覺好支牀。"]'),
('30cc8a39-49b8-4cb3-880e-531f007f3f4a','辛巳仲冬二日冬至孟冬晦日偶成  其二','釋文珦','宋','宋诗','song-poetry','','[]','駸駸近一陽，晝短夜偏長。',48,'全唐诗/poet.song.219000.json','["駸駸近一陽，晝短夜偏長。", "打睡工夫到，潛蹤計策良。", "曉霜寒有力，冬日淡無光。", "生怕人相覓，衰翁嬾下牀。"]'),
('7f64acec-1893-4abc-8349-d41c2e064328','歲盡','釋文珦','宋','宋诗','song-poetry','','[]','雲深路不通，獨處歲還窮。',48,'全唐诗/poet.song.219000.json','["雲深路不通，獨處歲還窮。", "盡斷塵勞念，方成隱遯功。", "松疏斜漏日，竹勁老吟風。", "不是遺名者，何由到此中。"]'),
('e6b99917-9d11-4305-8347-aa27688af2c8','地偏','釋文珦','宋','宋诗','song-poetry','','[]','地偏人到稀，倦客老柴扉。',48,'全唐诗/poet.song.219000.json','["地偏人到稀，倦客老柴扉。", "屈指同遊盡，回頭萬事違。", "石泉清夢枕，山月冷禪衣。", "身與孤雲合，無心自在飛。"]'),
('0bddd911-020d-433a-b02e-5a782a7ab911','靜地','釋文珦','宋','宋诗','song-poetry','','[]','適時非所長，靜地閲流光。',48,'全唐诗/poet.song.219000.json','["適時非所長，靜地閲流光。", "舊燕無留影，新鴻有斷行。", "交朋皆謝往，老大足悲傷。", "彊詠多羞澀，追思亦易忘。"]'),
('feb007a2-5afb-44a3-95ee-6d618dab1dc6','山居冬日','釋文珦','宋','宋诗','song-poetry','','[]','嬾隨冬日柳，獨許歲寒松。',48,'全唐诗/poet.song.219000.json','["嬾隨冬日柳，獨許歲寒松。", "無復芳菲意，深棲雲外峰。", "病身寒易縮，老衲澀難縫。", "却喜同懷者，時來問隠蹤。"]'),
('25dcd21f-08b7-43e0-9b56-637f1fb581da','傳聲問我','釋文珦','宋','宋诗','song-poetry','','[]','問我是何人，空門舊隠淪。',48,'全唐诗/poet.song.219000.json','["問我是何人，空門舊隠淪。", "因知身世假，養得性情真。", "短景將沉照，枯株不受春。", "古來黄綺輩，亦復嬾稱臣。"]'),
('685a8e0f-8084-4e71-ba68-9c8aee134e92','野草花','釋文珦','宋','宋诗','song-poetry','','[]','心愛無名草，閒花取次開。',48,'全唐诗/poet.song.219000.json','["心愛無名草，閒花取次開。", "自能追造化，渾不假栽培。", "姚魏傷攀折，楩柟困剪裁。", "祇因非世用，長得保根荄。"]'),
('5cebd325-64d0-4265-b60d-e3e4d999e9de','放浪','釋文珦','宋','宋诗','song-poetry','','[]','放浪一虛舟，江湖七十秋。',48,'全唐诗/poet.song.219000.json','["放浪一虛舟，江湖七十秋。", "見聞遺耳目，生死付浮休。", "寧有機心在，唯同造物游。", "脫然人境外，無喜亦無憂。"]'),
('e52226c0-2cba-4e1f-a62a-09ff6d866e8e','幽懷','釋文珦','宋','宋诗','song-poetry','','[]','野僧如野鹿，畏下白雲層。',48,'全唐诗/poet.song.219000.json','["野僧如野鹿，畏下白雲層。", "遲暮知身幻，疎慵奈世憎。", "烟埋秋徑竹，風閃夜堂燈。", "萬事何須問，幽懷自可憑。"]'),
('a664c3fa-4a1e-4275-8838-076daeecd609','曉別故人','釋文珦','宋','宋诗','song-poetry','','[]','別日不易數，相逢多故情。',48,'全唐诗/poet.song.219000.json','["別日不易數，相逢多故情。", "爲吾留一宿，同子話三生。", "月印秋燈白，霜添夜氣清。", "晨鐘緣底事，還又動離聲。"]'),
('e7c77f98-cdc1-4af8-b12a-4c1429145c23','感舊','釋文珦','宋','宋诗','song-poetry','','[]','山川雖不改，傷感自難窮。',48,'全唐诗/poet.song.219000.json','["山川雖不改，傷感自難窮。", "野樹浮新綠，宮花隕舊紅。", "兩間無異氣，一等是春風。", "萬古乘除理，誰能究始終。"]'),
('10ccd04a-6a07-49e4-a69a-9b47f2f3c93b','不出','釋文珦','宋','宋诗','song-poetry','','[]','饑寒驅不出，忍死住空山。',48,'全唐诗/poet.song.219000.json','["饑寒驅不出，忍死住空山。", "芰製幾回補，荆扉終歲關。", "是非塵外遠，雲月句中閒。", "此意難名道，存諸靜默間。"]'),
('adb350d5-6056-40c6-b8e4-c2c4a6c3a1a9','雪霽別鄉','釋文珦','宋','宋诗','song-poetry','','[]','雪霽別鄉關，經行百里間。',48,'全唐诗/poet.song.219000.json','["雪霽別鄉關，經行百里間。", "溪流殊蕩漾，山色正斕斒。", "民散無多戶，程途轉幾灣。", "衰齡垂八十，未必又重還。"]'),
('4131d915-b92a-4508-943c-335b1d168f58','吟意','釋文珦','宋','宋诗','song-poetry','','[]','朝吟暮亦吟，吟意在山林。',48,'全唐诗/poet.song.219000.json','["朝吟暮亦吟，吟意在山林。", "往事皆如夢，餘生已死心。", "白雲閒到底，黄葉積來深。", "此是吾安處，人休笑陸沉。"]'),
('2a88006f-f33c-4990-9fac-5bf3a981a035','閉戶','釋文珦','宋','宋诗','song-poetry','','[]','閉戶秋風裏，寥寥絕往還。',48,'全唐诗/poet.song.219000.json','["閉戶秋風裏，寥寥絕往還。", "菊開無俗豔，木落見真山。", "心比孤蟾浄，身同野鹿閒。", "困來雖就枕，無夢到人間。"]'),
('bfe8a456-baa1-4b6e-b5a7-d720c0eda597','九日吟','釋文珦','宋','宋诗','song-poetry','','[]','又過一番秋，秋應笑白頭。',48,'全唐诗/poet.song.219000.json','["又過一番秋，秋應笑白頭。", "任教花自笑，其奈我忘憂。", "未死聊游戲，纔亡即罷休。", "應知皆是幻，盡底付悠悠。"]'),
('0557c7bb-9c3f-46f1-8e4d-4caffad4ee92','遊越','釋文珦','宋','宋诗','song-poetry','','[]','吳客來遊古越都，緬懷前事更踟躕。',64,'全唐诗/poet.song.219000.json','["吳客來遊古越都，緬懷前事更踟躕。", "高峰篆刻空秦望，遺廟丹青尚禹謨。", "佛屋幾遷王令宅，官租半入賀家湖。", "日斜欲返烟城去，柳下春船不受呼。"]'),
('612f15db-4c24-4431-b66a-d7e0856b6554','出越城訪歸隠庵主人','釋文珦','宋','宋诗','song-poetry','','[]','何事相尋向此遊，入城不似出城幽。',64,'全唐诗/poet.song.219000.json','["何事相尋向此遊，入城不似出城幽。", "山於屋外參差見，水到門前款曲流。", "樹腹半空栖伏翼，竹梢初動蔓牽牛。", "分明記得前回過，斜月疎鐘到客舟。"]'),
('4addca85-fb8a-4d1d-947f-213a23ab7341','書懷','釋文珦','宋','宋诗','song-poetry','','[]','爲知不是功名骨，換著方袍入翠微。',64,'全唐诗/poet.song.219000.json','["爲知不是功名骨，換著方袍入翠微。", "身事半生貧裏過，家園千里夢中歸。", "尋詩野寺雲黏屐，采藥名山露濕衣。", "似此疎狂爭怪得，從來野鶴自難鞿。"]'),
('c2683188-a58b-4367-a521-f8a84e51ddb1','雁蕩大龍湫','釋文珦','宋','宋诗','song-poetry','','[]','此水昔年人不見，梵僧來說始知名。',64,'全唐诗/poet.song.219000.json','["此水昔年人不見，梵僧來說始知名。", "飛揚半雜烟嵐氣，斷續全同風雨聲。", "四壁倚空疑鬼鑿，一峰當面自天成。", "雖然未作山中住，曾到山中夢亦清。"]'),
('b5cc697f-c080-42b1-8d4a-df56a7d25d81','農家','釋文珦','宋','宋诗','song-poetry','','[]','繞屋桑麻槿作籬，當門一樹白薔薇。',64,'全唐诗/poet.song.219000.json','["繞屋桑麻槿作籬，當門一樹白薔薇。", "老翁請喚牛醫至，穉子鞭攔鴨陣歸。", "賽願酒豐同飲福，輸官絹足各裁衣。", "年年十月農功畢，還向谿頭整釣磯。"]'),
('f32499ef-5902-4154-8e9d-d69cfcbcceab','千里','釋文珦','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','千里辭家比塞鴻，飄飄不定又還東。',64,'全唐诗/poet.song.219000.json','["千里辭家比塞鴻，飄飄不定又還東。", "波平蹔喜扁舟穩，天闊回瞻故壘空。", "別墅烟昏歸晚牧，長江雨歇掛晴虹。", "前程行止誰能計，已悟浮生似夢中。"]'),
('6350bad7-7ee2-4a9d-a968-8a8fde17141c','偶泛','釋文珦','宋','宋诗','song-poetry','','[]','偶泛扁舟向海埏，初非有意訪神仙。',64,'全唐诗/poet.song.219000.json','["偶泛扁舟向海埏，初非有意訪神仙。", "蓬萊方丈不可問，漢武秦皇空復然。", "水上樓臺皆蜃氣，石間膏馥是龍涎。", "麻姑曾共方平說，行復揚塵變土田。"]'),
('2daea328-26ac-4e06-8903-59042e568ac5','苕溪夜泛','釋文珦','宋','宋诗','song-poetry','','[]','萍蹤人泛清苕去，水宿風餐幾度經。',64,'全唐诗/poet.song.219000.json','["萍蹤人泛清苕去，水宿風餐幾度經。", "結網燈沈漁浦霧，待艐船泊酒家亭。", "樹頭栖鷺疑殘雪，草上流螢似亂星。", "夜後夢回寒月上，棹歌聲裏弁山青。"]'),
('ba8722a6-0392-4595-b3ae-cddd8652c852','武康道中','釋文珦','宋','宋诗','song-poetry','','[]','又過防風舊國西，客懷煙景兩淒淒。',64,'全唐诗/poet.song.219000.json','["又過防風舊國西，客懷煙景兩淒淒。", "青山環繞疑無路，白水分流盡入溪。", "竹外野祠荒甃缺，柳邊漁戶草廬低。", "萍蓬漂轉成何事，不及林猿有定棲。"]'),
('7ab6c659-4d26-41c4-b114-38bcce0c6889','讀伍子胥史事','釋文珦','宋','宋诗','song-poetry','','[]','惆悵當年死屬鏤，到頭忠義竟何如。',64,'全唐诗/poet.song.219000.json','["惆悵當年死屬鏤，到頭忠義竟何如。", "眼懸城郭空懷舊，魂寄江濤尚賈餘。", "向使君王從諫諍，未應宮闕便丘墟。", "唯應教得鴟夷子，萬里扁舟計不疎。"]'),
('279af3ad-d7d4-4ffc-b309-87a4e81f3784','行窩吟','釋文珦','宋','宋诗','song-poetry','','[]','了無一事可相拘，布襪青鞋信所如。',64,'全唐诗/poet.song.219000.json','["了無一事可相拘，布襪青鞋信所如。", "亂石荒苔樵子徑，竹籬茅舍隠人居。", "山林真樂須還我，朝市閑名不問渠。", "頗謂行窩安樂法，遠勝叔夜養生書。"]'),
('09899d79-7a68-4da7-9363-d889a4f18119','東湖荷花','釋文珦','宋','宋诗','song-poetry','','[]','酣紅膩綠三千頃，總是波神變化成。',64,'全唐诗/poet.song.219000.json','["酣紅膩綠三千頃，總是波神變化成。", "出自淤泥元不染，開於玉井舊知名。", "暑天勝似涼天好，葉氣過於花氣清。", "何事濂溪偏愛此，爲他枝蔓不曾生。"]'),
('f25b7366-7f59-4933-b0dd-580cb83127f4','五朵峰','釋文珦','宋','宋诗','song-poetry','','[]','莫知小朶飛來日，慧理曾經指異蹤。',64,'全唐诗/poet.song.219000.json','["莫知小朶飛來日，慧理曾經指異蹤。", "香潤儘多西竺石，孤高亦有晉朝松。", "斷無一幹栖凡鳥，別有深泓卧老龍。", "絕頂世人遊不到，瑶叢清麗似芙蓉。"]'),
('8a4dade3-f21c-4497-9d2c-464ab2bad3f9','觀禹貢九州歷代帝王國都地理圖','釋文珦','宋','宋诗','song-poetry','','[]','萬里江山幾廢興，覽圖真合拊吾膺。',64,'全唐诗/poet.song.219000.json','["萬里江山幾廢興，覽圖真合拊吾膺。", "三王二帝皆難問，兩漢六朝何所稱。", "此日中原全拱北，異時深谷或爲陵。", "看來今古皆如夢，夢境虛無豈足憑。"]'),
('0df5a1c3-bfd4-485f-8f43-1feebbf19ebd','戍婦詞','釋文珦','宋','宋诗','song-poetry','','[]','新婚便別比秋胡，何似當年莫嫁夫。',64,'全唐诗/poet.song.219000.json','["新婚便別比秋胡，何似當年莫嫁夫。", "身在朔方征戍久，鴈來南國信音無。", "空閨寂寂寒宵永，荒路悠悠遠夢孤。", "聞道仙家能縮地，癡心要覓長房符。"]'),
('2569bd2e-17eb-48bb-8293-0825f903d5f2','水亭寫興','釋文珦','宋','宋诗','song-poetry','','[]','爲愛幽亭枕碧流，乘閒於此對沙鷗。',64,'全唐诗/poet.song.219000.json','["爲愛幽亭枕碧流，乘閒於此對沙鷗。", "荷傾宿雨明珠碎，蒲颭輕風翠带柔。", "列岫周遭疑雉堞，斷霞零落似汀洲。", "無人相與言清事，落日鳴蟬滿樹愁。"]'),
('4884a054-1084-41ca-a316-04c538187b42','送趙東閣罷官歸永嘉','釋文珦','宋','宋诗','song-poetry','','[]','一年吟抱寄京華，幾度相逢說永嘉。',64,'全唐诗/poet.song.219000.json','["一年吟抱寄京華，幾度相逢說永嘉。", "夢入西山尋枸杞，約歸東閣看梅花。", "風霜摧拉知何事，雨露生成自有涯。", "應笑屈平終不返，空留遺恨在長沙。"]'),
('1539a7fb-a9ae-4b0c-9135-1fea5f285a8a','奉酬鹽倉李丈金橘銀魚之什','釋文珦','宋','宋诗','song-poetry','','[]','爲有風流賀季真，道齋從此往來頻。',64,'全唐诗/poet.song.219000.json','["爲有風流賀季真，道齋從此往來頻。", "錦囊牙軸詩千卷，金橘銀魚酒一巡。", "見我每呼蓮社客，看君還是竹林人。", "有時夜話寒更盡，明日相逢語又新。"]'),
('eddb8378-e0f7-4aef-93bc-05baf1d174d0','子思惠詩用韻酬之','釋文珦','宋','宋诗','song-poetry','','[]','老慵祇合在雞羣，變化那能慕海鵾。',64,'全唐诗/poet.song.219000.json','["老慵祇合在雞羣，變化那能慕海鵾。", "壯歲親朋多死別，窮途造化與生存。", "欲尋衣食愁無路，却被妻孥怨少恩。", "健筆期君今落第，相賙未得剩空論。"]'),
('470efbaf-73f2-40e0-98a2-cc0ccfd7da90','晚秋閒步','釋文珦','宋','宋诗','song-poetry','','[]','晚來閒步閲秋光，田上人家盡滌場。',64,'全唐诗/poet.song.219000.json','["晚來閒步閲秋光，田上人家盡滌場。", "遠浦寒波浮鴈鶩，荒山落日下牛羊。", "客鬢已非當日黑，菊花空似去年黄。", "因聽翁媼言音異，又復令人憶故鄉。"]'),
('9cc161c5-7c99-4673-8653-7dbca4fd17ee','尋山家','釋文珦','宋','宋诗','song-poetry','','[]','路入深原三四里，林藏雞犬十餘家。',64,'全唐诗/poet.song.219000.json','["路入深原三四里，林藏雞犬十餘家。", "村籬疎密齊栽枳，山崦高低盡種畬。", "石罅春風生野筍，洞中流水出殘花。", "愛同樵客言幽事，不覺歸途暮景斜。"]'),
('c029c3a3-070f-4421-a552-ee8a8db88bab','客裏','釋文珦','宋','宋诗','song-poetry','','[]','客裏還驚節序還，倚闌搔首獨淒然。',64,'全唐诗/poet.song.219000.json','["客裏還驚節序還，倚闌搔首獨淒然。", "垂開柳眼如相看，落盡梅花又可憐。", "幻境自知如夢螘，離情幾欲託啼鵑。", "數聲忽聽烏檐角，款曲吹殘谷口煙。"]'),
('22a323ee-33b5-492a-a9f9-da2cf5a242cf','首夏獨遊響潭','釋文珦','宋','宋诗','song-poetry','','[]','不解驅馳巧作謀，偃然守拙卧林丘。',64,'全唐诗/poet.song.219000.json','["不解驅馳巧作謀，偃然守拙卧林丘。", "方忻嫩綠成槐夏，又愛輕寒作麥秋。", "龍宅清深唯獨往，鶑聲款曲似相留。", "僧言瀑布巖尤好，明日須當到上頭。"]'),
('0826063c-09ea-4016-9c96-cb3c0bb9fb12','看新歷','釋文珦','宋','宋诗','song-poetry','','[]','又看景定新頒歷，百歲還驚五十過。',64,'全唐诗/poet.song.219000.json','["又看景定新頒歷，百歲還驚五十過。", "憶昔壯懷多曠遠，只今衰鬢已蹉跎。", "飄零世路饒荆棘，展轉歸心念薜蘿。", "春草夕陽江上去，不堪回首一長歌。"]'),
('02024dc9-d9d3-4d33-ad1d-cbf17a0d66b6','閒人','釋文珦','宋','宋诗','song-poetry','','[]','不求富貴不嫌貧，天地悠悠任此身。',64,'全唐诗/poet.song.219000.json','["不求富貴不嫌貧，天地悠悠任此身。", "飛步任教趨要路，好懷到底屬閒人。", "自歸白屋交遊遠，認得青山面目真。", "平地退藏知是寶，太行從古有摧輪。"]'),
('f17d0943-4224-478f-9fc2-e8b2c366113c','春盡日','釋文珦','宋','宋诗','song-poetry','','[]','春去無緣得暫留，意行曉到古原頭。',64,'全唐诗/poet.song.219000.json','["春去無緣得暫留，意行曉到古原頭。", "落花隨水如多怨，老柳因風不奈愁。", "鵑聲作意歸何許，蝶夢無憑覺即休。", "林叟相逢俱一笑，都緣彼此是同流。"]'),
('fd3a4617-c556-4f8b-9be2-f9985a313a5f','晚春遣興','釋文珦','宋','宋诗','song-poetry','','[]','始聽鄰屋響秋碪，獨住閒房春又深。',64,'全唐诗/poet.song.219000.json','["始聽鄰屋響秋碪，獨住閒房春又深。", "徧地繁花非故色，一窗涼葉是新陰。", "倉庚謾得東君意，杜宇偏傷遠客心。", "節物相催身易老，臨風時復動悲吟。"]'),
('91e82889-6fce-490a-995b-7e6872cc3280','酬李篔房元日見寄韻','釋文珦','宋','宋诗','song-poetry','','[]','五年嬾踏上京塵，真是乾坤散誕身。',64,'全唐诗/poet.song.219000.json','["五年嬾踏上京塵，真是乾坤散誕身。", "正向山中閒卧雪，忽聞戶外報迎春。", "且傾竹葉屠蘇酒，休畫桃符鬰壘神。", "底事詩筒來往密，結交多是苦吟人。"]'),
('893fd0ad-2d1b-4ec2-a823-aa6743e739a7','酬篔房秋崖昆仲見寄韻','釋文珦','宋','宋诗','song-poetry','','[]','歲月駸駸苦易過，凝霜還見委庭莎。',64,'全唐诗/poet.song.219000.json','["歲月駸駸苦易過，凝霜還見委庭莎。", "從來桑下不三宿，此去榆光尚幾何。", "舊社久荒誰復記，遠公難覓恨空多。", "諸賢頼有劉雷在，時寄新詩到薜蘿。"]'),
('72afb724-6689-4c43-a7bb-20880e198b3d','余與篔房秋崖冬日會於沙谿春復會於龜谿適逢祠山誕辰二翁有詩見貽依韻酬答','釋文珦','宋','宋诗','song-poetry','','[]','沙谿谿上看梅夕，苔徑荒涼月暈黄。',64,'全唐诗/poet.song.219000.json','["沙谿谿上看梅夕，苔徑荒涼月暈黄。", "何事重尋老吟伴，爲難同入少年場。", "和風澹澹行花塢，春水溶溶滿柳塘。", "尚欲重聽送神曲，祇愁明月雨淋浪。"]'),
('e442b0ca-ab4f-462d-aae4-959b30c2a75f','題慈照坦上人房應山閣','釋文珦','宋','宋诗','song-poetry','','[]','禪心直以山爲體，不與終南捷徑同。',64,'全唐诗/poet.song.219000.json','["禪心直以山爲體，不與終南捷徑同。", "吟久白雲生曲檻，定回明月在前峰。", "子牙釣石臨溪古，博望槎源與漢通。", "自有山靈回俗駕，幾人於此得相逢。"]'),
('3799b9ea-c765-4cc1-b270-408d1db643dc','食苦筍','釋文珦','宋','宋诗','song-poetry','','[]','老去居山樂最真，盤蔬日日富前陳。',64,'全唐诗/poet.song.219000.json','["老去居山樂最真，盤蔬日日富前陳。", "愛嘗苦筍疏甜筍，似進忠臣遠佞臣。", "飯爲韻清常倍食，酒因味爽或添巡。", "美芹之意全相似，頗謂堪將獻紫宸。"]'),
('88241f67-cb1f-400f-9913-badd030323db','遊囊山禮妙應祖師慧薰塔','釋文珦','宋','宋诗','song-poetry','','[]','踏徧諸方倦說禪，偶逢佳處結良緣。',64,'全唐诗/poet.song.219000.json','["踏徧諸方倦說禪，偶逢佳處結良緣。", "祖師聖解何須舉，衲子家風要別傳。", "雲外壺中如聚墨，望中滄海欲浮天。", "如今覿面相呈了，啼鳥落花俱寂然。"]'),
('cc7253d1-f7db-4d30-8b49-247c5adc61ad','山居冬日','釋文珦','宋','宋诗','song-poetry','','[]','白水青山不礙禪，登高臨遠意翛然。',64,'全唐诗/poet.song.219000.json','["白水青山不礙禪，登高臨遠意翛然。", "老梅卧雪香逾遠，瘦柏凌霜骨更堅。", "四海交遊多契闊，一生陶寫頼詩篇。", "人間萬事俱拋棄，自此閒居又幾年。"]'),
('8d237f04-8aed-4bbd-b65b-314feb1f8c5d','別馨桂山','釋文珦','宋','宋诗','song-poetry','','[]','與君相見各華顛，握手松間感變遷。',64,'全唐诗/poet.song.219000.json','["與君相見各華顛，握手松間感變遷。", "能記靈山同聽日，不疑絳縣老人年。", "難尋舊夢悲蝴蝶，替說新愁頼杜鵑。", "無奈怱怱又還別，有詩須寄武康船。"]'),
('7a388425-8316-4baf-a9c4-4f4ed35580dd','客居','釋文珦','宋','宋诗','song-poetry','','[]','借得空房住十春，野麋山鹿日相新。',64,'全唐诗/poet.song.219000.json','["借得空房住十春，野麋山鹿日相新。", "寧嫌老景猶爲客，却喜閑身不屬人。", "於轉物時觀世界，向無心處得天真。", "深居謝絕曾非傲，朽鈍形骸畏屈伸。"]'),
('09bc8cd1-4c2d-44f3-8e49-4ceea079cc84','閒居遣興','釋文珦','宋','宋诗','song-poetry','','[]','無情日月互相磨，萬古悠悠一逝波。',64,'全唐诗/poet.song.219000.json','["無情日月互相磨，萬古悠悠一逝波。", "六十四年成事少，八千餘卷費功多。", "山林有志知難變，毀譽無根聽自訛。", "近問野人安穩法，教予祇學採樵歌。"]'),
('e6fe133b-18f8-4f6c-ad67-ddc886b474df','雲林','釋文珦','宋','宋诗','song-poetry','','[]','雲林佳處輒遲留，不覺駸駸白盡頭。',64,'全唐诗/poet.song.219000.json','["雲林佳處輒遲留，不覺駸駸白盡頭。", "率野唯聞多虎兕，到門那得有羊裘。", "老身真箇如山靜，往事從教逐水流。", "富貴功名是何物，纔堪休處便須休。"]'),
('a1bca987-61c0-4093-9128-90afd2ccee49','放吟','釋文珦','宋','宋诗','song-poetry','','[]','心絕馳競如安流，身逃繫屬同虛舟。',64,'全唐诗/poet.song.219000.json','["心絕馳競如安流，身逃繫屬同虛舟。", "無車每每跨黄犢，有暇時時盟白鷗。", "隨分嬉遊隨分樂，可曾計較可曾愁。", "老吟亦不記聲律，亂寫孟郊沙井頭。"]'),
('8f3d6ee7-b24a-4d40-9c88-61b33879f3e5','一生','釋文珦','宋','宋诗','song-poetry','','[]','一生踪跡任浮沉，兩鬢何爲雪易侵。',64,'全唐诗/poet.song.219000.json','["一生踪跡任浮沉，兩鬢何爲雪易侵。", "不可破除唯道義，最難憑託是人心。", "清溪路口閒雲合，白版門前落葉深。", "老子衰年嬾酬應，若非同伴莫相尋。"]'),
('f0e29f50-c3b6-4fc1-8ac6-b24bd65a4bdb','由樵徑登北高峰遂至韜光庵','釋文珦','宋','宋诗','song-poetry','','[]','鳥路欹傾不可登，攀緣直上最高層。',64,'全唐诗/poet.song.219000.json','["鳥路欹傾不可登，攀緣直上最高層。", "陰崖老樹春無葉，古竇寒泉夏作冰。", "斜抱江流縈翠带，亂山分脈走瓜藤。", "雲根細紀當年事，太守曾來訪隠僧。"]'),
('391b7b84-cbc1-41e7-8d7c-5f9f44a16f1f','村行即事','釋文珦','宋','宋诗','song-poetry','','[]','客中頗覺身無事，徐步西村引興長。',64,'全唐诗/poet.song.219000.json','["客中頗覺身無事，徐步西村引興長。", "茅舍竹籬分向背，麥畦麻稜間青黄。", "少婦乘時方煮繭，老翁擇日又移秧。", "農家滿眼皆生意，應是無心出此鄉。"]'),
('0d7197e9-6215-43e7-9d3c-5229df910767','山居  其一','釋文珦','宋','宋诗','song-poetry','','[]','身寄孤猨野鶴鄉，邇來真與世相忘。',64,'全唐诗/poet.song.219000.json','["身寄孤猨野鶴鄉，邇來真與世相忘。", "東南地闕多流水，西北山高少夕陽。", "根有茯苓松色異，土生蘭茝蘚苔香。", "細將萬事都思徧，唯有閒居味最長。"]'),
('05e199fe-3bd8-4b0a-89e0-d54bf603b3f6','山居  其二','釋文珦','宋','宋诗','song-poetry','','[]','肯道山居太寂寥，不妨隨分自逍遥。',64,'全唐诗/poet.song.219000.json','["肯道山居太寂寥，不妨隨分自逍遥。", "盡空眼界終無翳，爲厭聲塵亦去瓢。", "菊老尚能存正色，松孤還自有高標。", "道人樂地唯如此，說與同流意更消。"]'),
('2068d66f-0ace-4d66-9d9d-225e3361145e','送春','釋文珦','宋','宋诗','song-poetry','','[]','老人無復趁春場，見說春歸亦送將。',64,'全唐诗/poet.song.219000.json','["老人無復趁春場，見說春歸亦送將。", "唯恐再來吾不見，偏於此別意難忘。", "花枝卧雨紅顔盡，草蔓梳風綠髮長。", "作計欲留留不住，聊歌一曲當離觴。"]'),
('ad375bf1-319b-4d5b-ad68-6882d7250c58','登臨寫興','釋文珦','宋','宋诗','song-poetry','','[]','臨水登山送此生，禽猿箇箇盡忘情。',64,'全唐诗/poet.song.219000.json','["臨水登山送此生，禽猿箇箇盡忘情。", "破除妄念唯空寂，藏蓄危機是利名。", "老子樂時誰不笑，衆人重處我能輕。", "有時信口長歌發，好似東陽獨自精。"]'),
('7c956ce9-35ae-4276-840e-03b525eb1d97','春草','釋文珦','宋','宋诗','song-poetry','','[]','菶菶萋萋綠漸滋，昔人辭意足堪推。',64,'全唐诗/poet.song.219000.json','["菶菶萋萋綠漸滋，昔人辭意足堪推。", "由來南浦傷離日，不似西堂得句時。", "行旅獨看空感慨，池塘關夢自神奇。", "吾雖萬事皆慵嬾，春草生時亦有詩。"]'),
('31cd2c42-8fcd-4e67-9757-402af8350339','世味','釋文珦','宋','宋诗','song-poetry','','[]','世味從前已備嘗，重罹世難轉悽傷。',64,'全唐诗/poet.song.219000.json','["世味從前已備嘗，重罹世難轉悽傷。", "肯希逸驥能千里，最善靈龜解六藏。", "覽勝每尋清伴侶，觀山別是好心腸。", "年逾七十唯求死，便不埋時也不妨。"]'),
('6219e065-0b07-4cd3-9c68-e61ac2a28154','幽處','釋文珦','宋','宋诗','song-poetry','','[]','惡圓難與俗浮沉，野處窮居歲月深。',64,'全唐诗/poet.song.219000.json','["惡圓難與俗浮沉，野處窮居歲月深。", "青嶂於予偏有分，白雲嫌道太無心。", "人間富貴皆塵物，世外風泉是好音。", "老去翛然竟何事，若非入靜即閒吟。"]'),
('327196d7-1385-4b26-9d81-088291b3198c','篔房秋崖來訪不相值後往謝之篔復有詩喜余之至因次其韻','釋文珦','宋','宋诗','song-poetry','','[]','吟車曾到社橋來，不見山人乞食回。',64,'全唐诗/poet.song.219000.json','["吟車曾到社橋來，不見山人乞食回。", "荒沼秋深蓮已謝，寒林冬近菊初開。", "句引淵明無酒琖，觀迎元度但茶杯。", "尋盟却喜梅花發，日日論詩坐碧苔。"]'),
('c37b2253-b56c-4f1e-b2ba-77afeda13048','石室','釋文珦','宋','宋诗','song-poetry','','[]','石室閒眠過午鐘，看來唯我最疎慵。',64,'全唐诗/poet.song.219000.json','["石室閒眠過午鐘，看來唯我最疎慵。", "生憎俗客妨幽趣，不與樵夫說定蹤。", "麋下磵陰時引子，鶴歸林表只依松。", "人生未解休心去，多向塵區歎不逢。"]'),
('96614d42-61cb-4e24-92bd-c6c63ae89108','野寺','釋文珦','宋','宋诗','song-poetry','','[]','野寺居來歲月長，幽深真是隠人鄉。',64,'全唐诗/poet.song.219000.json','["野寺居來歲月長，幽深真是隠人鄉。", "怪枝結頂青松古，巨石分流碧澗長。", "拈弄詩章非俗事，斷除禪病得良方。", "因悲竊國亡身者，枉作塵勞夢一場。"]'),
('4e4ee6da-de4f-4c39-a116-6babd17a6ac2','題逆賈','釋文珦','宋','宋诗','song-poetry','','[]','逆賈猖狂秉國鈞，民彝帝業總成塵。',64,'全唐诗/poet.song.219000.json','["逆賈猖狂秉國鈞，民彝帝業總成塵。", "虔劉幾似刀兵劫，全活幸蒙天地仁。", "衆醉有誰知甲子，獨醒還自記庚申。", "鼎湖龍馭重回首，應悔當年錯用人。"]'),
('12f01087-5c65-4f78-862d-fb166ce3e278','晚步','釋文珦','宋','宋诗','song-poetry','','[]','竹杖芒鞋晚步遲，爲貪山水有清暉。',64,'全唐诗/poet.song.219000.json','["竹杖芒鞋晚步遲，爲貪山水有清暉。", "栖鴉已带殘陽去，牧豎遥穿薄靄歸。", "可保禪身終放浪，從教塵世各脂韋。", "閒中自有無窮樂，敢道麻衣勝錦衣。"]'),
('2f1b7d7c-296c-4a91-8502-bfb90948df23','因悟','釋文珦','宋','宋诗','song-poetry','','[]','因悟維顛匪一繩，遂無心續祖師燈。',64,'全唐诗/poet.song.219000.json','["因悟維顛匪一繩，遂無心續祖師燈。", "祇圖塵世難窺影，遠入深峰不記層。", "土木形骸從朽腐，冰霜志節自堅凝。", "非吾同伴如相覓，牢閉蓬門定不譍。"]'),
('c2149b5a-9731-4243-ab62-9bb6e40a2420','天地之間有此身','釋文珦','宋','宋诗','song-poetry','','[]','天地之間有此身，此身豈肯惹風塵。',64,'全唐诗/poet.song.219000.json','["天地之間有此身，此身豈肯惹風塵。", "竹籬茅舍居來穩，紙帳蒲團趣更真。", "行己作成山水癖，到頭不是利名人。", "使予生遇陶唐世，當與許由巢父倫。"]'),
('52196333-3705-419a-a86e-509cef07f8fe','老身','釋文珦','宋','宋诗','song-poetry','','[]','老身到此合稱翁，雙足蹣跚兩耳聾。',64,'全唐诗/poet.song.219000.json','["老身到此合稱翁，雙足蹣跚兩耳聾。", "聊託迂疎居世表，幸無名字到官中。", "生期槁木寒灰盡，性與孤猿野鶴同。", "去歲有錐無地卓，今年錐地併皆空。"]'),
('3ade35f8-6d4e-408d-9f1d-92cca665513f','洞霄宮','釋文珦','宋','宋诗','song-poetry','','[]','山勢逶迤九鎖分，洞天終自異人羣。',64,'全唐诗/poet.song.219000.json','["山勢逶迤九鎖分，洞天終自異人羣。", "君王在昔曾游幸，故老猶今述見聞。", "瀑濺鶴衣明似雪，氣蒸龍穴暗成雲。", "夢回髣髴鳴笙磬，定有游仙拜老君。"]'),
('712f9c08-b7b8-4922-9e0d-ac474094258a','出遊歸隠','釋文珦','宋','宋诗','song-poetry','','[]','出遊歸隠兩無心，非慕沃洲支道林。',64,'全唐诗/poet.song.219000.json','["出遊歸隠兩無心，非慕沃洲支道林。", "啗柏自然閑土銼，製荷曾不費金鍼。", "悠悠往事空塵夢，冉冉餘生任陸沉。", "頗謂天閑千里馬，難勝寥廓九臯禽。"]'),
('44d57f21-7726-4f63-9f72-c36a6ff16ee3','山中老宿','釋文珦','宋','宋诗','song-poetry','','[]','雲壑居來歲月長，千株松下一間房。',64,'全唐诗/poet.song.219000.json','["雲壑居來歲月長，千株松下一間房。", "掃空心地苕花帚，熏徹根塵柏子香。", "施法定應拈麈柄，接人曾不下禪床。", "生緣已自都忘了，唯道西歸有故鄉。"]'),
('b954cfe7-c1ad-4349-8fc4-aa74bf8fc9cd','禪翁','釋文珦','宋','宋诗','song-poetry','','[]','禪翁八十鬢如霜，冷坐雲邊舊竹房。',64,'全唐诗/poet.song.219000.json','["禪翁八十鬢如霜，冷坐雲邊舊竹房。", "唯放此身長嬾散，更無餘事可思量。", "飛流激石泉珠迸，斜照入林松影長。", "即景成詩疑未穩，更尋樵父爲平章。"]'),
('edaaa45c-51de-492f-a205-bb419ab1f665','哭恭仲溫','釋文珦','宋','宋诗','song-poetry','','[]','信敬謙勤德更純，江湖風誼最相親。',64,'全唐诗/poet.song.219000.json','["信敬謙勤德更純，江湖風誼最相親。", "曾知九要三玄髓，豈混重泉一窖塵。", "此日傷心亡我友，異時再面是他人。", "山中弟子懷師德，各翦生綃暗寫真。"]'),
('1b043390-2391-4f90-a425-c7713b7ff576','西風','釋文珦','宋','宋诗','song-poetry','','[]','西風吹鬢鬢成霜，變異無端那有常。',64,'全唐诗/poet.song.219000.json','["西風吹鬢鬢成霜，變異無端那有常。", "交友後先同昨夢，老人八十尚他鄉。", "書空鴈字行疎密，泣砌蟲吟韻短長。", "盡是客中秋意緒，誰能對此不凄涼。"]'),
('e8012677-6b9e-4ecf-9708-e8b360dc0274','歸來','釋文珦','宋','宋诗','song-poetry','','[]','歸來巖下養衰形，日日眠雲聽瀑聲。',64,'全唐诗/poet.song.219000.json','["歸來巖下養衰形，日日眠雲聽瀑聲。", "但愛一閒堪佚老，翻思萬卷是勞生。", "人嫌草座麻衣陋，自守芝翁木客盟。", "沒齒如斯吾事足，更無他事可關情。"]'),
('8c75b297-6722-43a8-8cb8-207d2c88174a','自愛','釋文珦','宋','宋诗','song-poetry','','[]','自愛予生愛性真，真存渾不管渠嗔。',64,'全唐诗/poet.song.219000.json','["自愛予生愛性真，真存渾不管渠嗔。", "從來有水有山處，著得無名無利人。", "騰踏豈須誇駔駿，幽潛端可養精神。", "盡向雲邊尋隠迹，誰知雲是老夫身。"]'),
('3d724720-e9ea-4cab-bab3-bf0153d3a6a0','人壽','釋文珦','宋','宋诗','song-poetry','','[]','人壽百年三萬日，有誰曾滿百年來。',64,'全唐诗/poet.song.219000.json','["人壽百年三萬日，有誰曾滿百年來。", "騰騰任運聊堪樂，汩汩勞生盡可哀。", "富貴惟增身外累，酕醄當覆掌中杯。", "到頭一等皆歸死，未死須教笑口開。"]'),
('944e0504-6b7e-4fb3-95cc-77aeb0d0f271','老子','釋文珦','宋','宋诗','song-poetry','','[]','老子深棲趣已成，塵鞿何計可相縈。',64,'全唐诗/poet.song.219000.json','["老子深棲趣已成，塵鞿何計可相縈。", "寒泉一道知來脈，靈木多年産寄生。", "雲外暗藏龍虎穴，風中清度鶴猿聲。", "過從等是無心侶，同喫山厨芋顆羹。"]'),
('381388a5-7106-4bd9-8b93-5583ffc78a58','採蓮曲  其一','釋文珦','宋','宋诗','song-poetry','','[]','蕩槳入平湖，湖波渺無極。',24,'全唐诗/poet.song.219000.json','["蕩槳入平湖，湖波渺無極。", "紅白芙蓉花，何如妾顔色。"]'),
('6c9bd12e-9fe4-46e4-95e1-fd48e176cfbc','採蓮曲  其二','釋文珦','宋','宋诗','song-poetry','','[]','荷葉似儂鬢，荷花似儂妝。',24,'全唐诗/poet.song.219000.json','["荷葉似儂鬢，荷花似儂妝。", "夫壻常別離，羞見雙鴛鴦。"]'),
('7eeb2feb-06ff-4282-8986-743db4ea2dcd','採蓮曲  其三','釋文珦','宋','宋诗','song-poetry','','[]','採蓮莫傷根，傷根不成藕。',24,'全唐诗/poet.song.219000.json','["採蓮莫傷根，傷根不成藕。", "因思藕不成，悔作征人婦。"]'),
('67ed2b22-694e-428d-80be-05c68b1c3bb2','採蓮曲  其四','釋文珦','宋','宋诗','song-poetry','','[]','採蓮惟採花，不敢採蓮子。',24,'全唐诗/poet.song.219000.json','["採蓮惟採花，不敢採蓮子。", "其中有苦意，與妾心相似。"]'),
('d98fa608-61c6-45ca-9faf-5b6804423a86','種蘭菊','釋文珦','宋','宋诗','song-poetry','','[]','菊蒔陶籬本，蘭滋楚畹芳。',24,'全唐诗/poet.song.219000.json','["菊蒔陶籬本，蘭滋楚畹芳。", "荷鋤春雨後，懷古意何長。"]'),
('7aa228a4-356c-4a5f-88cd-4e5553f23829','經旬','釋文珦','宋','宋诗','song-poetry','','[]','經旬坐春雨，畏濕不下席。',24,'全唐诗/poet.song.219000.json','["經旬坐春雨，畏濕不下席。", "曉看籬角萱，怒長忽過尺。"]'),
('04264999-e0b3-4383-977e-a436a5545710','農謠','釋文珦','宋','宋诗','song-poetry','','[]','斗種播良田，可收三十石。',24,'全唐诗/poet.song.219000.json','["斗種播良田，可收三十石。", "天予人奪之，耕夫每無食。"]'),
('f7201239-7c35-4474-895b-269f124a90b0','贈道士褚雪巘','釋文珦','宋','宋诗','song-poetry','','[]','身不離珠庭，新箋道德經。',24,'全唐诗/poet.song.219000.json','["身不離珠庭，新箋道德經。", "時來琪樹下，閒看鶴梳翎。"]'),
('c059cb19-d323-4ca4-b34d-d301bcc26154','晚泊','釋文珦','宋','宋诗','song-poetry','','[]','煙生浦欲無，日暮潮初落。',24,'全唐诗/poet.song.219000.json','["煙生浦欲無，日暮潮初落。", "客帆何處來，又近垂楊泊。"]'),
('d59f095e-e159-47cc-886d-3a6548a2cb12','梅花','釋文珦','宋','宋诗','song-poetry','','[]','梅花如隠人，不與羣芳競。',24,'全唐诗/poet.song.219000.json','["梅花如隠人，不與羣芳競。", "別塢春風多，寒流照清影。"]'),
('00bbc6a7-8b14-403e-be15-1127a81a29bc','山中月夜','釋文珦','宋','宋诗','song-poetry','','[]','秋月滿疎林，林影自零亂。',24,'全唐诗/poet.song.219000.json','["秋月滿疎林，林影自零亂。", "白猿啼一聲，山空夜將半。"]'),
('50a42102-40f7-4faf-9808-9c0c820f5543','曉行','釋文珦','宋','宋诗','song-poetry','','[]','寒雞誤客行，躑躅犯霜露。',24,'全唐诗/poet.song.219000.json','["寒雞誤客行，躑躅犯霜露。", "冰凍不生潮，娥江夜難渡。"]'),
('c73268f6-c2aa-4322-8f4d-c3ed44185ac7','晚  其一','釋文珦','宋','宋诗','song-poetry','','[]','暝色生前浦，日沉西嶺樹。',24,'全唐诗/poet.song.219000.json','["暝色生前浦，日沉西嶺樹。", "隠約有孤僧，遠入深雲去。"]'),
('db6ba4a3-f231-44cb-85b5-9b2b3ac5b45f','晚  其二','釋文珦','宋','宋诗','song-poetry','','[]','殘陽下西岑，暝色起平坂。',24,'全唐诗/poet.song.219000.json','["殘陽下西岑，暝色起平坂。", "林下一僧歸，鐘聲煙際遠。"]'),
('f646c043-270c-4a08-b563-80eb33f11922','漁艇  其一','釋文珦','宋','宋诗','song-poetry','','[]','炊菰青蘆叢，釣魚白蘋洲。',24,'全唐诗/poet.song.219000.json','["炊菰青蘆叢，釣魚白蘋洲。", "扁舟不用楫，蕩漾隨春流。"]'),
('c0885682-92cd-4985-89dd-bb454bb5365a','漁艇  其二','釋文珦','宋','宋诗','song-poetry','','[]','斜枕綠蓑衣，醉眠呼不醒。',24,'全唐诗/poet.song.219000.json','["斜枕綠蓑衣，醉眠呼不醒。", "午夜天無雲，月滿孤篷頂。"]'),
('d2a7caf3-a106-466c-a0ca-66cdfc6fa92e','客枕  其一','釋文珦','宋','宋诗','song-poetry','','[]','客枕正無憀，寒鷄鳴夜半。',24,'全唐诗/poet.song.219000.json','["客枕正無憀，寒鷄鳴夜半。", "開門望天末，月沉星爛爛。"]'),
('4ba02c61-ca09-48ff-af96-909f1bc2a0d6','客枕  其二','釋文珦','宋','宋诗','song-poetry','','[]','客枕難成夢，秋宵轉覺長。',24,'全唐诗/poet.song.219000.json','["客枕難成夢，秋宵轉覺長。", "莎鷄鳴不住，階下月如霜。"]'),
('46273665-9c38-409e-ac0a-7b5b19281907','逆旅','釋文珦','宋','宋诗','song-poetry','','[]','逆旅夜冥冥，寒燈結燼青。',24,'全唐诗/poet.song.219000.json','["逆旅夜冥冥，寒燈結燼青。", "一聲霜鴈過，倦客夢初醒。"]'),
('e8b32f8c-db04-415a-89c0-57ab413ac60c','秋感','釋文珦','宋','宋诗','song-poetry','','[]','霜露變羣物，遊子難爲情。',24,'全唐诗/poet.song.219000.json','["霜露變羣物，遊子難爲情。", "吾親隔重泉，奈此風葉聲。"]'),
('bd1b55c0-939d-4b03-937e-731059a226f1','久客','釋文珦','宋','宋诗','song-poetry','','[]','客裏又深秋，凄凉怕舉頭。',24,'全唐诗/poet.song.219000.json','["客裏又深秋，凄凉怕舉頭。", "西風吹敗葉，葉葉是歸愁。"]'),
('e8a75e83-c047-48e4-97c4-892c1dcffd67','客中','釋文珦','宋','宋诗','song-poetry','','[]','客中春又半，舊隠欲歸難。',24,'全唐诗/poet.song.219000.json','["客中春又半，舊隠欲歸難。", "唯恐傷懷抱，花開不欲看。"]'),
('4745ba48-2e5e-4688-b053-9950ce524411','東岡曉雪','釋文珦','宋','宋诗','song-poetry','','[]','蕭蕭夜來雪，失却登山徑。',24,'全唐诗/poet.song.219000.json','["蕭蕭夜來雪，失却登山徑。", "曉望東岡頭，寒花滿松頂。"]'),
('e32d643d-04ee-4bbf-8ed7-d74934d568d3','送僧歸浙東','釋文珦','宋','宋诗','song-poetry','','[]','舊隠青山下，歸程白露前。',24,'全唐诗/poet.song.219000.json','["舊隠青山下，歸程白露前。", "他時此相憶，懊惱浙江船。"]'),
('fb62e852-8210-4cc8-98b7-834cf2067c86','竹堂秋雨','釋文珦','宋','宋诗','song-poetry','','[]','秋雨滴寒竹，主人魂夢清。',24,'全唐诗/poet.song.219000.json','["秋雨滴寒竹，主人魂夢清。", "客來聽未慣，認作打篷聲。"]'),
