('1308d52b-564f-4d14-87a7-33d08f4ec032','嘲蝶','釋文珦','宋','宋诗','song-poetry','','[]','耳聲眼色總非真，物我同爲一窖塵。',32,'全唐诗/poet.song.219000.json','["耳聲眼色總非真，物我同爲一窖塵。", "蝴蝶不知身是夢，花間栩栩過青春。"]'),
('9a8d46d7-4300-49c6-aa3e-9329fd2dd60b','獨客','釋文珦','宋','宋诗','song-poetry','','[]','嘖嘖陰蟲鳴不已，獨客無悰夜中起。',32,'全唐诗/poet.song.219000.json','["嘖嘖陰蟲鳴不已，獨客無悰夜中起。", "迢遥星漢正西流，千峰浸月清如水。"]'),
('c287526c-3fe8-4842-a36c-67c992820a73','贈日者雲谷俞喜  其一','釋文珦','宋','宋诗','song-poetry','','[]','十載唯耕谷口雲，倚鉏時復看天文。',32,'全唐诗/poet.song.219000.json','["十載唯耕谷口雲，倚鉏時復看天文。", "世間貴賤君皆識，却恐無人解識君。"]'),
('7b2b28e6-3f70-4f2a-97eb-c2bed83557d2','贈日者雲谷俞喜  其二','釋文珦','宋','宋诗','song-poetry','','[]','客身猶卧玲瓏石，鄉夢長懸岞崿山。',32,'全唐诗/poet.song.219000.json','["客身猶卧玲瓏石，鄉夢長懸岞崿山。", "詹尹自應知我意，爲言何日定當還。"]'),
('39166ec4-1fe3-465e-974d-7f01d8dba8bb','春日野外','釋文珦','宋','宋诗','song-poetry','','[]','春波蕩瀁滿方塘，春草無名各自長。',32,'全唐诗/poet.song.219000.json','["春波蕩瀁滿方塘，春草無名各自長。", "沙際漁翁偏自在，醉拋蓑笠卧斜陽。"]'),
('44643917-c184-4d18-af75-3cfa1877455c','欹枕','釋文珦','宋','宋诗','song-poetry','','[]','徹底清閑住草堂，更無一事可商量。',32,'全唐诗/poet.song.219000.json','["徹底清閑住草堂，更無一事可商量。", "時時欹枕寒窗下，靜看西山白鷺行。"]'),
('771774ed-512c-4d6e-b3e7-2807e2d561b7','傷感','釋文珦','宋','宋诗','song-poetry','','[]','百萬長驅入戰塵，幾人能保去時身。',32,'全唐诗/poet.song.219000.json','["百萬長驅入戰塵，幾人能保去時身。", "古來戰將知多少，盡作青青塞草春。"]'),
('01c0552a-0daf-4883-8351-f8e2db4b1e95','樵隠','釋文珦','宋','宋诗','song-poetry','','[]','歸隠青山歲月多，定知無意出煙蘿。',32,'全唐诗/poet.song.219000.json','["歸隠青山歲月多，定知無意出煙蘿。", "樵風自是仙家事，更莫看棋爛斧柯。"]'),
('b6ac3cd7-e0a0-4cf9-a914-20fe6efa3a69','懷故鄉','釋文珦','宋','宋诗','song-poetry','','[]','家住潛溪雲萬里，別來四十九春風。',32,'全唐诗/poet.song.219000.json','["家住潛溪雲萬里，別來四十九春風。", "無田種秫不歸去，夢落山光水色中。"]'),
('7855b481-09a4-4cb0-b7f1-db20c53c50be','聞鴈  其一','釋文珦','宋','宋诗','song-poetry','','[]','山寒經月斷人行，孤鴈噰噰忽一聲。',32,'全唐诗/poet.song.219000.json','["山寒經月斷人行，孤鴈噰噰忽一聲。", "身在異鄉兄弟盡，老夫那得易爲情。"]'),
('461c164c-78b0-4eb4-82cb-740a7555185f','聞鴈  其二','釋文珦','宋','宋诗','song-poetry','','[]','重雲散盡天如鏡，寒鴈哭霜冬夜永。',32,'全唐诗/poet.song.219000.json','["重雲散盡天如鏡，寒鴈哭霜冬夜永。", "欲寫相思寄遠人，翩翩過盡無留影。"]'),
