('a4d2fe51-adfb-4a8f-9a11-df234784e7a5','雪晴','釋文珦','宋','宋诗','song-poetry','','[]','日照松頭凍雪崩，又聞烘拆小池冰。',32,'全唐诗/poet.song.219000.json','["日照松頭凍雪崩，又聞烘拆小池冰。", "起看門外羣峰色，絕頂纔分翠一稜。"]'),
('6f30a796-d967-40e1-bf22-86e566c63c16','曉鐘','釋文珦','宋','宋诗','song-poetry','','[]','夢覺風吹雨脚斷，庵西斜月透疎松。',32,'全唐诗/poet.song.219000.json','["夢覺風吹雨脚斷，庵西斜月透疎松。", "披衣起坐不成寐，細聽四山鳴曉鐘。"]'),
('4ba5a1a1-ae4a-412d-819b-4c96c464e636','香林洞口觀猿','釋文珦','宋','宋诗','song-poetry','','[]','貴遊拋果引羣狙，大小玄黄趕擲殊。',32,'全唐诗/poet.song.219000.json','["貴遊拋果引羣狙，大小玄黄趕擲殊。", "別有白猿歸洞裏，一生不受俗人呼。"]'),
('6e6afcd6-7562-4bc1-a67b-ec598bac7e79','村行與田翁語','釋文珦','宋','宋诗','song-poetry','','[]','門對荒陂柳半遮，老翁留客坐枯槎。',32,'全唐诗/poet.song.219000.json','["門對荒陂柳半遮，老翁留客坐枯槎。", "自言雨足好苗色，猶恐風多損稻花。"]'),
('d352071a-7758-438c-91ae-9e161eaaf1a0','贈仙翁','釋文珦','宋','宋诗','song-poetry','','[]','九曲溪連萬樹松，樹邊雲屋住仙翁。',32,'全唐诗/poet.song.219000.json','["九曲溪連萬樹松，樹邊雲屋住仙翁。", "不曾說著人間事，日暮唯先閉鶴籠。"]'),
('20ebaf51-76b2-460e-a3d7-2551fafc6275','西風  其一','釋文珦','宋','宋诗','song-poetry','','[]','西風似識野夫心，吹葉填門日漸深。',32,'全唐诗/poet.song.219000.json','["西風似識野夫心，吹葉填門日漸深。", "童子切須休掃著，要他朝夕助秋吟。"]'),
('8089299b-cda3-4def-9236-d3b4039dc159','西風  其二','釋文珦','宋','宋诗','song-poetry','','[]','西風飋飋起松林，捲盡長空萬里陰。',32,'全唐诗/poet.song.219000.json','["西風飋飋起松林，捲盡長空萬里陰。", "明月在天天似水，似余一片坐禪心。"]'),
('d8e802b7-61a7-4937-bdb8-b5f592690b69','邊思  其一','釋文珦','宋','宋诗','song-poetry','','[]','十年辛苦戍邊城，朔漠漫漫萬里平。',32,'全唐诗/poet.song.219000.json','["十年辛苦戍邊城，朔漠漫漫萬里平。", "厭聽胡兒吹曉角，聲聲都是斷腸聲。"]'),
('d61801f0-6af1-49b1-913a-39ca745689da','邊思  其二','釋文珦','宋','宋诗','song-poetry','','[]','胡鴈南翔已盡回，閨中不見寄書來。',32,'全唐诗/poet.song.219000.json','["胡鴈南翔已盡回，閨中不見寄書來。", "窮荒二月無青草，長對東風賦七哀。"]'),
('8decafc1-44bc-45fd-baa2-bba85a1afb4d','愛秋','釋文珦','宋','宋诗','song-poetry','','[]','宋玉悲秋我愛秋，清秋行樂勝春遊。',32,'全唐诗/poet.song.219000.json','["宋玉悲秋我愛秋，清秋行樂勝春遊。", "林疎盡見山中石，更有寒泉带石流。"]'),
