('bc3f4f1a-651f-4f4b-9a1a-8d833ca6d795','丈亭別癯翁','釋文珦','宋','宋诗','song-poetry','','[]','幾年惆悵限江東，暫喜沙頭一笑同。',32,'全唐诗/poet.song.219000.json','["幾年惆悵限江東，暫喜沙頭一笑同。", "依舊扁舟相背發，可堪回首月明中。"]'),
('ecdd5110-bdf3-4342-99f2-150f5b211444','別友  其一','釋文珦','宋','宋诗','song-poetry','','[]','十年踪跡與君同，今日魂銷執手中。',32,'全唐诗/poet.song.219000.json','["十年踪跡與君同，今日魂銷執手中。", "自是交深難話別，不關秋雨又秋風。"]'),
('5f52ac40-3cfc-44eb-ba01-9d12492c6ead','別友  其二','釋文珦','宋','宋诗','song-poetry','','[]','故人別我江東去，不堪回首城邊路。',32,'全唐诗/poet.song.219000.json','["故人別我江東去，不堪回首城邊路。", "明日思君不見君，惟有春雲滿江樹。"]'),
('60c1fa4e-70dc-41c9-922b-4754fc713ea6','古墓','釋文珦','宋','宋诗','song-poetry','','[]','不知何代公侯墓，酹壇欹傾牧兒聚。',32,'全唐诗/poet.song.219000.json','["不知何代公侯墓，酹壇欹傾牧兒聚。", "淒涼翁仲滿身苔，獨對寒松泣秋雨。"]'),
('7390143e-e988-4670-bc42-8c7fc0c31f33','深居','釋文珦','宋','宋诗','song-poetry','','[]','千巖萬壑幽深地，一鉢三衣自在身。',32,'全唐诗/poet.song.219000.json','["千巖萬壑幽深地，一鉢三衣自在身。", "斷定不行朝市路，無因猶識利名人。"]'),
('04fab86d-2d2d-4380-b8dd-3805e2d2d92b','山園三月桃未花','釋文珦','宋','宋诗','song-poetry','','[]','春風不入窶人家，三月園桃未著花。',32,'全唐诗/poet.song.219000.json','["春風不入窶人家，三月園桃未著花。", "老子放癡都不問，山厨日日飯胡麻。"]'),
('094a27b6-4a58-4ef0-9f45-103bee71364c','山桃','釋文珦','宋','宋诗','song-poetry','','[]','山桃初熟山人摘，中有甜子如藥黑。',32,'全唐诗/poet.song.219000.json','["山桃初熟山人摘，中有甜子如藥黑。", "夜寒月落霜在枝，擘破獼猴不敢食。"]'),
('5b89d0f0-17f4-48e8-bbff-27c4f51e840f','陌頭','釋文珦','宋','宋诗','song-poetry','','[]','陌頭遊子矜年少，爭把夭桃比貌紅。',32,'全唐诗/poet.song.219000.json','["陌頭遊子矜年少，爭把夭桃比貌紅。", "老眼看來渾似夢，開時便與落時同。"]'),
('11753631-9c5e-4381-9410-f02fad801cbe','法寶璉師求竹軒','釋文珦','宋','宋诗','song-poetry','','[]','南軒竹色映溪光，不減吾州五月涼。',32,'全唐诗/poet.song.219000.json','["南軒竹色映溪光，不減吾州五月涼。", "猶恨秋來鷗鷺少，須君更爲築橫塘。"]'),
('8bc5e12e-5f32-4cae-9cc2-9e6ef84468e5','老懷','釋文珦','宋','宋诗','song-poetry','','[]','終向江湖老此身，了無機事却難馴。',32,'全唐诗/poet.song.219000.json','["終向江湖老此身，了無機事却難馴。", "沙鷗信是同盟者，白首相看意最真。"]'),
('ec4bda49-f748-4652-a02c-84cfbd1a3e75','聽雪','釋文珦','宋','宋诗','song-poetry','','[]','密片打窗窗自白，老翁寒坐正清吟。',32,'全唐诗/poet.song.219000.json','["密片打窗窗自白，老翁寒坐正清吟。", "忽聞壓折牆頭竹，却想山中積處深。"]'),
('08bf8e88-27e3-4539-9294-ae727b800ea5','幾夜','釋文珦','宋','宋诗','song-poetry','','[]','幾夜自聽松雪響，西峰道者不曾來。',32,'全唐诗/poet.song.219000.json','["幾夜自聽松雪響，西峰道者不曾來。", "今朝擬得尋幽話，溪路清寒却又迴。"]'),
