('54206e6e-9118-4579-ae73-819780b2228b','湖亭','釋文珦','宋','宋诗','song-poetry','','[]','一堤楊柳青絲輭，百頃芙蕖錦障開。',32,'全唐诗/poet.song.219000.json','["一堤楊柳青絲輭，百頃芙蕖錦障開。", "中有閒人心似水，坐看沙鳥鏡中來。"]'),
('2a1aeba4-2864-4f13-9858-024bff7194cf','春晚','釋文珦','宋','宋诗','song-poetry','','[]','黄鳥聲中春意深，百花如夢已消沉。',32,'全唐诗/poet.song.219000.json','["黄鳥聲中春意深，百花如夢已消沉。", "午窗睡覺心無事，行過溪南看綠陰。"]'),
('4b7a87a1-3a94-4834-a518-c53cf9e9ffbb','客舍春日久雨','釋文珦','宋','宋诗','song-poetry','','[]','自入春來日日陰，客愁春恨兩難禁。',32,'全唐诗/poet.song.219000.json','["自入春來日日陰，客愁春恨兩難禁。", "不知門外東風信，看見池塘春水深。"]'),
('f4774f4a-085e-4ebc-bfcd-3daed427df07','柳花','釋文珦','宋','宋诗','song-poetry','','[]','岸柳飛花老却春，風前何事巧隨人。',32,'全唐诗/poet.song.219000.json','["岸柳飛花老却春，風前何事巧隨人。", "都緣漂蕩無歸處，全似天涯倦客身。"]'),
('50f2169b-746a-4ab8-bad4-1eac4571d16b','送禪上人歸日本','釋文珦','宋','宋诗','song-poetry','','[]','今日送君歸日東，便成永別恨難窮。',32,'全唐诗/poet.song.219000.json','["今日送君歸日東，便成永別恨難窮。", "海邦萬里波濤隔，不似青山有路通。"]'),
('9701daf7-3ae1-46cf-970b-a3cd99ad6a36','送僧歸隠','釋文珦','宋','宋诗','song-poetry','','[]','道林身世一何閒，去似孤雲不可攀。',32,'全唐诗/poet.song.219000.json','["道林身世一何閒，去似孤雲不可攀。", "若果怕人知隠迹，買山休買有名山。"]'),
('347862c6-cf6d-4d2a-b2ec-e688a1ddcf50','送僧還山','釋文珦','宋','宋诗','song-poetry','','[]','閒雲一片又飛還，松桂蕭森滿舊山。',32,'全唐诗/poet.song.219000.json','["閒雲一片又飛還，松桂蕭森滿舊山。", "後夜有誰相伴住，自聽泉落翠微間。"]'),
('69114e37-b59a-45cd-81a8-dd0b5bf7a2ff','送僧歸靜林精舍','釋文珦','宋','宋诗','song-poetry','','[]','天竺山中秋講散，露蛩煙鴈動鄉情。',32,'全唐诗/poet.song.219000.json','["天竺山中秋講散，露蛩煙鴈動鄉情。", "五株松下梁朝寺，歸聽羅浮古磬聲。"]'),
('77018625-f2a7-4181-bf30-073d6fecc765','病起  其一','釋文珦','宋','宋诗','song-poetry','','[]','病起山房四壁空，一年春盡雨聲中。',32,'全唐诗/poet.song.219000.json','["病起山房四壁空，一年春盡雨聲中。", "無人知道情懷惡，獨倚溪橋看落紅。"]'),
('29971677-94d2-4b71-a9d2-53e821119f51','病起  其二','釋文珦','宋','宋诗','song-poetry','','[]','卧病厭厭斷聞見，年頭未識春風面。',32,'全唐诗/poet.song.219000.json','["卧病厭厭斷聞見，年頭未識春風面。", "今朝强起步晴光，傷心滿地殘梅片。"]'),
('18b38bac-3c94-423d-83e0-cdc8a3799a3c','杜鵑','釋文珦','宋','宋诗','song-poetry','','[]','遊魂變化事無涯，吳蜀相望萬里賒。',32,'全唐诗/poet.song.219000.json','["遊魂變化事無涯，吳蜀相望萬里賒。", "回首故宮歸不得，聲聲啼血染山花。"]'),
('7f413a45-335d-4544-afe8-3da35e155f26','老耳聾聵乙酉歲絕不聞鵑啼','釋文珦','宋','宋诗','song-poetry','','[]','湖海漂流歲月長，每聞杜宇輒思鄉。',32,'全唐诗/poet.song.219000.json','["湖海漂流歲月長，每聞杜宇輒思鄉。", "如今耳與聲塵絕，啼殺吾心也不傷。"]'),
('d4c921d5-ca44-4d24-a8c1-e26a351fb19a','山中隠者居','釋文珦','宋','宋诗','song-poetry','','[]','書滿茅堂藥滿園，路蹊深絕似桃源。',32,'全唐诗/poet.song.219000.json','["書滿茅堂藥滿園，路蹊深絕似桃源。", "夕陽過去樵聲盡，一箇獼猴出掩門。"]'),
('d0ab445d-cc9b-42f3-a996-30a5a2b4a1e0','不出','釋文珦','宋','宋诗','song-poetry','','[]','不出柴門三月彊，亦無詩句答風光。',32,'全唐诗/poet.song.219000.json','["不出柴門三月彊，亦無詩句答風光。", "悠然自有深居樂，滿徑從教春草長。"]'),
('282ab9c3-c929-4fd4-8822-7e95a4bdaeee','無心','釋文珦','宋','宋诗','song-poetry','','[]','出本無心倦即歸，悠悠天地一支離。',32,'全唐诗/poet.song.219000.json','["出本無心倦即歸，悠悠天地一支離。", "此真難與時人說，惟有山雲乃得知。"]'),
('139bfdb2-17cd-4d73-a493-eb51da6c31c2','秋曉訪菊','釋文珦','宋','宋诗','song-poetry','','[]','醉陶爲爾早辭官，醒屈曾將當夕餐。',32,'全唐诗/poet.song.219000.json','["醉陶爲爾早辭官，醒屈曾將當夕餐。", "我愛露叢深似染，曉尋特地犯清寒。"]'),
('f721380a-5894-4609-a786-02f87090d841','落葉','釋文珦','宋','宋诗','song-poetry','','[]','落葉重重與砌平，流泉澹澹入池清。',32,'全唐诗/poet.song.219000.json','["落葉重重與砌平，流泉澹澹入池清。", "無人識我無人到，獨自吟詩獨自行。"]'),
('9b123fd8-4ea2-4e67-810f-1cb45504ae57','不留塵物','釋文珦','宋','宋诗','song-poetry','','[]','不留塵物涴吾清，更喜官中無姓名。',32,'全唐诗/poet.song.219000.json','["不留塵物涴吾清，更喜官中無姓名。", "淡飯粗衣隨處樂，登山臨水一身輕。"]'),
('300b227b-ee43-4545-a270-ea7ffa196d15','湖上雨中晚歸','釋文珦','宋','宋诗','song-poetry','','[]','冷澹一堤枯柳，孤高九里寒松。',28,'全唐诗/poet.song.219000.json','["冷澹一堤枯柳，孤高九里寒松。", "行盡北山煙雨，白雲深處聞鐘。"]'),
('2b9992eb-7180-4253-b3a7-4d3dc360a86f','秋思','釋文珦','宋','宋诗','song-poetry','','[]','聽說相思情緒，難禁最是秋時。',28,'全唐诗/poet.song.219000.json','["聽說相思情緒，難禁最是秋時。", "燕去重增別恨，鴈來不報歸期。"]'),
('8637e700-cd05-40f4-b565-e6177db3a8e3','山樓夜','釋文珦','宋','宋诗','song-poetry','','[]','月滿千重林壑，人憑一曲闌干。',28,'全唐诗/poet.song.219000.json','["月滿千重林壑，人憑一曲闌干。", "但覺衣襟徵潤，不知風露高寒。"]'),
('a6b81507-fbaf-43fb-8879-61560b5525c0','扁舟夜返','釋文珦','宋','宋诗','song-poetry','','[]','扁舟頗多幽趣，孤月正照寒沙。',28,'全唐诗/poet.song.219000.json','["扁舟頗多幽趣，孤月正照寒沙。", "曲渚回塘深處，青燈竹屋誰家。"]'),
('a05b0347-ae56-4dfd-bd5a-736cb5508d97','久客','釋文珦','宋','宋诗','song-poetry','','[]','落日回潮寂寞，西風老柳蕭疎。',28,'全唐诗/poet.song.219000.json','["落日回潮寂寞，西風老柳蕭疎。", "久客自知津渡，故人不寄音書。"]'),
('63c0df10-807c-4314-8ca2-a6e1cd7cde4d','晚秋野外','釋文珦','宋','宋诗','song-poetry','','[]','隔岸茅茨低小，臨溪草徑橫斜。',28,'全唐诗/poet.song.219000.json','["隔岸茅茨低小，臨溪草徑橫斜。", "楊柳已無餘葉，芙蓉尚有殘花。"]'),
('a760b519-39a3-4559-a13c-6b676b7f6e67','野外','釋文珦','宋','宋诗','song-poetry','','[]','絕巘應藏佛屋，深源定有仙家。',28,'全唐诗/poet.song.219000.json','["絕巘應藏佛屋，深源定有仙家。", "風裏傳來清梵，澗中流出胡麻。"]'),
('2a31c259-a436-460a-8d4f-95c7fd888775','春曉尋山家','釋文珦','宋','宋诗','song-poetry','','[]','石澗寒流不盡，茅簷宿雨初晴。',28,'全唐诗/poet.song.219000.json','["石澗寒流不盡，茅簷宿雨初晴。", "幽客眠雲未起，四時鳥弄春聲。"]'),
('1714d909-e603-4f82-af95-79da00febc4c','夢覺','釋文珦','宋','宋诗','song-poetry','','[]','七十五聲更漏，一千餘里鄉心。',28,'全唐诗/poet.song.219000.json','["七十五聲更漏，一千餘里鄉心。", "夢裏分明歸去，覺來無處追尋。"]'),
('231e05a9-b0c6-45e8-b476-bcbef9023947','書山水畫卷','釋文珦','宋','宋诗','song-poetry','','[]','遠浦漁舟若箇，荒林草屋誰家。',28,'全唐诗/poet.song.219000.json','["遠浦漁舟若箇，荒林草屋誰家。", "不信丹青能爾，分明鴈落平沙。"]'),
('34af8bfb-f41f-4592-9ccf-f1a40245f04f','得性','釋文珦','宋','宋诗','song-poetry','','[]','得性賢於得祿，歸山勝似歸朝。',28,'全唐诗/poet.song.219000.json','["得性賢於得祿，歸山勝似歸朝。", "飲澗肺腸清浄，卧雲魂夢逍遥。"]'),
('2a9d0fd5-bede-455a-9a92-a55a728fbd19','闕題  其一','釋文珦','宋','宋诗','song-poetry','','[]','大藥生自心田，神方藴乎靈府。',28,'全唐诗/poet.song.219000.json','["大藥生自心田，神方藴乎靈府。", "不論火候抽添，萬病自然良愈。"]'),
('0eb6d830-4372-42b6-9a15-98cb6438495c','闕題  其二','釋文珦','宋','宋诗','song-poetry','','[]','衆患皆因有欲，一閒全得無聞。',28,'全唐诗/poet.song.219000.json','["衆患皆因有欲，一閒全得無聞。", "心定常如止水，身安不喜行雲。"]'),
('d86899d2-6069-4130-91db-732e91740fa1','闕題  其三','釋文珦','宋','宋诗','song-poetry','','[]','飲罷唯圖睡快，老來不作書癡。',28,'全唐诗/poet.song.219000.json','["飲罷唯圖睡快，老來不作書癡。", "一味古人糟粕，誰能更辨醇醨。"]'),
('f71ad329-48e4-4f4e-af95-3e7080a20793','闕題  其四','釋文珦','宋','宋诗','song-poetry','','[]','吾生本不識字，人謂吾詩入微。',28,'全唐诗/poet.song.219000.json','["吾生本不識字，人謂吾詩入微。", "篇章聊復爾耳，止觀然猶庶幾。"]'),
('0790a95b-193a-4adb-8f79-3f735e861758','剡源山房','釋文珦','宋','宋诗','song-poetry','','[]','茅屋小於船，寒宵此會偏。',144,'全唐诗/poet.song.219000.json','["茅屋小於船，寒宵此會偏。", "苦吟因靜得，幽思與閒便。", "斷壁棲雲氣，虛窗閉篆煙。", "帖殘重補畫，琴老不勝絃。", "畫軸塵爲古，茶鑪火自然。", "細泉膠莧腹，凍鶴墮松巔。", "石皷鳴如磬，甆缾色類鉛。", "雪明燈焰減，風遠漏聲傳。", "鼠黠窺人走，僮頑背客眠。", "骨清神欲脫，興逸語猶顛。", "野性終應在，浮名豈足纏。", "欲從支遁隠，未有買山錢。"]'),
('bef95a2d-1851-44d7-8a72-0d7071dbbb01','和盧推官中秋遇雨','釋文珦','宋','宋诗','song-poetry','','[]','秋中唯此夕，雨蔽月圓時。',72,'全唐诗/poet.song.219000.json','["秋中唯此夕，雨蔽月圓時。", "握管沉幽思，臨軒失舊期。", "孤燈花謾落，良會信成虧。", "宋玉悲潛長，安仁鬢亦衰。", "簷聲愁裏滴，星度暗中移。", "到曉休臨鑑，霜髯只自欺。"]'),
('db54402a-ca7b-4d86-97c1-d146f52e27a3','錢塘晚渡別友','釋文珦','宋','宋诗','song-poetry','','[]','寒月照沙頭，輕風引客舟。',72,'全唐诗/poet.song.219000.json','["寒月照沙頭，輕風引客舟。", "掛帆重曠望，舉櫂復夷猶。", "地勢連吳越，星躔次斗牛。", "鴈煙縈別思，漁火點鄉愁。", "雙鬢誰憐白，單衣自怯秋。", "明朝定相憶，獨上水邊樓。"]'),
('3a90dd70-859d-45ea-b909-bd967e856c29','同諸友尋幽登飛來峰','釋文珦','宋','宋诗','song-poetry','','[]','湖際山何限，飛來獨著名。',192,'全唐诗/poet.song.219000.json','["湖際山何限，飛來獨著名。", "玲瓏疑鬼鑿，崷崒自天成。", "猿去猶存洞，龍歸尚有泓。", "樹因含玉潤，泉爲煉丹清。", "桂子排空落，蓮花浥露擎。", "鷲形傳佛國，靈應動神京。", "翻譯賢人迹，稽留隠者情。", "脩藤垂萬歲，孤石記三生。", "夜講臺偏古，春風檜重榮。", "賓王辭可訊，慧理塔難平。", "客至心多戀，僧居慮自輕。", "躋攀雖詰屈，臨眺獨高明。", "觀闕雄三島，衣冠邁百城。", "東南且行在，西北待經營。", "溟漲無涯涘，江流但注傾。", "一時歸眼界，終古播詩聲。"]'),
('a4d4c46b-c213-4dbb-a7b4-2e2ee42dd193','晚步','釋文珦','宋','宋诗','song-poetry','','[]','晚策信所往，幽懷那可窮。',96,'全唐诗/poet.song.219000.json','["晚策信所往，幽懷那可窮。", "孤村流水外，古木亂山中。", "雨過天容浄，風收地籟空。", "淡煙歸獨鳥，深澗飲長虹。", "日下青峰表，潮生滄海東。", "光吞羣象沒，氣混百川雄。", "㭬杙知樵子，乘舟識釣翁。", "閒身天與健，蕭散復誰同。"]'),
('6713e8a8-fe05-46fc-b187-0d984e6ce6bb','馮深居挽詞','釋文珦','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','天地一深翁，匡廬氣所鍾。',132,'全唐诗/poet.song.219000.json','["天地一深翁，匡廬氣所鍾。", "親傳厚齋業，優得考亭宗。", "勁節霜崖竹，高標雪嶠松。", "滄溟含雅量，干莫避辭鋒。", "元老皆知敬，憸夫獨不容。", "畏塗嘗跌足，道院蹔潛縱。", "冤白州麾晚，身亡奠斝重。", "魂應歸帝所，人盡哭堂封。", "有道存方冊，無名上景鐘。", "死生今隔異，湖海昔過從。", "芻束無繇致，愁凝五老峰。"]'),
('4ddb8c53-1972-46e5-8f23-26c57867dd88','星諸兄挽詞','釋文珦','宋','宋诗','song-poetry','','[]','吾宗老兄弟，夫子最高明。',108,'全唐诗/poet.song.219000.json','["吾宗老兄弟，夫子最高明。", "問學窮根柢，公忠出性情。", "夙能全至孝，元不念脩程。", "道自成均重，身由射策榮。", "把麾聞列郡，持橐貳春卿。", "得請還山早，居家舊疾平。", "正安琳館樂，忽報玉樓成。", "死後名逾盛，生前志未行。", "他年如定謚，謚號决當清。"]'),
('52441489-6942-4669-8d08-63c6d9288b55','閒居多暇追敘舊遊成一百十韻','釋文珦','宋','宋诗','song-poetry','','[]','予生駑且鈍，良御謾加鞭。',288,'全唐诗/poet.song.219000.json','["予生駑且鈍，良御謾加鞭。", "蹇步常居後，長途靡克前。", "於焉辭里塾，竟爾向林泉。", "魯誥方擩嚌，真乘又賾研。", "孳孳羞愒日，矻矻自窮年。", "靈嶽言猶在，天台筆已專。", "玄珠因象得，祖印以心傳。", "終覺符深妙，初非離簡編。", "連環資講貫，涵泳藉詩篇。", "斷斷無他技，愔愔合自然。", "從來憎繫屬，其肯望陶甄。", "謬忝諸公識，常推衆客先。", "歲時頻問勞，旦夕競招延。", "有意行方外，因思去日邊。", "書探禹穴古，鑑入賀湖漣。", "巖壑爭奇秀，涇溪互屬聯。", "鄞江浮汗漫，雪竇踏雲煙。", "曠望方壺表，高躋太白巔。", "石橋誇聖所，華頂歷星躔。", "羽洞僊蹤秘，丹丘地勢偏。", "搘筇踰絕嶠，杭葦下中川。", "秋蕩懷康樂，春池憶惠連。", "尋猿過翠壁，訪鶴列青田。", "古郡名存栝，仙都頂有蓮。"]'),
('d5f4a6ff-c6a6-467f-a8c3-6e931880559b','閒興','釋文珦','宋','宋诗','song-poetry','','[]','分得此生閒，於今老更頑。',72,'全唐诗/poet.song.219000.json','["分得此生閒，於今老更頑。", "心終如白水，身不離青山。", "拙性從人誚，前詩或自刪。", "衡門深草色，壞衲上苔斑。", "雖有貧居樂，猶聞世道艱。", "皇天如有意，會見古風還。"]'),
('c7e89284-1584-4a1e-af23-fee9f35bb5ca','不出','釋文珦','宋','宋诗','song-poetry','','[]','晚暮衰慵劇，因尋此地居。',120,'全唐诗/poet.song.219000.json','["晚暮衰慵劇，因尋此地居。", "山深常見鹿，溪淺少藏魚。", "野徑歸煙僻，寒窗映水虛。", "松枯生蘚遍，梅老著花疎。", "對月空塵翳，眠雲晤卷舒。", "以閒消苑結，因靜得真如。", "兀坐多凭几，徐行不用車。", "公卿誰識我，猿鶴最知予。", "善賈休沽玉，全生願作樗。", "終身期不出，頗自愛吾廬。"]'),
('8cc32241-ca29-4256-b778-952a5715cc54','爲清渭濱作雪深室歌','釋文珦','宋','宋诗','song-poetry','','[]','積雪兮深深，萬卉兮消沈。',50,'全唐诗/poet.song.219000.json','["積雪兮深深，萬卉兮消沈。", "梅獨花兮水之陰，容斯靜兮暗暗。", "香斯清兮不淫。", "有孤操兮慰予心，爲高歌兮詔主林。"]'),
('370cc19c-723d-4eb9-b41d-28e79f8cb89a','放鶴操','釋文珦','宋','宋诗','song-poetry','','[]','相彼胎禽兮有志凌霄，翦翎鎩翼兮羈縻於籠牢，爲時人之近玩兮中心鬰陶。',92,'全唐诗/poet.song.219000.json','["相彼胎禽兮有志凌霄，翦翎鎩翼兮羈縻於籠牢，爲時人之近玩兮中心鬰陶。", "有高人兮逆知其然，養成羽儀兮縱之於千仞之巔，使全其性兮逍遥乎九天。", "九天之高兮穹窿，鶴之樂兮融融，維高人之德兮與天無窮。"]'),
('6e4cb603-fa1f-48cf-a3db-e88478982078','貴家園池夏夜','釋文珦','宋','宋诗','song-poetry','','[]','楊柳蔭華館，菡萏生回塘。',48,'全唐诗/poet.song.219000.json','["楊柳蔭華館，菡萏生回塘。", "薰風散炎蒸，積水生夜涼。", "長歌滄浪曲，可洗冰炭腸。", "主人不知愛，白頭猶異方。"]'),
('8c7f5b82-c1af-43c1-98f1-f968a7c32c6e','平齋老先生遊霅城葉氏園池有作俾次元韻','釋文珦','宋','宋诗','song-poetry','','["\u8861\u5c71"]','名園無俗情，漁子往來密。',48,'全唐诗/poet.song.219000.json','["名園無俗情，漁子往來密。", "憑闌古城近，屏翳秀石出。", "弁衡山獻青，苕霅水□碧。", "好景吟不窮，煙霏又將夕。"]'),
('67f35cf6-5b3f-4b7b-bf3b-1fd28dc55633','二疏','釋文珦','宋','宋诗','song-poetry','','[]','漢朝諸公卿，鮮有能自全。',60,'全唐诗/poet.song.219000.json','["漢朝諸公卿，鮮有能自全。", "廣受信明哲，獨悟於機先。", "託之老氏訓，辭祿偕歸田。", "祖帳東都門，萬口稱其賢。", "於今閲千齡，高風猶凜然。"]'),
('a926877b-e4d3-4a04-aa30-3f4773a18ae1','越中三江斗門','釋文珦','宋','宋诗','song-poetry','','[]','斗門何代設，千古截寒潮。',48,'全唐诗/poet.song.219000.json','["斗門何代設，千古截寒潮。", "水廟依楓樹，湖田足葑苗。", "衆山臨海盡，叢港達城遥。", "落日漁歌裏，西風動泬寥。"]'),
('e7751010-74ea-4bbb-9a15-b8f0b8488455','柴門','釋文珦','宋','宋诗','song-poetry','','[]','柴門雖設不曾關，時有忘機客往還。',64,'全唐诗/poet.song.219000.json','["柴門雖設不曾關，時有忘機客往還。", "風送釣舟來北渚，雨催樵子下西山。", "生前富貴何勞美，身後聲名亦是閒。", "萬慮消除心自在，從教人道我疎頑。"]'),
('1c5c5a45-aae3-47bb-9eb8-f156950955f9','衡門  其一','釋文珦','宋','宋诗','song-poetry','','[]','衡門隨我分，可是賤儒冠。',48,'全唐诗/poet.song.219000.json','["衡門隨我分，可是賤儒冠。", "任性中腸樂，無營夢境安。", "澗聲暗後響，山氣夜深寒。", "活計何勞問，薇生採不難。"]'),
('1a282a82-edc6-4d8b-8e8a-77e4a89543a4','衡門  其二','釋文珦','宋','宋诗','song-poetry','','[]','鐵錫已高懸，殘山剩水邊。',48,'全唐诗/poet.song.219000.json','["鐵錫已高懸，殘山剩水邊。", "算年齊易卦，寫夢入詩篇。", "介癖游從少，幽深景物偏。", "衡門終日掩，吾自守吾玄。"]'),
('c3278339-fcef-453e-8b70-8e5bcd8a65e8','江村','釋文珦','宋','宋诗','song-poetry','','[]','古樹兩三株，人家四散居。',48,'全唐诗/poet.song.219000.json','["古樹兩三株，人家四散居。", "草簷經雨爛，沙路過潮虛。", "漁罷籬懸網，耕歸壁掛鋤。", "相呼命鄰叟，農隙課兒書。"]'),
('4acaa945-f958-4137-994c-466aab2fdecd','水村即事二首  其一','釋文珦','宋','宋诗','song-poetry','','[]','祭鼓鼕鼕野廟，茅茨小小人家。',28,'全唐诗/poet.song.219000.json','["祭鼓鼕鼕野廟，茅茨小小人家。", "水際數株榆柳，籬邊幾陸桑麻。"]'),
('cd18eb8e-6d5a-4a2b-9987-a185d43df1ca','水村即事二首  其二','釋文珦','宋','宋诗','song-poetry','','[]','草徑別通村墅，柴門祇對河塍。',28,'全唐诗/poet.song.219000.json','["草徑別通村墅，柴門祇對河塍。", "老婦自安鷄柵，小兒解守魚罾。"]'),
('061d82d2-f9c5-476f-ac6c-43b8911d4a19','山村','釋文珦','宋','宋诗','song-poetry','','[]','山村幾家住，茅屋障春泥。',48,'全唐诗/poet.song.219000.json','["山村幾家住，茅屋障春泥。", "麥隴微通徑，桑林半閣梯。", "過溪孤放犢，隔巷數聲鷄。", "全似桃源裏，遊人到欲迷。"]'),
('1b4526cd-9804-460b-9e13-1a54273752b6','爲仇近仁賦山村','釋文珦','宋','宋诗','song-poetry','','[]','我愛山村人，自得山村趣。',96,'全唐诗/poet.song.219000.json','["我愛山村人，自得山村趣。", "唯與漁樵狎，絕無軒冕慕。", "高情寄雲松，至樂在霜芋。", "長吟招隠詩，更作閒居賦。", "出處均一靜，曠達遺萬慮。", "猶嫌車馬喧，肯受塵土污。", "白駒志雖潔，玄豹斑已露。", "祗恐鶴書來，奪我良朋去。"]'),
('045798f1-f36f-43fb-8888-78f1a5b6a6a9','深村','釋文珦','宋','宋诗','song-poetry','','[]','深村堪就隠，隨處有人家。',48,'全唐诗/poet.song.219000.json','["深村堪就隠，隨處有人家。", "地遠官無禁，年豐酒易賒。", "烟波藏釣艇，山雨送樵車。", "絕似桃源裏，唯無洞口花。"]'),
('23a38aba-c8f7-4173-ae48-e94947329c0a','靜處','釋文珦','宋','宋诗','song-poetry','','[]','常於靜處著閒身，別是清虛冷淡人。',64,'全唐诗/poet.song.219000.json','["常於靜處著閒身，別是清虛冷淡人。", "禪裏斷除千種法，吟中消受一生貧。", "聲名豈必存編簡，林壑從來有隠淪。", "雲月溪山無限景，對餘一一意皆真。"]'),
('1b9ea64b-bb7a-4095-a4ee-a8101c61461a','萬山深處','釋文珦','宋','宋诗','song-poetry','','[]','萬山深處絕諠嘩，野鶴孤猿共此家。',64,'全唐诗/poet.song.219000.json','["萬山深處絕諠嘩，野鶴孤猿共此家。", "莫使游塵污泉石，有妨閑客卧烟霞。", "寒衣綠芰千層葉，饑食青松數樹花。", "無可破除無可羨，清貧却是好生涯。"]'),
('cb8bea77-d815-44fc-906f-f1ebf6f4e769','身嬾','釋文珦','宋','宋诗','song-poetry','','[]','身嬾都忘動，心空不待安。',36,'全唐诗/poet.song.219000.json','["身嬾都忘動，心空不待安。", "葉鳴山鹿至，火盡地鑪寒。", "即此爲吾樂，同人話却難。"]'),
('9a909e5d-6dde-4641-b230-2d8938083dc5','身閑  其一','釋文珦','宋','宋诗','song-poetry','','[]','身閒日日日高眠，疏牖開於疊嶂邊。',64,'全唐诗/poet.song.219000.json','["身閒日日日高眠，疏牖開於疊嶂邊。", "巨竹拂雲知地力，細泉鳴玉自天然。", "牆頭盧橘金丸重，籬角楊梅火齊圓。", "只與禽猿同此樂，莫教馬跡到門前。"]'),
('8931a191-e2e8-4098-bc2f-165071a74130','身閑  其二','釋文珦','宋','宋诗','song-poetry','','[]','身閒更喜交遊絕，三徑寥寥草樹荒。',64,'全唐诗/poet.song.219000.json','["身閒更喜交遊絕，三徑寥寥草樹荒。", "但覺空門無住著，不知塵世有炎凉。", "吟殘海月生松壁，定起山雲滿石床。", "何緣饑渴猶相累，擬覓幽人斷穀方。"]'),
('1ab3127e-efb3-44a9-9b65-ac892d81b9f0','癖性','釋文珦','宋','宋诗','song-poetry','','[]','癖性唯耽靜，溪山占一坳。',48,'全唐诗/poet.song.219000.json','["癖性唯耽靜，溪山占一坳。", "小橋橫獨水，矮屋蓋重茅。", "坎井寒泉冽，深蹊密陰交。", "閒門終日掩，不許俗人敲。"]'),
('e3c97197-efb4-4b81-b16e-d8a12214950b','敘志','釋文珦','宋','宋诗','song-poetry','','[]','夙了萬緣空，年衰轉更慵。',48,'全唐诗/poet.song.219000.json','["夙了萬緣空，年衰轉更慵。", "夢身休化蝶，病耳畏聞蛩。", "野服蘿堪製，山糧穄可舂。", "誓將雲木友，怕與世人逢。"]'),
('091dcd21-251c-40c0-aee5-fd9cb8e84409','言志  其一','釋文珦','宋','宋诗','song-poetry','','[]','凡物無美惡，適俗斯見收。',48,'全唐诗/poet.song.219000.json','["凡物無美惡，適俗斯見收。", "荆玉勿彊獻，隋珠毋暗投。", "苟曰道不同，其可相爲謀。", "知己盡淪喪，吾生行且休。"]'),
('d3783faf-4c6b-4074-b5b7-692d4c5ff1fe','言志  其二','釋文珦','宋','宋诗','song-poetry','','[]','人生在斯世，窮達懸諸天。',48,'全唐诗/poet.song.219000.json','["人生在斯世，窮達懸諸天。", "迷徒不知此，多爲外物遷。", "豈若保真素，白雲日高眠。", "鴻飛杳冥冥，弋者何慕焉。"]'),
('4014b782-d775-488f-b291-47878305ac04','言志  其三','釋文珦','宋','宋诗','song-poetry','','[]','衆人窮智慮，沒齒常區區。',48,'全唐诗/poet.song.219000.json','["衆人窮智慮，沒齒常區區。", "吾獨不能爾，林卧安其愚。", "聰明既寂絕，因之得玄珠。", "其珠有夜光，終將破昏衢。"]'),
('12154ac2-e9cb-40b4-8d9d-2d5bdd7bd4af','言志  其四','釋文珦','宋','宋诗','song-poetry','','[]','山中良自好，住久樂已成。',48,'全唐诗/poet.song.219000.json','["山中良自好，住久樂已成。", "山木有嘉蔭，山禽無俗聲。", "永言辭世路，世路多不平。", "亦以性疎嬾，不能但勞生。"]'),
('249bad58-873b-4ffe-b6ff-988fab561fc0','言志  其五','釋文珦','宋','宋诗','song-poetry','','[]','吾生癖而慵，煙霞成痼疾。',48,'全唐诗/poet.song.219000.json','["吾生癖而慵，煙霞成痼疾。", "千山復萬山，曾不厭深密。", "廣厦非所睎，分甘死蓬蓽。", "或問予如何，高明鬼瞰室。"]'),
('80dc8d8d-bf71-4d93-a5d5-5036e4a0f3f1','言志  其六','釋文珦','宋','宋诗','song-poetry','','[]','窮居雖寂寥，苦節諒難改。',48,'全唐诗/poet.song.219000.json','["窮居雖寂寥，苦節諒難改。", "青青山上薇，朝莫猶可採。", "薇盡而長饑，餓死亦無悔。", "古者夷與齊，清風彌億載。"]'),
('b754cbd8-4fa7-45c0-8e14-568dcf83dc42','言志  其七','釋文珦','宋','宋诗','song-poetry','','[]','人壽能幾何，百年猶一霎。',48,'全唐诗/poet.song.219000.json','["人壽能幾何，百年猶一霎。", "豈識貂蟬貴，且與漁樵狎。", "飲澗不需瓢，採山時荷鍤。", "世人莫相嗤，吾自用吾法。"]'),
('62875a49-ce87-4a2c-b7c6-d00e30eccf55','草衣木食','釋文珦','宋','宋诗','song-poetry','','[]','草衣而木食，老子樂在內。',48,'全唐诗/poet.song.219000.json','["草衣而木食，老子樂在內。", "身似玄空雲，蹤跡了無礙。", "雙松亦孤高，青青遠爲對。", "富貴不須論，本非吾所愛。"]'),
('7c663ee0-2c38-495c-9123-56bba9b57c75','煨芋','釋文珦','宋','宋诗','song-poetry','','[]','隠者似孤雲，都忘厭與忻。',48,'全唐诗/poet.song.219000.json','["隠者似孤雲，都忘厭與忻。", "漁樵每爭席，鸞鶴自爲群。", "地僻雲常滿，山高日易曛。", "蹲鴟煨正熟，不與俗人分。"]'),
('74375fe0-86d7-4433-9a00-4ed2c847ff79','懷友  其一','釋文珦','宋','宋诗','song-poetry','','[]','故交今何處，音問久不接。',48,'全唐诗/poet.song.219000.json','["故交今何處，音問久不接。", "歲月易蹉跎，關山更重疊。", "凝霜遍衰草，寒日照黄葉。", "幾度欲相尋，清川苦難涉。"]'),
('66955b72-1edb-44cc-be95-f35b8eeb3bd5','懷友  其二','釋文珦','宋','宋诗','song-poetry','','[]','路隔千里遥，人經十年別。',48,'全唐诗/poet.song.219000.json','["路隔千里遥，人經十年別。", "音書久不至，芳草又還歇。", "青山天外盡，白鳥煙中沒。", "此夕倚江樓，相思心欲絕。"]'),
('7e105bc5-63ed-4e92-82e4-ffec6e047862','隠懷','釋文珦','宋','宋诗','song-poetry','','[]','負疴在山澤，已若無此生。',72,'全唐诗/poet.song.219000.json','["負疴在山澤，已若無此生。", "期與草木盡，隠人不須名。", "西南數奇峰，宛同親弟兄。", "悠然有靜意，青青日相迎。", "因持短柄鑱，入山斸黄精。", "志不在苟得，聊復怡吾情。"]'),
('b6ea253e-ff14-4b5e-812c-9bb6a385a668','懷溪雲壑','釋文珦','宋','宋诗','song-poetry','','[]','夜深臺殿閉，空室自安禪。',48,'全唐诗/poet.song.219000.json','["夜深臺殿閉，空室自安禪。", "松頂掛寒月，竹根鳴暗泉。", "理方因靜勝，道不在言傳。", "溪友同知此，今居何處邊。"]'),
('d4cc48df-f2c4-49fc-9a87-bbf6a486b025','懷寄同志','釋文珦','宋','宋诗','song-poetry','','[]','垂垂當莫景，每每憶同參。',48,'全唐诗/poet.song.219000.json','["垂垂當莫景，每每憶同參。", "金石敦風誼，雲山異北南。", "道機應已熟，世夢莫教酣。", "路遠難相語，裁詩寄短函。"]'),
('c30dd410-f34b-44fd-8618-a3bde6fd5bf8','懷天童故棲','釋文珦','宋','宋诗','song-poetry','','[]','高僧住太白，給侍來天童。',48,'全唐诗/poet.song.219000.json','["高僧住太白，給侍來天童。", "東嶺極遐曠，西巖亦玲瓏。", "神龍宅其巔，風雲自相通。", "久別勞夢寐，何當返山中。"]'),
('dc3f3706-f615-44a4-95ef-eaa495c33843','旅夜思親','釋文珦','宋','宋诗','song-poetry','','[]','故里多離別，他鄉久滯留。',48,'全唐诗/poet.song.219000.json','["故里多離別，他鄉久滯留。", "蟲聲偏入夜，客夢不禁秋。", "枯葉兼風響，清溪带月流。", "倚門應望切，明日問歸舟。"]'),
('3dc87fb6-d169-4539-a87d-110b8943792c','憶友','釋文珦','宋','宋诗','song-poetry','','[]','同人久別離，消息不曾知。',24,'全唐诗/poet.song.219000.json','["同人久別離，消息不曾知。", "心似長堤柳，千絲又萬絲。"]'),
('f9571b53-6f68-4561-b3f2-3da0cb152b32','贈雲英院','釋文珦','宋','宋诗','song-poetry','','[]','賈島憐無可，都緣數句詩。',48,'全唐诗/poet.song.219000.json','["賈島憐無可，都緣數句詩。", "君雖是後輩，我謂過當時。", "溪浪和星動，松陰带鶴移。", "因吟到明坐，此道澹誰知。"]'),
('40b0f9b5-3977-487b-9db6-1416e5fd0b2a','寄林弓寮','釋文珦','宋','宋诗','song-poetry','','[]','暗數鳴絃日，知君已及瓜。',48,'全唐诗/poet.song.219000.json','["暗數鳴絃日，知君已及瓜。", "水光浮縣郭，山色滿樵家。", "訟簡遲開印，庭空早放衙。", "傳來多美政，不獨種桃花。"]'),
('fdfa6641-1079-4a3a-b2a1-d9794dbcad63','寄友  其一','釋文珦','宋','宋诗','song-poetry','','[]','故人相別去，歲月良已深。',96,'全唐诗/poet.song.219000.json','["故人相別去，歲月良已深。", "人皆寄音書，我唯寄其心。", "心真無轉移，音書有浮湛。", "所寄匪有它，但願保斯諶。", "毋爲威武屈，毋爲富貴淫。", "與其常戚戚，不如自愔愔。", "但使吾道存，何傷貧病侵。", "難與昧者言，託之於長吟。"]'),
('936dfecd-f17f-425b-881d-9f813f9d21bd','寄友  其二','釋文珦','宋','宋诗','song-poetry','','[]','半生行李各東西，無柰相思億萬重。',32,'全唐诗/poet.song.219000.json','["半生行李各東西，無柰相思億萬重。", "又恐因書增別恨，人行不敢寄緘封。"]'),
('b203bc07-9419-46fd-b505-6d79c0451394','寄友  其三','釋文珦','宋','宋诗','song-poetry','','[]','疎索復疎索，世道今難託。',48,'全唐诗/poet.song.219000.json','["疎索復疎索，世道今難託。", "驥騄筋力殘，鸞凰羽毛落。", "林公古人徒，風期諒如昨。", "歸來乎山中，携手共行樂。"]'),
('ced5ba17-25ae-4bd1-b4ad-08b25692b364','寄山中友人  其一','釋文珦','宋','宋诗','song-poetry','','[]','聞道幽棲野思饒，徑無塵迹草蕭蕭。',64,'全唐诗/poet.song.219000.json','["聞道幽棲野思饒，徑無塵迹草蕭蕭。", "長松架壑因爲屋，老櫸橫溪便作橋。", "煮石未須閒水碓，漱流何必棄風瓢。", "吾生更愛深居樂，定擬相從不待招。"]'),
('1e8b54d0-81e3-4470-b9b7-d385b98687a9','寄山中友人  其二','釋文珦','宋','宋诗','song-poetry','','[]','清修二師持遠徒，麻衣草座深山居。',64,'全唐诗/poet.song.219000.json','["清修二師持遠徒，麻衣草座深山居。", "心如蓮花不著水，身似孤雲行太虛。", "記得茅堂明月夕，同汲寒泉煮白石。", "多年不見擬相尋，秋風落葉迷行跡。"]'),
('f3f2ac06-3681-4dca-be97-6d20346174f4','寄遊邊友人','釋文珦','宋','宋诗','song-poetry','','[]','念君爲遠役，日日爲君愁。',48,'全唐诗/poet.song.219000.json','["念君爲遠役，日日爲君愁。", "直道無知己，身貧難自由。", "角吹關月曉，鼙動磧霜秋。", "想亦懷歸切，慈親雪滿頭。"]'),
('4b66738a-9a93-46fc-b5b2-af5cc3f554d8','寄社人','釋文珦','宋','宋诗','song-poetry','','[]','居士性無染，栽蓮徧芳洲。',48,'全唐诗/poet.song.219000.json','["居士性無染，栽蓮徧芳洲。", "宛在東林社，如乘太一舟。", "清香入書帷，浄色涵衣篝。", "尚友千載間，宗雷亦君儔。"]'),
('e7e4d0e5-7bf8-48ef-8805-ee37ceb55d51','寄林竹谿','釋文珦','宋','宋诗','song-poetry','','[]','四海寥寥孰可宗，唯知谿上有谿翁。',64,'全唐诗/poet.song.219000.json','["四海寥寥孰可宗，唯知谿上有谿翁。", "乾坤盡入文心裏，今古同歸醉眼中。", "梅子熟時明祖意，竹君多處振清風。", "野人祇是空相憶，浙水閩山信不通。"]'),
('cdad1505-7e8f-4bd4-90f4-9e73b6973855','韓東山遠訪於西岑寄','釋文珦','宋','宋诗','song-poetry','','[]','東東魏國之雲仍，一清不減玉壺冰。',96,'全唐诗/poet.song.219000.json','["東東魏國之雲仍，一清不減玉壺冰。", "生平閉戶養真素，隠節久爲人所稱。", "遠來訪我青蓮嶂，道骨仙風極閒曠。", "正是秋風落葉時，坐石分題語尤壯。", "奈何蹔合還又分，匆匆不得盡殷勤。", "如今相憶難相見，日日長歌日莫雲。"]'),
('7c83d594-db0c-44a7-89ee-7d11e08f7361','雨後寄侃直翁新行古','釋文珦','宋','宋诗','song-poetry','','[]','相去亦不遠，相尋殊覺難。',48,'全唐诗/poet.song.219000.json','["相去亦不遠，相尋殊覺難。", "一旬長苦雨，五月尚清寒。", "石屋深浮靄，山溪易作瀾。", "今朝喜新霽，始得問平安。"]'),
('e2f4aba8-e92a-44c8-a6d5-a0857a27825d','寄贈林石田','釋文珦','宋','宋诗','song-poetry','','[]','人言石田無所用，我道此田好畦壟。',64,'全唐诗/poet.song.219000.json','["人言石田無所用，我道此田好畦壟。", "靈根至竟不曾枯，徧與人間作詩種。", "田翁去作王門客，山翁復有居山癖。", "兩翁無奈路頭分，朝朝莫莫空相憶。"]'),
('ddea3b4b-311c-441a-a391-d570a75844b3','惠蓮峰詩以爲謝','釋文珦','宋','宋诗','song-poetry','','[]','月汀家在帝王都，不藏歌舞唯藏書。',96,'全唐诗/poet.song.219000.json','["月汀家在帝王都，不藏歌舞唯藏書。", "舊詫鄴侯三萬軸，君家所藏還有餘。", "寄我一詩辭縝密，言言皆自書中出。", "復來訪我飛來陰，坐石分題更超軼。", "西山落日催歸軒，執手西風傷別魂。", "他日終期到書室，一一與君重細論。"]'),
('67a8ebbc-fd78-4092-8f2b-6ebb64116757','柔桑','釋文珦','宋','宋诗','song-poetry','','[]','野岸多柔桑，春風長新綠。',24,'全唐诗/poet.song.219000.json','["野岸多柔桑，春風長新綠。", "葉葉是羅紈，不同凡草木。"]'),
('cc2f6de9-bd8a-45d2-93e5-4f1dd8c27521','柳下吟','釋文珦','宋','宋诗','song-poetry','','[]','妸娜綠楊陰，深於夏屋深。',48,'全唐诗/poet.song.219000.json','["妸娜綠楊陰，深於夏屋深。", "居來身自在，勝與俗浮沉。", "坐暑堪忘箑，乘風或散襟。", "清閒消不盡，乞與野鶑吟。"]'),
('b8985d10-b646-4beb-a99d-17c6676579de','曲木詠','釋文珦','宋','宋诗','song-poetry','','[]','擁腫仍卷曲，知經幾度春。',48,'全唐诗/poet.song.219000.json','["擁腫仍卷曲，知經幾度春。", "斯能無用者，絕似養生人。", "儻曰堪繩墨，安能逭斧斤。", "良材有何好，祇以自災身。"]'),
('6efdaba5-0ee8-468f-bc4c-ff21abfcfe49','蒲萄','釋文珦','宋','宋诗','song-poetry','','[]','玉瀣乘旒晚，天漿滿珞秋。',24,'全唐诗/poet.song.219000.json','["玉瀣乘旒晚，天漿滿珞秋。", "孟佗消不得，壓取換凉州。"]'),
('9315ceab-ae47-4b1c-a0bc-4c04d0ebc2a3','得兩金鋪乃秦漢門物以充水滴因作歌','釋文珦','宋','宋诗','song-poetry','','[]','弁翁挽我入吟廬，示以秦漢雙金鋪。',128,'全唐诗/poet.song.219000.json','["弁翁挽我入吟廬，示以秦漢雙金鋪。", "摩挲已覺銅腥盡，色如朱砂赤模糊。", "翁說多年棄中野，野人視之猶土苴。", "我心輒愛收拾歸，用配魏臺銅雀瓦。", "渟泉於中淺且清，玄穎由此生光晶。", "老夫生來亦好古，多翁於古能留情。", "阿房建章渺無所，此鋪獨入文房譜。", "資翁濡翰寫詩詞，千古遺音流樂府。"]'),
('9dab5fda-e1d5-4b28-989f-d0a6b7420100','舟中  其一','釋文珦','宋','宋诗','song-poetry','','[]','滄波渺渺思無窮，歸棹悠悠信夕風。',32,'全唐诗/poet.song.219000.json','["滄波渺渺思無窮，歸棹悠悠信夕風。", "睡去不知何處泊，覺來霜月滿船篷。"]'),
('955e0582-8e9e-4b6a-9f9f-63f110197c7b','舟中  其二','釋文珦','宋','宋诗','song-poetry','','[]','小艇不施檝，飄飄信天風。',84,'全唐诗/poet.song.219000.json','["小艇不施檝，飄飄信天風。", "夷猶清川上，遠近秋光同。", "聽牧弄牛笛，看漁收釣筒。", "閒人有至樂，何須作三公。", "赤舄乃桎梏，玄衮爲牢籠。", "終輸玄真子，寄傲煙波中。", "更愛嚴子陵，高舉如冥鴻。"]'),
('3387d049-e14a-4c6c-bd36-e2ff6b9b35b0','一鉢','釋文珦','宋','宋诗','song-poetry','','[]','一鉢一枝藤，清虛度此生。',48,'全唐诗/poet.song.219000.json','["一鉢一枝藤，清虛度此生。", "不貪爲至寶，可賤是浮名。", "閉戶閒身樂，登山野步輕。", "溪翁與林叟，是識老夫情。"]'),
('561b4c25-4b37-405c-a459-eec6a301fb1c','塞笛','釋文珦','宋','宋诗','song-poetry','','[]','孤笛起寒洲，傳聲到暝樓。',48,'全唐诗/poet.song.219000.json','["孤笛起寒洲，傳聲到暝樓。", "吹人元不怨，聽者自生愁。", "萬里家何所，三年戍未休。", "此時霜月下，白却少年頭。"]'),
('10492061-a747-4839-9e05-db51b6f96513','嘉禾舟中','釋文珦','宋','宋诗','song-poetry','','[]','舟次寒城外，人家已閉門。',48,'全唐诗/poet.song.219000.json','["舟次寒城外，人家已閉門。", "蜃眠春浪息，鳥入暮煙昏。", "澤廣疑無地，車鳴忽有村。", "茲遊雖適興，終不似丘園。"]'),
('b10655e6-0192-46dd-8a09-35e0d43a9df5','姚江舟中','釋文珦','宋','宋诗','song-poetry','','[]','江潮遠入河，幾度此經過。',48,'全唐诗/poet.song.219000.json','["江潮遠入河，幾度此經過。", "浦溆漁船聚，泥塗蟹穴多。", "纏綿吳客恨，哀怨越人歌。", "一曲頭堪白，頻聞可奈何。"]'),
('78501c3c-c5f0-43b9-b8e2-b70d2553deaf','樓頭鐘','釋文珦','宋','宋诗','song-poetry','','[]','晨鐘喚日出，夕鐘號月升。',77,'全唐诗/poet.song.219000.json','["晨鐘喚日出，夕鐘號月升。", "兩曜如轆轤，遞轉不曾停。", "人生於其間，誰能駐頹齡。", "樓頭鐘聲催人入黄土，長生之學虛荒誕幻無可馮。", "君不見嬴政入海採靈藥，回舟翻作鮑魚腥。"]'),
('e04454e2-d01a-4452-aab7-d7c1d722a934','泊舟','釋文珦','宋','宋诗','song-poetry','','[]','泊舟青林傍，日入風色莫。',168,'全唐诗/poet.song.219000.json','["泊舟青林傍，日入風色莫。", "翩翩群鳥歸，各以類相聚。", "我生獨何爲，孤立寡良遇。", "落落天壤間，真如惠王瓠。", "苦吟復誰聽，直道遭時惡。", "齒豁眼已昏，鬒髮坐成素。", "躑躅中夜起，霑衣苦多露。", "仰視天一方，繁星不知數。", "故鄉何由返，年老忘歸路。", "良宵苦無悰，明朝又何處。", "餘生但迍邅，百念空回互。", "感激動悲歌，鄰舟還詬怒。", "吞聲入篷底，局促似罝兔。", "行役古所嘆，人生亦多誤。"]'),
('454ec080-bf97-4ec8-b148-40eeb57e7fa4','仙家','釋文珦','宋','宋诗','song-poetry','','[]','四面煙霞一徑苔，碧桃花際洞門開。',32,'全唐诗/poet.song.219000.json','["四面煙霞一徑苔，碧桃花際洞門開。", "椶冠道士向余說，時復有人騎鶴來。"]'),
('0ff2c68c-69c6-44f2-9ec0-2134b8ddfd48','棲雲樓','釋文珦','宋','宋诗','song-poetry','','[]','白雲自悠然，幽人此棲息。',48,'全唐诗/poet.song.219000.json','["白雲自悠然，幽人此棲息。", "去留果何心，變化了無迹。", "俗客不曾來，沙鷗盡相識。", "何處動吟情，漁村數聲笛。"]'),
('4f779cca-b28e-4544-915a-63167f0fefb4','雲棲','釋文珦','宋','宋诗','song-poetry','','[]','我頗愛雲散，雲不嫌我頑。',48,'全唐诗/poet.song.219000.json','["我頗愛雲散，雲不嫌我頑。", "兩心既莫逆，每事常相關。", "靜室雲守護，空門雲往還。", "雲棲良自嘉，雲與身俱閒。"]'),
('ae072bc8-4c12-42f6-aa90-b61e665ec406','題江湖偉觀','釋文珦','宋','宋诗','song-poetry','','[]','左右江湖仙聖宅，龍飛鳳舞帝王家。',64,'全唐诗/poet.song.219000.json','["左右江湖仙聖宅，龍飛鳳舞帝王家。", "樓臺高下隨山勢，渤澥微茫湧日華。", "漁浦風和翻柳影，官河春盡落桐花。", "錢唐佳麗今無比，回首中原望眼賒。"]'),
('e00bedee-9d38-45a2-be72-818154015622','郭文舉祠','釋文珦','宋','宋诗','song-poetry','','[]','封禺山水國，曾是郭文遊。',48,'全唐诗/poet.song.219000.json','["封禺山水國，曾是郭文遊。", "列岫開新障，平川合衆流。", "丹青遺像在，松竹古祠秋。", "雖不逢堯禪，高風似許由。"]'),
('3b057369-d8d3-4369-a2c0-873c30267a29','重題郭文廟','釋文珦','宋','宋诗','song-poetry','','[]','嘗聞郭文舉，雅志在山林。',168,'全唐诗/poet.song.219000.json','["嘗聞郭文舉，雅志在山林。", "內以道自勝，不爲外物淫。", "人皆戀妻子，先生獨幽尋。", "人皆厭輕肥，先生無衣衾。", "人皆覬榮達，先生甘陸沉。", "世道既難言，先生示如瘖。", "懷寶終不售，熟識先生心。", "身與豺虎鄰，豺虎不敢侵。", "溫嶠何所聞，比公於展禽。", "更歷數百年，尚爲人所欽。", "或以神事公，置廟青山岑。", "歲時致牲醴，諒非公所歆。", "我來吊遺像，顧瞻一長吟。", "公儻察余衷，泠然御風臨。"]'),
('d45f2e95-b729-42e6-aca1-1ae7879e276b','曹娥廟','釋文珦','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','墳柏起陰風，舟行謁祭同。',48,'全唐诗/poet.song.219000.json','["墳柏起陰風，舟行謁祭同。", "鄉人今變俗，孝女舊沈躬。", "名寄長江遠，神還野廟空。", "尚餘黄絹字，零落斷碑中。"]'),
('b011d3dc-0b3b-4354-be59-f9e931a8131d','東嘉風土','釋文珦','宋','宋诗','song-poetry','','[]','山水知名舊永嘉，謝池千古湛清華。',64,'全唐诗/poet.song.219000.json','["山水知名舊永嘉，謝池千古湛清華。", "四郊風土宜柑樹，百里官河盡藕花。", "鴉鷺共棲江面石，漁商分泊渡頭沙。", "他年若向中川住，管定清遊少在家。"]'),
('8250e922-025c-43c5-9636-1cf762c7bb40','溪路','釋文珦','宋','宋诗','song-poetry','','[]','溪路六七里，茅茨三兩家。',48,'全唐诗/poet.song.219000.json','["溪路六七里，茅茨三兩家。", "斷崖懸石髓，古樹有松花。", "絕壑無人處，看雲到日斜。", "過山幽更甚，時復見樵車。"]'),
('73d5f373-bf76-4fbf-a20a-c2417ff18113','江路','釋文珦','宋','宋诗','song-poetry','','[]','江路何迢遠，乘舟亦自勞。',48,'全唐诗/poet.song.219000.json','["江路何迢遠，乘舟亦自勞。", "篷疎霜氣入，港狹水聲高。", "旅食無兼味，行裝祇縕袍。", "楫師催客起，初日上林皋。"]'),
('d10060e2-baa7-4ef6-b083-3cc0c9a293b1','悠悠荒路行','釋文珦','宋','宋诗','song-poetry','','[]','悠悠荒路間，能使客心惻。',168,'全唐诗/poet.song.219000.json','["悠悠荒路間，能使客心惻。", "千里無居人，茫茫但蓁棘。", "東西失蹊徑，南北迷阡陌。", "室廬盡空虛，墳壟皆發掘。", "日行畏虎狼，夜卧憂盜賊。", "今日狐兔場，當年帝王國。", "興亡故常理，何爲至斯極。", "淚下如流泉，潸潸自沾臆。", "否泰恒相代，乘時聖明出。", "垂衣成至治，天下定于一。", "四夷奉琛贄，萬國尊王室。", "禮樂復興行，流離再安集。", "鷄犬聲相聞，田疇富黍稷。", "徵以鴻鴈詩，於焉在中澤。"]'),
('9115cf9b-5273-46d1-b510-32fd764f3384','池上','釋文珦','宋','宋诗','song-poetry','','[]','曉來池上獨凭闌，無限春愁欲訴難。',32,'全唐诗/poet.song.219000.json','["曉來池上獨凭闌，無限春愁欲訴難。", "最是閏年時候別，楝花開盡尚清寒。"]'),
('da9ee935-b164-42e9-a289-00737b4ad3e9','原上曲','釋文珦','宋','宋诗','song-poetry','','[]','新塚嵯峨古塚平，塚頭澆酒又清明。',32,'全唐诗/poet.song.219000.json','["新塚嵯峨古塚平，塚頭澆酒又清明。", "酒痕不到重泉下，榆柳青青春鳥鳴。"]'),
('55d4441d-e046-4fde-9f8b-9d4d9b151a6d','山林  其一','釋文珦','宋','宋诗','song-poetry','','[]','塵世有衰榮，山林何損益。',48,'全唐诗/poet.song.219000.json','["塵世有衰榮，山林何損益。", "一身常晏如，于以養精魄。", "渴則飲清泉，饑則煮白石。", "自愛同閒雲，散誕無留迹。"]'),
('2a19d4f9-7d78-4938-b192-943dc9794a4d','山林  其二','釋文珦','宋','宋诗','song-poetry','','[]','山林與朝市，自昔分兩歧。',48,'全唐诗/poet.song.219000.json','["山林與朝市，自昔分兩歧。", "勢利幾傾奪，道人猶未知。", "唯愛八還經，展卷時讀之。", "是亦遮眼爾，不作文字癡。"]'),
('69411d37-e7fe-407d-9fd1-0822677d7a3a','山林  其三','釋文珦','宋','宋诗','song-poetry','','[]','舊無卓錐地，今者亦忘錐。',48,'全唐诗/poet.song.219000.json','["舊無卓錐地，今者亦忘錐。", "中心子無著，清浄如流離。", "野猿偶然來，問我何所爲。", "道我此意真，長嘯不相疑。"]'),
('94b4cfb8-5752-4b4a-8908-fc73917e1845','幽徑','釋文珦','宋','宋诗','song-poetry','','[]','幽徑任蓬蒿，衡門閉亦牢。',48,'全唐诗/poet.song.219000.json','["幽徑任蓬蒿，衡門閉亦牢。", "駒寒宜在谷，鶴倦懶鳴皋。", "老樹根流髓，重崖石長膏。", "樵童更閒靜，聽我讀離騷。"]'),
('720e5b20-2929-4fe7-aaaa-203142f03ca1','荒徑','釋文珦','宋','宋诗','song-poetry','','[]','荒徑入林微，蓬廬客到稀。',48,'全唐诗/poet.song.219000.json','["荒徑入林微，蓬廬客到稀。", "苔痕侵藥裹，山色冷吟衣。", "蚯蚓耕泥起，蜻蜓點水飛。", "坐來忘萬事，靜看宿雲歸。"]'),
('71f251a3-6293-4574-841d-70b50756b8aa','遠塵','釋文珦','宋','宋诗','song-poetry','','[]','忘名忘利人，傲岸孰能馴。',48,'全唐诗/poet.song.219000.json','["忘名忘利人，傲岸孰能馴。", "老去身猶健，閒中樂最真。", "潔修松體貌，清勁竹精神。", "日夕常相對，無緣更有塵。"]'),
('63069904-a110-4d18-b222-4aa00a402d10','潜山風土','釋文珦','宋','宋诗','song-poetry','','[]','潜爲杭古邑，漢郡屬丹陽。',48,'全唐诗/poet.song.219000.json','["潜爲杭古邑，漢郡屬丹陽。", "俗本崇勤儉，民終不寇攘。", "屋頭猶種木，田岸亦栽桑。", "頗與豳風類，吾心愛此鄉。"]'),
('01d8eec2-c30c-4af3-b3a0-4946e5977187','華陰有山行','釋文珦','宋','宋诗','song-poetry','','[]','華陰有山，上與天齊。',140,'全唐诗/poet.song.219000.json','["華陰有山，上與天齊。", "仰望莫及，雲煙朝隮。", "人迹罕到，群仙所棲。", "餐食沆瀣，乘駕虹霓。", "下視萬國，大倉一稊。", "我欲從之，恨無飛梯。", "何當遭逢，授以刀圭。", "俾我服餌，妙合天倪。", "髮白而黑，齒落而兒。", "身復少彊，靡資提携。", "一息萬里，匪拘東西。", "蓬瀛閬苑，嬉遊忻忻。", "納交松喬，誓無乖暌。", "得玄秘道，終然弗迷。"]'),
('5599d65d-4fa3-4744-a4f3-a7275322ffa6','天台山','釋文珦','宋','宋诗','song-poetry','','[]','天台仙聖宅，隔斷世間塵。',48,'全唐诗/poet.song.219000.json','["天台仙聖宅，隔斷世間塵。", "春夏長留雪，峰巒半入雲。", "溪行多病淑，樵徑少逢人。", "欲覓誅茅地，同流儻見分。"]'),
('cdd83ae9-ada1-43a5-9d57-b181c4408f73','岞崿山','釋文珦','宋','宋诗','song-poetry','','[]','岞崿多奇觀，人疑是假山。',132,'全唐诗/poet.song.219000.json','["岞崿多奇觀，人疑是假山。", "松亭藏霧黑，苔壁上雲斑。", "棧閣凌空險，巖棲履石艱。", "鶴眠庭樹穩，僮汲井泉慳。", "鐘磬青冥上，香燈杳靄間。", "志圖曾舊覽，題詠未經刪。", "疊嶂森南面，雙溪轉北灣。", "飛橋攔水斷，古邑带烟閒。", "猿嘯穿林遠，樵聲過嶺巒。", "客尋清梵至，僧背夕陽還。", "我亦頻來此，柴門不要關。"]'),
('a86b1160-b1ab-4c74-b907-c57ecdbc4842','仗錫山','釋文珦','宋','宋诗','song-poetry','','[]','高寒雪竇頂，仗錫更幽深。',48,'全唐诗/poet.song.219000.json','["高寒雪竇頂，仗錫更幽深。", "瀑布幾年雪，清猨終日吟。", "四窗標郡目，片石表山心。", "太白誅茅後，靈蹤尚可尋。"]'),
('4a5ff8e7-ca73-45f4-8f38-ed5f8c94d46f','空山  其一','釋文珦','宋','宋诗','song-poetry','','[]','深山一敝廬，今是幾年居。',48,'全唐诗/poet.song.219000.json','["深山一敝廬，今是幾年居。", "舉世皆嫌拙，吾心獨有餘。", "寒苴珍芥醤，嘉核愛梅諸。", "樵父時同賦，多將槁葉書。"]'),
('d75ce3f5-4168-4dfc-bf62-3a2496344455','空山  其二','釋文珦','宋','宋诗','song-poetry','','[]','空山一草廬，住來忘歲月。',48,'全唐诗/poet.song.219000.json','["空山一草廬，住來忘歲月。", "孤身同夢幻，兩鬢任霜雪。", "紛紛蠻觸爭，頗若大瑣屑。", "予雖知其然，不欲有分別。"]'),
('42d300f3-762a-4b7c-80ce-9097d0bbcf22','山深  其一','釋文珦','宋','宋诗','song-poetry','','[]','山深懶開門，忍饑卧風雪。',48,'全唐诗/poet.song.219000.json','["山深懶開門，忍饑卧風雪。", "忽聞簷外聲，知有崖松折。", "水邊盤陀石，中夜亦凍裂。", "西頂幽人來，清曉爲予說。"]'),
('cfbbffb6-e22c-43cd-9ba5-e0674cfa4cdc','山深  其二','釋文珦','宋','宋诗','song-poetry','','[]','山深寒易得，九月已蕭然。',48,'全唐诗/poet.song.219000.json','["山深寒易得，九月已蕭然。", "况是衰遲者，非同少壯年。", "玄裘如艾絮，禪榻藉蒲氈。", "童子燒枯葉，先教閟暖煙。"]'),
('1b1513b4-141d-4f87-882a-a5ff5b8a676d','仗錫山中','釋文珦','宋','宋诗','song-poetry','','[]','雨過春山薇蕨長，曉隨樵子穿雲上。',32,'全唐诗/poet.song.219000.json','["雨過春山薇蕨長，曉隨樵子穿雲上。", "貪看巖頭瀑布飛，坐來忘却青藜杖。"]'),
('84cffc5e-eaca-4369-becc-cfbf84f79c2e','山中  其一','釋文珦','宋','宋诗','song-poetry','','[]','世獨休分渭與涇，鴻飛祇合自冥冥。',64,'全唐诗/poet.song.219000.json','["世獨休分渭與涇，鴻飛祇合自冥冥。", "也知鬢髮變霜雪，終愛山光來戶庭。", "蟇傍花陰窺蛺蝶，蜾歸筠管祝螟蛉。", "從今萬事都拋棄，盡讀香山一藏經。"]'),
('3d42ef35-9cf3-4f57-b36c-6a79f62544e1','山中  其二','釋文珦','宋','宋诗','song-poetry','','[]','每說遠公棲隠處，亂雲□歌石難通。',32,'全唐诗/poet.song.219000.json','["每說遠公棲隠處，亂雲□歌石難通。", "不是樵夫相指引，無雲得到此山中。"]'),
('ad59674f-0edd-4192-bbf9-753fe1258b8e','山中吟  其一','釋文珦','宋','宋诗','song-poetry','','[]','偶爲山中遊，遂作山中住。',120,'全唐诗/poet.song.219000.json','["偶爲山中遊，遂作山中住。", "猿鶴盡相忘，不記山前路。", "架有古仙書，立言談信去。", "往往賾其玄，頗有會心處。", "乃知筌蹄作，意本在魚兔。", "觀象既得之，自可略章句。", "童豎難與言，趺坐入禪度。", "萬事靜中忘，不省白日莫。", "野雲忽飛來，宿我簷間樹。", "知我無所著，飄然又飛去。"]'),
('9818bcd9-f465-4200-94a5-7b82cd792310','山中吟  其二','釋文珦','宋','宋诗','song-poetry','','[]','自爲山中人，不厭山中居。',24,'全唐诗/poet.song.219000.json','["自爲山中人，不厭山中居。", "雲西最高峰，秀出如芙蕖。"]'),
('84ac3182-88ca-461d-a87e-51ae54e1e664','山中吟  其三','釋文珦','宋','宋诗','song-poetry','','[]','山房更近仙翁井，汲水僧歸秋夜永。',32,'全唐诗/poet.song.219000.json','["山房更近仙翁井，汲水僧歸秋夜永。", "石上行吟萬境空，白猨叫在青松頂。"]'),
('a161d7fe-d943-4405-93f2-eeca3f3e2a61','山中吟  其四','釋文珦','宋','宋诗','song-poetry','','[]','適俗豈吾志，歸山存杖藜。',48,'全唐诗/poet.song.219000.json','["適俗豈吾志，歸山存杖藜。", "漁樵日來往，巖崖恣攀躋。", "惜竹改新術，滋蘭因故畦。", "忘機舊猿鶴，偏近座邊栖。"]'),
('3c952649-2a5c-4070-8941-21ed170672dd','山中吟  其五','釋文珦','宋','宋诗','song-poetry','','[]','自爲山中歸，屢見歲華易。',48,'全唐诗/poet.song.219000.json','["自爲山中歸，屢見歲華易。", "不問眉間黄，唯觀鼻端白。", "水石盡成趣，漁樵或爭席。", "塵世未歸人，營營復何益。"]'),
('75f0ba3d-b678-4fc2-8568-11e726e6fcb1','山中吟  其六','釋文珦','宋','宋诗','song-poetry','','[]','受性不分拏，處身常落魄。',120,'全唐诗/poet.song.219000.json','["受性不分拏，處身常落魄。", "難以事王侯，唯堪友猨鶴。", "遂爾辭國都，終然住林壑。", "渴則飲澗谿，饑則茹薇藿。", "煙霞水石間，自得無窮樂。", "所歸在一死，天地爲棺槨。", "棄埋任從他，曾不加計度。", "烏鳶與螻蟻，於吾無厚薄。", "清泰藕華池，深知可棲託。", "念茲常在茲，但觀西日落。"]'),
('5f4062a1-c20a-49c4-a680-030012a3e1e1','獨山吟','釋文珦','宋','宋诗','song-poetry','','[]','剡山千萬峰，維此善其獨。',36,'全唐诗/poet.song.219000.json','["剡山千萬峰，維此善其獨。", "山中有幽人，遯世心自足。", "永言養靈苗，勿混凡草木。"]'),
('59a9f14c-ab40-4f46-b023-ea01ad8c791a','丘壑美','釋文珦','宋','宋诗','song-poetry','','[]','謝公昔高卧，遠意在蒼生。',48,'全唐诗/poet.song.219000.json','["謝公昔高卧，遠意在蒼生。", "方據要路津，中孚賤浮名。", "出處本一致，窮達無異營。", "秋房斯人徒，見此丘壑情。"]'),
('89237168-8b8f-477b-a8ea-021a82b37109','盤谷','釋文珦','宋','宋诗','song-poetry','','[]','盤谷住來深，餘生任陸沈。',48,'全唐诗/poet.song.219000.json','["盤谷住來深，餘生任陸沈。", "自知塵外趣，消盡世間心。", "林靄飄成畫，風泉寫入琴。", "清猨亦可愛，旦莫發長吟。"]'),
('8281a1e3-9ff5-482e-9bfd-e5b4b9a4126c','邃谷','釋文珦','宋','宋诗','song-poetry','','[]','邃谷居來久，寥寥絕衆喧。',48,'全唐诗/poet.song.219000.json','["邃谷居來久，寥寥絕衆喧。", "雲深通藥徑，草長失柴門。", "靜愛寒山色，閒尋野水源。", "清虛乃吾事，不與俗人言。"]'),
('ce97c948-1f21-4763-b2aa-f3ca47aa92fc','幽谷','釋文珦','宋','宋诗','song-poetry','','[]','幽谷寒偏早，初秋御裌衣。',48,'全唐诗/poet.song.219000.json','["幽谷寒偏早，初秋御裌衣。", "山田禾未熟，徑樹葉先飛。", "澗淺樵夫涉，籬疎野鹿歸。", "不嫌生計薄，且與世人違。"]'),
('d4aaa56b-4927-4a13-a26a-e405f867fbde','谷中','釋文珦','宋','宋诗','song-poetry','','[]','谷口松泉相和鳴，山蹊詰曲少人登。',32,'全唐诗/poet.song.219000.json','["谷口松泉相和鳴，山蹊詰曲少人登。", "苦櫧一樹猿偷盡，懊殺庵居老病僧。"]'),
('4b8266d5-50a1-4671-b6c3-7f56b73e9315','江上  其一','釋文珦','宋','宋诗','song-poetry','','[]','煙生浦欲無，日莫潮初落。',24,'全唐诗/poet.song.219000.json','["煙生浦欲無，日莫潮初落。", "客帆何處來，又近垂楊泊。"]'),
('19bb96b6-bf4b-43d5-9eba-12c41bbd74a0','江上  其二','釋文珦','宋','宋诗','song-poetry','','[]','無柰春芳損客心，每於江上獨行吟。',32,'全唐诗/poet.song.219000.json','["無柰春芳損客心，每於江上獨行吟。", "朝朝莫莫寒潮水，不似歸愁一度深。"]'),
('b646e34e-dad4-4a23-ae6f-7b7b633275a1','溪上','釋文珦','宋','宋诗','song-poetry','','[]','散策清溪岸，茅簷事事幽。',48,'全唐诗/poet.song.219000.json','["散策清溪岸，茅簷事事幽。", "燕巢春始壘，蛛網雨來收。", "翁媼能留客，兒童不識愁。", "興長歸徑晚，回首問羣鷗。"]'),
('4f644e57-7385-47f5-9953-41347b498bd3','溪邊','釋文珦','宋','宋诗','song-poetry','','[]','溪邊得微徑，陟險窮層巔。',60,'全唐诗/poet.song.219000.json','["溪邊得微徑，陟險窮層巔。", "上有巢居人，志隠忘歲年。", "心靜語言寡，道在精神全。", "終身願相依，媿我無宿緣。", "明朝下山去，悵望空雲煙。"]'),
('f629c184-c82a-4183-9914-02f34c0bd47e','雪竇山','釋文珦','宋','宋诗','song-poetry','','[]','寺在諸峰頂，寥寥遠世紛。',48,'全唐诗/poet.song.219000.json','["寺在諸峰頂，寥寥遠世紛。", "巖飛千丈雪，門掩萬重雲。", "地冷春疑晚，松深日易曛。", "孤猨清叫月，僧向定中聞。"]'),
('48b8c467-b0b6-485b-94e8-805374e8be13','春谷','釋文珦','宋','宋诗','song-poetry','','[]','春谷行難盡，鷄聲忽一家。',48,'全唐诗/poet.song.219000.json','["春谷行難盡，鷄聲忽一家。", "溪流隨雨漲，崖樹受風斜。", "竹地偏生菌，桐陰正養茶。", "老翁年八十，不識有紛華。"]'),
('cd943eff-0829-4ad4-8c93-f5bc3da4c709','薔薇洞','釋文珦','宋','宋诗','song-poetry','','[]','不知建業薔薇樹，何似淮淝草木立。',32,'全唐诗/poet.song.219000.json','["不知建業薔薇樹，何似淮淝草木立。", "因入謫仙詩句裏，等閑隨處得虛名。"]'),
('a5160535-c7df-4186-80df-b07b99925c1c','蘭谷','釋文珦','宋','宋诗','song-poetry','','[]','猗猗谷中蘭，青青飽香露。',24,'全唐诗/poet.song.219000.json','["猗猗谷中蘭，青青飽香露。", "爲語樵牧兒，莫采出山去。"]'),
('a89cc975-02f0-48fe-909d-e910f70f9ba5','題鷦鷯巢林行','釋文珦','宋','宋诗','song-poetry','','[]','鷦鷯巢中林，所擇唯一枝。',120,'全唐诗/poet.song.219000.json','["鷦鷯巢中林，所擇唯一枝。", "俛啄草間粒，自可長無饑。", "絕意於翺翔，其樂誠在茲。", "挾之上空虛，高風亦奚爲。", "體微力難任，飄飄竟何歸。", "窮達懸於天，賦予常不齊。", "君子識其分，小大隨所施。", "狂夫每爭先，虛騁不知疲。", "以之致高位，未免多瑕玼。", "靜退以爲德，此理良可推。"]'),
('91c2a132-24d5-4fb3-84bb-ec9e7288674e','竹間吟','釋文珦','宋','宋诗','song-poetry','','[]','維昔晉唐人，其心多愛竹。',72,'全唐诗/poet.song.219000.json','["維昔晉唐人，其心多愛竹。", "七賢子猷徒，往駕已不復。", "惓惓思此君，鉏雲種青玉。", "勁節何亭亭，清風常穆穆。", "質美而貌閒，對之良不俗。", "遂老於其間，疇能賦淇奧。"]'),
('5876495a-381e-4102-958b-9e994850b04c','竹邊','釋文珦','宋','宋诗','song-poetry','','[]','野性何曾計此身，老來方覺負初心。',32,'全唐诗/poet.song.219000.json','["野性何曾計此身，老來方覺負初心。", "故山無地堪栽竹，猶傍人家看竹林。"]'),
('07c79bc6-ff28-4cc6-aded-5d35ea1208dc','鳳仙花','釋文珦','宋','宋诗','song-poetry','','[]','何年鳳背古仙人，草木之中自化身。',32,'全唐诗/poet.song.219000.json','["何年鳳背古仙人，草木之中自化身。", "丹袂翠翹秋色裏，猶資沆瀣養精神。"]'),
('c3440696-6ef6-4b33-ac98-454f137e3d3b','白湛淵書來命賦綠陰','釋文珦','宋','宋诗','song-poetry','','[]','化紅爲浄綠，圃樹已成陰。',48,'全唐诗/poet.song.219000.json','["化紅爲浄綠，圃樹已成陰。", "俯映澄淵水，清如靜者心。", "華滋深几席，餘潤滴衣襟。", "衆鳥猶知愛，皎皎遺好音。"]'),
('92a70cbb-af2f-4ab6-974b-118fcbbaee34','黄葵花','釋文珦','宋','宋诗','song-poetry','','[]','一入長門只淡妝，秋衣猶是舊宮黄。',32,'全唐诗/poet.song.219000.json','["一入長門只淡妝，秋衣猶是舊宮黄。", "到頭不信君恩斷，日日傾心向太陽。"]'),
('279c07cf-381f-40cd-90cc-2fc7ece5b202','和林靜學雙蘭','釋文珦','宋','宋诗','song-poetry','','[]','一本兩花新，重滋舊畹春。',48,'全唐诗/poet.song.219000.json','["一本兩花新，重滋舊畹春。", "難教入凡夢，唯共保天真。", "沮溺終稱隠，夷齊又得仁。", "臨風如欲笑，笑著獨醒人。"]'),
('02b7bbcc-c5b6-4cb5-acf8-73b5a93b0eb0','聽松','釋文珦','宋','宋诗','song-poetry','','[]','別駕公事閒，翦棘開三徑。',48,'全唐诗/poet.song.219000.json','["別駕公事閒，翦棘開三徑。", "天風引長松，蕭蕭滿清聽。", "坐石琴意真，憑闌醉魂醒。", "亦使山中人，悠然動歸興。"]'),
('b7493a41-3392-4051-baaf-cc75c9d18766','柳言','釋文珦','宋','宋诗','song-poetry','','[]','彭澤門前閒草木，絲絲那向路傍生。',32,'全唐诗/poet.song.219000.json','["彭澤門前閒草木，絲絲那向路傍生。", "便教繫得春風住，也與時人管送迎。"]'),
('5b41d825-e9dc-4f64-906a-3f5ea3d30de6','采蘭吟','釋文珦','宋','宋诗','song-poetry','','[]','楚芳有幽姿，采采倏盈把。',48,'全唐诗/poet.song.219000.json','["楚芳有幽姿，采采倏盈把。", "馨香滿襟袖，欲寄同心者。", "道遠不可求，余懷爲誰寫。", "佩服林下遊，自愛逸而野。"]'),
('c784c683-83e3-41fe-89f2-b22e5714431a','朝采卷耳行','釋文珦','宋','宋诗','song-poetry','','[]','朝采卷耳，于陵于岡。',100,'全唐诗/poet.song.219000.json','["朝采卷耳，于陵于岡。", "取葉存根，以備酒漿。", "嗟我懷人，在彼遐方。", "閔其勤勞，寤寐弗忘。", "念得送我，置爾之傍。", "所願莫遂，徘徊彷徨。", "鳳遊四海，亦思其凰。", "毋以道遠，而易中腸。", "好鳥和鳴，其飛頡頏。", "感物增憂，泣涕沾裳。"]'),
('70c4a719-52db-4f44-9851-71ae50d48ad1','鑒上人所居金竹青琅玕一莖','釋文珦','宋','宋诗','song-poetry','','[]','瀟灑非凡種，虛空是本心。',48,'全唐诗/poet.song.219000.json','["瀟灑非凡種，虛空是本心。", "纔生一青玉，不數萬黄金。", "月寫孤鸞影，風傳丹鳳音。", "從茲護根本，會見別成林。"]'),
('b27cceb2-64f6-4f8b-acb5-41a3afc2716e','清谿鷺','釋文珦','宋','宋诗','song-poetry','','[]','清谿雙白鷺，其羽可爲儀。',72,'全唐诗/poet.song.219000.json','["清谿雙白鷺，其羽可爲儀。", "潔白廼如此，那肯居洿池。", "志士慎厥身，濁世難縶羈。", "鐘鼎或愆義，寧賤而長饑。", "貪夫昧所從，得養非攸宜。", "猶鴟啄腐鼠，此鳥能笑之。"]'),
('51c03e1f-2de6-4787-8331-6cbf5efe0ba8','枯魚過河泣','釋文珦','宋','宋诗','song-poetry','','[]','爲魚當深潜，深潜身可肥。',84,'全唐诗/poet.song.219000.json','["爲魚當深潜，深潜身可肥。", "勿以風濤便，踊躍圖奮飛。", "風濤或遽止，處陸胡能歸。", "汝骸既已腊，泣河計還非。", "生榮與死辱，二者相因依。", "富貴而亢極，後患亦豈微。", "功成泛五湖，鴟夷獨知幾。"]'),
('2533c786-848b-4a5d-89c9-b5c9ad4b662f','翩翩春燕行','釋文珦','宋','宋诗','song-poetry','','[]','翩翩春燕，厥有常心。',100,'全唐诗/poet.song.219000.json','["翩翩春燕，厥有常心。", "來以春陽，去以秋陰。", "不爽于社，爲時所欽。", "玄衣濟濟，美度愔愔。", "差池其羽，下上其音。", "如服仁義，如鼓瑟琴。", "繕壘杏梁，銜泥柳林。", "宮房孔式，非僭非淫。", "居處齊一，淑惠且任。", "實生商后，匪曰凡禽。"]'),
('ec9f185c-4e3c-44e0-ba9e-78baac300979','雉朝飛','釋文珦','宋','宋诗','song-poetry','','[]','春日遲遲，有雉朝飛。',76,'全唐诗/poet.song.219000.json','["春日遲遲，有雉朝飛。", "一雄自得，群雌相隨。", "自西自東，飲啄不違。", "牧犢採薪，見而感之。", "我生徒爲人，七十反無妻。", "嘗聞二南世，天下無鰥嫠。", "萬物得其所，婚姻皆以時。"]'),
('f8ccd103-3155-46c2-93cf-441f485a3c3c','山樂官','釋文珦','宋','宋诗','song-poetry','','[]','嗚呼有鳥山樂官，鳴聲宛轉空林間。',80,'全唐诗/poet.song.219000.json','["嗚呼有鳥山樂官，鳴聲宛轉空林間。", "恐是執簧秉翟者，遺形變化之遊魂。", "生兮不遇聖明世，千載而下猶煩冤。", "遺之好音不爾聽，何如卷舌且勿言。", "簫韶九成集嘉瑞，當與威鳳同飛鶱。"]'),
('5723d622-e3d6-4ca4-925e-4a00b5f6a2a1','茅茨  其一','釋文珦','宋','宋诗','song-poetry','','[]','千重青嶂底，坐卧一茅茨。',48,'全唐诗/poet.song.219000.json','["千重青嶂底，坐卧一茅茨。", "棲息今成樂，興亡總不知。", "林居獨脚鬼，壁畫九頭龜。", "自是山林樣，休嫌欠入時。"]'),
('2cebf39a-bafb-4027-ba35-a006023e1335','茅茨  其二','釋文珦','宋','宋诗','song-poetry','','[]','茅茨住得安，何必府潭潭。',48,'全唐诗/poet.song.219000.json','["茅茨住得安，何必府潭潭。", "省禍由知足，防心在不貪。", "衣荷同纊暖，食蘗比飴甘。", "清苦人休訝，山翁已慣諳。"]'),
('595666fe-8ecd-4c0e-ac21-6c9028c0ef8e','蕭然','釋文珦','宋','宋诗','song-poetry','','[]','蕭然一茅茨，遠在青山郭。',48,'全唐诗/poet.song.219000.json','["蕭然一茅茨，遠在青山郭。", "歲晚倦行遊，來茲解纓絡。", "功名人莫笑，吾志在丘壑。", "試問伏轅駒，何如九霄鶴。"]'),
('6004c383-63bf-467e-8695-5fc92f54a790','端居','釋文珦','宋','宋诗','song-poetry','','[]','爲得近樵漁，閒尋此地居。',48,'全唐诗/poet.song.219000.json','["爲得近樵漁，閒尋此地居。", "省交長閉戶，耽靜欲焚書。", "自愛心情澹，人嫌禮貌疎。", "徑從荒草沒，衰懶不能除。"]'),
('9082ad33-15ba-458f-a32a-faedb357218f','林和靖孤山舊隠','釋文珦','宋','宋诗','song-poetry','','[]','抱璞肯自剖，藏之在深櫝。',96,'全唐诗/poet.song.219000.json','["抱璞肯自剖，藏之在深櫝。", "嗟彼荆山人，不能衛其足。", "生先有良貴，那愛分□祿。", "閒居五十年，祗著山人服。", "華衮有何好，此服安且燠。", "童鶴亦清真，梅邊伴幽獨。", "身後無子孫，高風許誰續。", "疎澹水邊螢，飛來照吟屋。"]'),
('c8075cd0-1fc7-4409-b6ee-4c886dd14908','閒門','釋文珦','宋','宋诗','song-poetry','','[]','閒門絕塵鞅，松栝皆肺肺。',48,'全唐诗/poet.song.219000.json','["閒門絕塵鞅，松栝皆肺肺。", "言忘見道真，靜極聞天籟。", "野菜寧加糝，山衣或無带。", "此心苟不欺，貧賤亦何害。"]'),
('b09a3a8b-670f-44a0-bdba-fec9d024720e','空廬','釋文珦','宋','宋诗','song-poetry','','[]','荒徑草青青，空廬未始扃。',48,'全唐诗/poet.song.219000.json','["荒徑草青青，空廬未始扃。", "好山皆在目，無事可勞形。", "已信虛空講，何妨樹石聽。", "悠然朝復莫，真道自相冥。"]'),
('50765964-411a-41d3-86c8-a7f65129135b','幽棲','釋文珦','宋','宋诗','song-poetry','','[]','幽棲絕世紛，足以養心君。',48,'全唐诗/poet.song.219000.json','["幽棲絕世紛，足以養心君。", "是草皆爲藥，無山不出雲。", "房空留鹿伴，果熟與猿分。", "信口成詩句，長謠到夕曛。"]'),
('fa2326bb-f0e7-43ef-889f-a701bc441d60','棲遲','釋文珦','宋','宋诗','song-poetry','','[]','棲遲嚴壑間，所尚不同俗。',48,'全唐诗/poet.song.219000.json','["棲遲嚴壑間，所尚不同俗。", "窗下列芳蘭，門前藝修竹。", "崖屋夏中寒，石田秋後熟。", "委質於自然，陶然意常足。"]'),
('9552ee0e-879d-4152-b781-42a72c643675','雪屋','釋文珦','宋','宋诗','song-poetry','','[]','風落曉空寒，茅簷一尺寬。',48,'全唐诗/poet.song.219000.json','["風落曉空寒，茅簷一尺寬。", "亂聲依竹密，斜片打窗殘。", "絕穀炊煙斷，開門去路難。", "枕書眠白晝，人說似袁安。"]'),
('a55f8645-f41c-45e6-a81a-87efab77fb37','田家','釋文珦','宋','宋诗','song-poetry','','[]','田家翁媼頗自適，翁解耕耘婦能織。',128,'全唐诗/poet.song.219000.json','["田家翁媼頗自適，翁解耕耘婦能織。", "官中租賦無稽違，所養牛羊亦蕃息。", "歲時力作不徒勞，桑柘滿園禾黍高。", "皆因勤儉百事足，老身不復愁逋逃。", "兒女長成畢婚嫁，祇在東鄰與西舍。", "甕頭時復有新篘，親戚團欒樂情話。", "神前祭賽宜豊腴，家中衣飯隨精粗。", "縣吏下鄉雞犬盡，但願官府無追呼。"]'),
('28ca494f-ff97-4b9f-92a1-2b619b3ec98b','田家謠','釋文珦','宋','宋诗','song-poetry','','[]','東坡粟已黄，西疇稻堪穫。',96,'全唐诗/poet.song.219000.json','["東坡粟已黄，西疇稻堪穫。", "農家慶豐年，茅茨舉盃酌。", "復喜官家用賢相，奮發天威去元惡。", "詔書寬徭榜村路，悍吏不來鷄犬樂。", "兒童牧牛捨牛舞，翁媼賽神聽神語。", "飲則食兮福鄉土，五日一風十日雨，萬歲千秋戴明主。"]'),
('d1df9a88-cad7-4801-bd4d-815bd9a806c9','山中田舍','釋文珦','宋','宋诗','song-poetry','','[]','茅簷共翠微，井臼亦相依。',48,'全唐诗/poet.song.219000.json','["茅簷共翠微，井臼亦相依。", "衣望桑麻熟，糧兼芋栗肥。", "山田秋賦少，村樂醉人歸。", "不識封侯事，王城相到稀。"]'),
('74a2a541-786d-41cb-85f8-cb6c2d0db9b8','靜處','釋文珦','宋','宋诗','song-poetry','','[]','常於靜處著閒身，別是清虛冷澹人。',64,'全唐诗/poet.song.219000.json','["常於靜處著閒身，別是清虛冷澹人。", "禪裏斷除千種法，吟中消受一生貧。", "聲名豈必存編簡，林壑從來有隠淪。", "雲月溪山無限景，對余一一意皆真。"]'),
('23907b42-1b01-4712-b581-b855a2586f70','松竹間','釋文珦','宋','宋诗','song-poetry','','[]','瘦竹老松間，閒房僅容膝。',48,'全唐诗/poet.song.219000.json','["瘦竹老松間，閒房僅容膝。", "棲遲非一朝，謝遣用三術。", "泉落雙澗清，雲消衆山出。", "誰能强予遷，愛此成痼疾。"]'),
('254a301d-306c-4444-b1f5-77f70509698b','桂堂吟','釋文珦','宋','宋诗','song-poetry','','[]','團團老桂陰，縹緲見雲棟。',48,'全唐诗/poet.song.219000.json','["團團老桂陰，縹緲見雲棟。", "西風吹古薌，熏破幽人夢。", "夢破葉間清露滴，明月滿空秋一色，便跨銀蟾上穹碧。"]'),
('e99f455c-d96b-4160-9e6d-1e6b3d71e0a9','祕書山中草堂','釋文珦','宋','宋诗','song-poetry','','[]','謝客開山興，深居寄草堂。',228,'全唐诗/poet.song.219000.json','["謝客開山興，深居寄草堂。", "曲闌憑野色，虛牖敞晴光。", "路轉青林合，泉流碧澗長。", "群巒分向背，平楚接微茫。", "蘭茝含幽潔，松筠傲雪霜。", "玄猨啼夜月，青鶴舞朝陽。", "地僻煙霞古，雲深草樹凉。", "藤梢藏釣石，桂子落琴床。", "爲識禽魚性，終辭鴛鷺行。", "真曾脫穎出，祇作善刀藏。", "不愛燒金術，唯留煮石方。", "賦詩閒點筆，勘易靜焚香。", "釀酒應浮白，收茶自過黄。", "秋來看㓢竹，春盡課劙桑。", "水暖分魚種，崖寒取蜜房。", "人高徵士節，天動少微芒。", "道在名難隠，身閒樂叵量。", "更知齊指馬，誠足傲羲皇。", "蕭散氛埃表，高風不可忘。"]'),
('f1f00036-1559-444f-9f59-206c84c0679d','松竹堂','釋文珦','宋','宋诗','song-poetry','','[]','玉立諸君子，蒼髯十八公。',48,'全唐诗/poet.song.219000.json','["玉立諸君子，蒼髯十八公。", "有此歲寒質，胡能媚東風。", "勿墮長房術，勿受秦皇封。", "深期老此堂，長與幽人同。"]'),
('12bfd0f1-64ab-4e80-9175-ebc9a5048934','松屋','釋文珦','宋','宋诗','song-poetry','','[]','試問青松若箇栽，僧門祇向樹邊開。',64,'全唐诗/poet.song.219000.json','["試問青松若箇栽，僧門祇向樹邊開。", "月明定有仙人過，露滴頻聞野鶴回。", "千歲老根成虎魄，幾尋枯幹裹莓苔。", "住來自得清虛味，不管流光白髮催。"]'),
('35b0788b-80be-4930-bf03-ecda11c4125a','茅屋','釋文珦','宋','宋诗','song-poetry','','[]','道人不出山，偃卧一茅屋。',24,'全唐诗/poet.song.219000.json','["道人不出山，偃卧一茅屋。", "獨有南山雲，時到簷前宿。"]'),
('e670019c-45ad-434c-a005-069d65746035','竹居','釋文珦','宋','宋诗','song-poetry','','[]','簷外竹珊珊，空房住一間。',48,'全唐诗/poet.song.219000.json','["簷外竹珊珊，空房住一間。", "無人曾到此，老子有餘閒。", "土蝕銅壺缺，苔滋粉壁斑。", "於焉自成樂，遮莫笑癡頑。"]'),
('59909dac-3605-4299-805f-d18f0176fd09','農家','釋文珦','宋','宋诗','song-poetry','','[]','農家何所知，鄰里自相宜。',48,'全唐诗/poet.song.219000.json','["農家何所知，鄰里自相宜。", "草徑東風軟，茅簷春日遲。", "數鴉鳴禿樹，一犢卧荒陂。", "酒熟相留醉，於人不作期。"]'),
('3c4cd85e-5a11-4bc2-a5a2-18e318187aff','隠居二首  其一','釋文珦','宋','宋诗','song-poetry','','[]','流水何嘗有競，閒雲本亦無心。',28,'全唐诗/poet.song.219000.json','["流水何嘗有競，閒雲本亦無心。", "靜者不殊雲水，悠然自樂山林。"]'),
('16a49a09-3cea-4852-b143-83d850b0d5f4','隠居二首  其二','釋文珦','宋','宋诗','song-poetry','','[]','任術終當死術，爲仁必得稱仁。',28,'全唐诗/poet.song.219000.json','["任術終當死術，爲仁必得稱仁。", "比似榮華滅族，何如貧賤脩身。"]'),
('974987f3-4772-405a-8e46-0677fa10abee','客居多暇步過田家','釋文珦','宋','宋诗','song-poetry','','[]','客寄無生事，乘閒到水東。',48,'全唐诗/poet.song.219000.json','["客寄無生事，乘閒到水東。", "風和禽語樂，日暖土膏融。", "田父稱家有，行人自屢空。", "殷勤留我飯，憐我不爲農。"]'),
('20c788f9-a6b5-44bb-ab3e-4f91f085ffeb','訪山家','釋文珦','宋','宋诗','song-poetry','','[]','山翁居處僻，野屋蓋茅新。',48,'全唐诗/poet.song.219000.json','["山翁居處僻，野屋蓋茅新。", "自得煙霞趣，應無車馬塵。", "怪禽啼似鬼，古木變爲人。", "不是忘緣者，誰能與子親。"]'),
('b93bdea2-3966-4a0d-9bc3-72672eec8595','春曉尋山家','釋文珦','宋','宋诗','song-poetry','','[]','石澗寒流不盡，茅簷宿雨初晴。',28,'全唐诗/poet.song.219000.json','["石澗寒流不盡，茅簷宿雨初晴。", "幽客眠雲未起，四山鳥哢春聲。"]'),
('6ee439de-bc69-4658-84b1-b21b417aaad6','夏日過隠人湖居','釋文珦','宋','宋诗','song-poetry','','[]','軒窗臨水開，潔瑩如冰鏡。',48,'全唐诗/poet.song.219000.json','["軒窗臨水開，潔瑩如冰鏡。", "含風柳千絲，清暑荷萬柄。", "近結鷗鷺盟，遠寄江湖興。", "吾亦愛君廬，爲發滄浪詠。"]'),
('98eed1e4-fe0f-4252-b983-d4842630f7b6','宋飲冰晚過林居','釋文珦','宋','宋诗','song-poetry','','[]','山晚少人行，蕭蕭隕籜聲。',48,'全唐诗/poet.song.219000.json','["山晚少人行，蕭蕭隕籜聲。", "陽光沈樹杪，暝色起柴荆。", "過我論幽事，知君無宦情。", "虛名是何物，濁酒且須傾。"]'),
('e6ca51be-7180-47b1-9914-6c3b85431377','夜歸陋室','釋文珦','宋','宋诗','song-poetry','','[]','蕭蕭兩鬢如凝霜，險阻艱難曾備嘗。',80,'全唐诗/poet.song.219000.json','["蕭蕭兩鬢如凝霜，險阻艱難曾備嘗。", "少年氣節尚奇偉，老來事業成荒唐。", "盜賊紛紛安衽席，衰翁秋晚猶絺綌。", "明月皎皎星宿稀，夜靜入門徒四壁。", "四海知音今已矣，仰天太息悲風起。"]'),
('137f26cd-1d4a-4e97-8306-e748720acc62','江樓寫望  其一','釋文珦','宋','宋诗','song-poetry','','[]','危欄朝獨倚，千里望中閒。',48,'全唐诗/poet.song.219000.json','["危欄朝獨倚，千里望中閒。", "旭日穿層浪，明霞際斷山。", "京華襟带裏，于越有無間。", "鼓枻知誰子，長歌去不還。"]'),
('9d5ae4d1-ffbb-4420-9c93-23c9114cc13b','江樓寫望  其二','釋文珦','宋','宋诗','song-poetry','','[]','晨登江上樓，周覽竟遐目。',120,'全唐诗/poet.song.219000.json','["晨登江上樓，周覽竟遐目。", "江天渺無際，清致如可匊。", "初日明遠峰，微煙消廣麓。", "平波浄如鏡，羣象印寒淥。", "浦溆集帆檣，長空來鸛鶩。", "涼風天末起，散入簷前竹。", "曠然適野情，誰能念幽獨。", "手把離騷經，閒倚闌干讀。", "靈均邈千載，遺音諒難續。", "滄浪在何處，思以濯吾足。"]'),
('a13059ae-bd27-485c-abfb-0c32c1654eee','江樓閑望懷關內親知','釋文珦','宋','宋诗','song-poetry','','[]','摇落江天欲盡秋，遠鴻高送一行愁。',64,'全唐诗/poet.song.219000.json','["摇落江天欲盡秋，遠鴻高送一行愁。", "音書寂絕秦雲外，身世蹉跎楚水頭。", "年貌暗隨黄葉去，時情深付碧波流。", "風凄日冷湖光晚，駐目寒空獨倚樓。"]'),
('00b44795-eab3-443c-8883-924815012e12','憑闌','釋文珦','宋','宋诗','song-poetry','','[]','清川屢縈回，石路更深窈。',48,'全唐诗/poet.song.219000.json','["清川屢縈回，石路更深窈。", "經月無行人，柴門閉春草。", "虛堂在雲際，疎磬出林杪。", "日日有餘閒，憑闌看飛鳥。"]'),
('1c6a250d-5c47-4a01-8609-b9469277359c','富春屠','釋文珦','宋','宋诗','song-poetry','','[]','瓜橋路入屠山寺，山勢蜿蜒似卧龍。',64,'全唐诗/poet.song.219000.json','["瓜橋路入屠山寺，山勢蜿蜒似卧龍。", "長者布金傳幾世，應真垂迹在前峰。", "連筒架壑寒泉潔，高閣凌空莫靄重。", "八十老僧偏念古，向余慷慨說孫鍾。"]'),
('3b954d37-bac4-4354-bfe8-7f50c932519c','賦海上人吾廬','釋文珦','宋','宋诗','song-poetry','','[]','君愛吾亦愛，居之幽且深。',48,'全唐诗/poet.song.219000.json','["君愛吾亦愛，居之幽且深。", "嘉木有餘蔭，鳴禽多好音。", "不知此身閒，但覺萬慮沈。", "自非羲皇人，何以知子心。"]'),
('aba480b8-4348-4e4c-aab0-308720a98cc0','君子吟','邵雍','宋','宋诗','song-poetry','','[]','君子與義，小人與利。',160,'全唐诗/poet.song.22000.json','["君子與義，小人與利。", "與義日興，與利日廢。", "君子尚德，小人尚力。", "尚德樹恩，尚力樹敵。", "君子作福，小人作威。", "作福福至，作威禍隨。", "君子樂善，小人樂惡。", "樂惡惡至，樂善善歸。", "君子好譽，小人好毀。", "好毀人怒，好譽人喜。", "君子思興，小人思壞。", "思興召祥，思壞召怪。", "君子好與，小人好求。", "好與多喜，好求多憂。", "君子好生，小人好殺。", "好生道行，好殺道絕。"]'),
('a7583bc5-0e37-43eb-bf1d-a64e85619133','先天吟','邵雍','宋','宋诗','song-poetry','','[]','先天天弗違，後天奉天時。',24,'全唐诗/poet.song.22000.json','["先天天弗違，後天奉天時。", "弗違無時虧，奉時有時疲。"]'),
('a54ceb83-b7d6-410e-a7f7-edec84589407','爽口吟','邵雍','宋','宋诗','song-poetry','','[]','爽口之物少茹，爽心之行少慮。',28,'全唐诗/poet.song.22000.json','["爽口之物少茹，爽心之行少慮。", "爽意之言少語，爽身之事少做。"]'),
('58f7ee64-3a12-4325-8e92-7a21d45aecab','至誠吟','邵雍','宋','宋诗','song-poetry','','[]','不多求故得，不雜學故明。',24,'全唐诗/poet.song.22000.json','["不多求故得，不雜學故明。", "欲得心常明，無過用至誠。"]'),
('cd908600-c88b-448b-ac11-606885d4649d','書事吟','邵雍','宋','宋诗','song-poetry','','[]','他山有石能攻玉，玉未全成老已催。',64,'全唐诗/poet.song.22000.json','["他山有石能攻玉，玉未全成老已催。", "有限光陰隨事去，無涯衰朽逐人來。", "陶鎔情性詩千首，燮理筋骸酒一盃。", "六十六年無事日，心源方始似昭回。"]'),
('d6fd9a80-91ac-42de-8ffb-7ee786c5d483','答寧秀才求詩吟','邵雍','宋','宋诗','song-poetry','','[]','林下閑言語，何須要許多。',24,'全唐诗/poet.song.22000.json','["林下閑言語，何須要許多。", "幾乎三百首，足以備吟哦。"]'),
('8423649e-4cd8-4436-83d1-c5386798d25d','詩酒吟','邵雍','宋','宋诗','song-poetry','','[]','聖人難處口能宣，何止千年與萬年。',64,'全唐诗/poet.song.22000.json','["聖人難處口能宣，何止千年與萬年。", "心靜始能知白白，眼明方會看青天。", "鬼神情狀將詩寫，造化功夫用酒傅。", "傅寫不干詩酒事，若無詩酒又難言。"]'),
('dbf75104-bc7c-46dc-84eb-778ba3a1c62c','白頭吟','邵雍','宋','宋诗','song-poetry','','[]','何人頭不白，我白不因愁。',48,'全唐诗/poet.song.22000.json','["何人頭不白，我白不因愁。", "只被人多欲，其如我不憂。", "不憂緣不動，多欲爲多求。", "年老人常事，如何不白頭。"]'),
('068bdb5e-28b2-4164-9813-497c89a449ba','人物吟','邵雍','宋','宋诗','song-poetry','','[]','人破須至護，物破須至補。',48,'全唐诗/poet.song.22000.json','["人破須至護，物破須至補。", "補護既已多，卒歸于敗露。", "人有人之情，物有物之理。", "人物類不同，情理安有異。"]'),
('27a93c7b-8b75-490b-ad13-b1c63e9ba240','偶得吟','邵雍','宋','宋诗','song-poetry','','[]','林間無事可裝懷，晝睡功勞酒一盃。',32,'全唐诗/poet.song.22000.json','["林間無事可裝懷，晝睡功勞酒一盃。", "殘夢不能全省記，半隨風雨過東街。"]'),
('8d0e8f19-cc18-4cf1-9937-912bc9ef934b','觀物吟','邵雍','宋','宋诗','song-poetry','','[]','一氣才分，兩儀已備。',40,'全唐诗/poet.song.22000.json','["一氣才分，兩儀已備。", "圓者爲天，方者爲地。", "變化生成，動植類起。", "人在其間，最靈最貴。"]'),
('9ab9bd76-b449-4522-a4a0-901e9ffaa179','戰國吟','邵雍','宋','宋诗','song-poetry','','[]','七國之時尚戰爭，威强智詐一齊行。',128,'全唐诗/poet.song.22000.json','["七國之時尚戰爭，威强智詐一齊行。", "廉頗白起善用兵，蘇秦張儀善縱橫。", "朝爲布衣暮公卿，昨日鼎食今鼎烹。", "范雎謝相何心情，蔡澤入秦何依憑。", "始皇奮袂天下寧，二世乞爲氓不能。", "三千賓客憤未平，百二山河漢已興。", "所存舊物惟空名，殘陽衰草山川形。", "都似一場春夢過，自餘惡足語威獰。"]'),
('66253028-f40c-4cce-a917-7c3da297197e','感事吟','邵雍','宋','宋诗','song-poetry','','[]','切玉如泥劍不虛，誰知世上有昆吾。',64,'全唐诗/poet.song.22000.json','["切玉如泥劍不虛，誰知世上有昆吾。", "能言未是真男子，善處方名大丈夫。", "士老林泉誠所願，民填溝壑諒何辜。", "然非我事我心惻，珍重羲皇一卷書。"]'),
('61f8881d-86b7-473b-9884-dd442a44fd84','又五首  其一','邵雍','宋','宋诗','song-poetry','','[]','萬物有精英，人爲萬物靈。',48,'全唐诗/poet.song.22000.json','["萬物有精英，人爲萬物靈。", "必先詳事體，然後論人情。", "氣靜形安樂，心閑身太平。", "伊耆治天下，不出此名生。"]'),
('82259d6b-c559-4cd8-91bd-20eb5388d95c','又五首  其二','邵雍','宋','宋诗','song-poetry','','[]','用藥似交兵，兵交豈有寧。',48,'全唐诗/poet.song.22000.json','["用藥似交兵，兵交豈有寧。", "求安安未得，去病病還生。", "湯劑未全補，甘肥又却爭。", "何由能壽考，瑞應老人星。"]'),
('3968b190-8f62-4bac-b48f-57deceee7f39','又五首  其三','邵雍','宋','宋诗','song-poetry','','[]','萬物道爲樞，其來類自殊。',48,'全唐诗/poet.song.22000.json','["萬物道爲樞，其來類自殊。", "性雖無厚薄，理亦有精麄。", "未若人爲盛，還知物有餘。", "我生于此日，幸免作庸夫。"]'),
('ec9514b4-75da-4a33-b9a5-8545d8ced2e1','又五首  其四','邵雍','宋','宋诗','song-poetry','','[]','曾聞不若見，曾見不如經。',48,'全唐诗/poet.song.22000.json','["曾聞不若見，曾見不如經。", "既用身經過，何煩口說行。", "改詩知化筆，醒酒識和羹。", "料得人間事，無由出此情。"]'),
('d1cdd63b-8735-4c1f-aa19-558e5eeb4870','又五首  其五','邵雍','宋','宋诗','song-poetry','','[]','前有億萬年，後有億萬世。',48,'全唐诗/poet.song.22000.json','["前有億萬年，後有億萬世。", "中間有壽人，未過百來歲。", "出口無善言，行身無善事。", "徒有人之身，殊無人之貴。"]'),
('32ee3757-2f6c-4990-8d7f-03f3da136b92','履道留題吟','邵雍','宋','宋诗','song-poetry','','[]','何代無人振德輝，衆賢今日會西畿。',32,'全唐诗/poet.song.22000.json','["何代無人振德輝，衆賢今日會西畿。", "太平文物風流事，更勝元和全盛時。"]'),
('33b4f5ee-79ca-488d-b45f-db7020f34c3e','見義吟','邵雍','宋','宋诗','song-poetry','','[]','見善必爲，不見則已。',20,'全唐诗/poet.song.22000.json','["見善必爲，不見則已。", "量力而動，力盡而止。"]'),
('ffc02f27-a111-440e-8c97-5299a3242ad9','觀物吟','邵雍','宋','宋诗','song-poetry','','[]','如鸞如鳳，意思安詳。',40,'全唐诗/poet.song.22000.json','["如鸞如鳳，意思安詳。", "所生之人，非忠則良。", "如鼠如雀，意思驚躩。", "所生之人，不凶則惡。"]'),
('cd737d24-1bcc-4928-a3bb-9c3da8e918f0','王公吟','邵雍','宋','宋诗','song-poetry','','[]','王公大人，天下具瞻。',81,'全唐诗/poet.song.22000.json','["王公大人，天下具瞻。", "輕流薄習，重損威嚴。", "此尚未了，彼安能兼。", "非唯失道，又復起貪。", "頂戴儒冠冠，心存象教。", "本圖心寧，復使心鬧。", "譬如生子，當求克肖。", "不教義方，教之竊盜。"]'),
('32b025fd-4db9-44ac-8c77-c4a93ce84705','自詠吟','邵雍','宋','宋诗','song-poetry','','[]','老去無成齒髮衰，年將七十待何爲。',64,'全唐诗/poet.song.22000.json','["老去無成齒髮衰，年將七十待何爲。", "居常無病不服藥，間或有懷猶作詩。", "引水更憐魚並至，折花仍喜蝶相隨。", "平生積學無他效，只得胸中恁坦夷。"]'),
('9e51a7f9-64a4-4fdc-b8f1-857129488ecb','觀物吟','邵雍','宋','宋诗','song-poetry','','[]','畫工狀物，經月經年。',110,'全唐诗/poet.song.22000.json','["畫工狀物，經月經年。", "軒鑑照物，立寫于前。", "鑑之爲明，猶或未精。", "工出人手，平與不平。", "天下之平，莫若于水。", "止能照表，不能照裏。", "表裏洞照，其唯聖人。", "察言觀行，罔或不真。", "盡物之性，去己之情。", "有德之人，而必有言。", "能言之人，未必能行。"]'),
('8bdde787-7fa3-40e4-9c44-ac1c5efd3035','能寐吟','邵雍','宋','宋诗','song-poetry','','[]','大驚不寐，大憂不寐。',50,'全唐诗/poet.song.22000.json','["大驚不寐，大憂不寐。", "大傷不寐，大病不寐。", "大喜不寐，大安能寐。", "何故不寐，湛於有累。", "何故能寐，行於無事。"]'),
('d6316e4d-475c-455c-80cb-b709c905a82c','鷓鴣吟二首  其一','邵雍','宋','宋诗','song-poetry','','[]','人間重者是黄金，誰道黄金無處尋。',64,'全唐诗/poet.song.22000.json','["人間重者是黄金，誰道黄金無處尋。", "不著閑辭文雅意，更將何事悅良心。", "遠山四面供清潤，幽鳥千般送好音。", "無限春光都去盡，請君聽唱鷓鴣吟。"]'),
('d7252356-4aba-45f5-9617-c06cb524bba7','鷓鴣吟二首  其二','邵雍','宋','宋诗','song-poetry','','[]','翠竹叢深啼鷓鴣，鷓鴣聲更勝提壺。',64,'全唐诗/poet.song.22000.json','["翠竹叢深啼鷓鴣，鷓鴣聲更勝提壺。", "江南江北常相逐，春後春前多自呼。", "遷客銷魂驚夢寐，征人零淚濕衣裾。", "愁中聞處腸先斷，似此傷懷禁得無。"]'),
('8fc1a2c4-9f1b-421f-b429-fbb8a24c7d89','先天吟','邵雍','宋','宋诗','song-poetry','','[]','若問先天一字無，後天方要著功夫。',32,'全唐诗/poet.song.22000.json','["若問先天一字無，後天方要著功夫。", "拔山蓋世稱才力，到此分毫强得乎。"]'),
('014cbacd-b347-4b4a-be7b-8faefe8e18d4','自樂吟','邵雍','宋','宋诗','song-poetry','','[]','麟鳳何嘗不在郊，太平消得苦譊譊。',64,'全唐诗/poet.song.22000.json','["麟鳳何嘗不在郊，太平消得苦譊譊。", "纔聞善事心先喜，每見奇書手自抄。", "一瓦清泉來竹下，兩竿紅日上松梢。", "窩中睡起窩前坐，安得閑辭解客嘲。"]'),
('a0d865de-af26-4448-80aa-d67dea267791','民情吟','邵雍','宋','宋诗','song-poetry','','[]','民情既樂，和氣爲祥。',40,'全唐诗/poet.song.22000.json','["民情既樂，和氣爲祥。", "民情既憂，戾氣爲殃。", "祥爲雨露，天下豐穰。", "殃爲水旱，天下凶荒。"]'),
('c80469af-77ea-478c-b26d-a2888b379bc1','牡丹吟','邵雍','宋','宋诗','song-poetry','','[]','牡丹花品冠羣芳，況是其間更有王。',32,'全唐诗/poet.song.22000.json','["牡丹花品冠羣芳，況是其間更有王。", "四色變而成百色，百般顔色百般香。"]'),
('e62717fa-a691-4262-aada-5e9b5d678476','代書吟','邵雍','宋','宋诗','song-poetry','','[]','金須百鍊始知精，水鑑何如人鑑明。',64,'全唐诗/poet.song.22000.json','["金須百鍊始知精，水鑑何如人鑑明。", "不棄既能存故舊，久要焉敢忘平生。", "經綸事體當言用，道義襟懷只論誠。", "草木面前何止萬，歲寒松桂獨青青。"]'),
('faac5635-e979-4849-8a7f-d81360181aa4','病淺吟','邵雍','宋','宋诗','song-poetry','','[]','病淺之時人不疑，病深之後藥難醫。',64,'全唐诗/poet.song.22000.json','["病淺之時人不疑，病深之後藥難醫。", "勞謙所以有終吉，迷復何嘗無大虧。", "物我中間難著髮，天人之際豈容絲。", "能知古樂猶今樂，省了譊譊多少辭。"]'),
('48504138-499d-4401-9ffe-d0d64e56f149','借出詩','邵雍','宋','宋诗','song-poetry','','[]','詩狂書更逸，近歲不勝多。',24,'全唐诗/poet.song.22000.json','["詩狂書更逸，近歲不勝多。", "太半落天下，未還安樂窩。"]'),
('226de73c-1be8-45b6-ad7c-e9918ae15d73','無苦吟','邵雍','宋','宋诗','song-poetry','','[]','平生無苦吟，書翰不求深。',48,'全唐诗/poet.song.22000.json','["平生無苦吟，書翰不求深。", "行筆因調性，成詩爲寫心。", "詩揚心造化，筆發性園林。", "所樂樂吾樂，樂而安有淫。"]'),
('6564b273-d542-4dce-a8fa-0a8ba46b5d0d','萬物吟','邵雍','宋','宋诗','song-poetry','','[]','萬物備于身，乾坤不負人。',48,'全唐诗/poet.song.22000.json','["萬物備于身，乾坤不負人。", "時光嗟荏苒，事體落因循。", "既感青春老，還驚白髮新。", "胸中若無有，未免作埃塵。"]'),
('b5edff99-3346-4692-afe8-18a898338c5d','月窟吟','邵雍','宋','宋诗','song-poetry','','[]','月窟與天根，中間來往頻。',48,'全唐诗/poet.song.22000.json','["月窟與天根，中間來往頻。", "所居皆綽綽，何往不伸伸。", "投足自有定，滿懷都是春。", "若無詩與酒，又似太虧人。"]'),
('dda8a02d-e681-444c-8254-e0481f69017e','大象吟','邵雍','宋','宋诗','song-poetry','','[]','大象自中虛，中虛真不渝。',48,'全唐诗/poet.song.22000.json','["大象自中虛，中虛真不渝。", "施爲心事業，應對口功夫。", "伎倆千般有，憂愁一點無。", "人能知此理，勝讀五車書。"]'),
('bc95f395-c458-4919-b41f-ad884b3d64be','百病吟','邵雍','宋','宋诗','song-poetry','','[]','百病起於情，情輕病亦輕。',48,'全唐诗/poet.song.22000.json','["百病起於情，情輕病亦輕。", "可能無係累，却是有依憑。", "秋月千山靜，春華萬木榮。", "若論真事業，人力莫經營。"]'),
('e820519a-dfa0-4b49-b4cf-1a8d2bffbec3','小車吟','邵雍','宋','宋诗','song-poetry','','[]','春暖未苦熱，秋涼未甚寒。',24,'全唐诗/poet.song.22000.json','["春暖未苦熱，秋涼未甚寒。", "小車隨意出，所到即成歡。"]'),
('9997f9ed-da16-4181-aadc-7921e830036a','擊壤吟','邵雍','宋','宋诗','song-poetry','','[]','擊壤三千首，行窩二十家。',48,'全唐诗/poet.song.22000.json','["擊壤三千首，行窩二十家。", "樂天爲事業，養志是生涯。", "出入將如意，過從用小車。", "人能知此樂，何必待紛華。"]'),
('ad1a196c-78eb-4ed9-a951-ae9fe2f714b2','留題水北楊郎中園亭二首  其一','邵雍','宋','宋诗','song-poetry','','[]','買宅從來重見山，見山今直幾何錢。',64,'全唐诗/poet.song.22000.json','["買宅從來重見山，見山今直幾何錢。", "奇峯環列遠隔水，喬木俯臨微带煙。", "行路客疑驚洞府，凭欄人恐是神仙。", "長憂暗入丹青手，寫向鮫綃天下傳。"]'),
('4212d7ba-78c6-4f7e-8614-50f2ab4a9c94','留題水北楊郎中園亭二首  其二','邵雍','宋','宋诗','song-poetry','','[]','洛下誰家不買居，買居還得似君無。',64,'全唐诗/poet.song.22000.json','["洛下誰家不買居，買居還得似君無。", "風光一片非塵世，景物四時成畫圖。", "後圃花奇同閬苑，前軒峯好類蓬壺。", "人生能向此中老，亦是世間豪丈夫。"]'),
('2854756d-4a83-44c1-8fa2-dee4d59a6792','秋盡吟','邵雍','宋','宋诗','song-poetry','','[]','數日之間秋遂盡，百思無以慰蹉跎。',64,'全唐诗/poet.song.22000.json','["數日之間秋遂盡，百思無以慰蹉跎。", "園林正好愛不徹，草木已黄情柰何。", "雖老筋骸行尚健，儘高臺榭望仍多。", "終朝把酒未成醉，又欲臨風一浩歌。"]'),
('457331cb-1519-4526-af96-7031b10d8a8c','不肖吟','邵雍','宋','宋诗','song-poetry','','[]','不肖之人，志在遊蕩。',40,'全唐诗/poet.song.22000.json','["不肖之人，志在遊蕩。", "身在屋下，心在屋上。", "不肖之子，志在浮誇。", "身尚不保，焉能保家。"]'),
('bf8f7b03-7ddf-4ea3-b06a-5d90c81de899','君子吟','邵雍','宋','宋诗','song-poetry','','[]','君子之去，亦如其來。',40,'全唐诗/poet.song.22000.json','["君子之去，亦如其來。", "小人之來，亦如其去。", "既有恩情，且無怨怒。", "既有憎嫌，且無思慕。"]'),
('7757f115-3f5f-4d00-a4cf-d07bb509b48f','小人吟','邵雍','宋','宋诗','song-poetry','','[]','小人無節，棄本逐末。',20,'全唐诗/poet.song.22000.json','["小人無節，棄本逐末。", "喜思其與，怒思其奪。"]'),
('75629d8a-5256-42fe-8c41-939305bdb41b','把手吟','邵雍','宋','宋诗','song-poetry','','[]','富貴把手，貧賤掣肘。',40,'全唐诗/poet.song.22000.json','["富貴把手，貧賤掣肘。", "貧賤把手，富貴掣肘。", "金石之交，死且不朽。", "市井之交，自難長久。"]'),
('7517233d-11ad-4497-969e-2ef550d86e2b','大易吟','邵雍','宋','宋诗','song-poetry','','[]','天地定位，否泰反類。',60,'全唐诗/poet.song.22000.json','["天地定位，否泰反類。", "山澤通氣，損咸見義。", "雷風相薄，恒益起意。", "水火相射，既濟未濟。", "四象相交，成十六事。", "八卦相盪，爲六十四。"]'),
('66d915d1-5a80-4745-90ad-509a90263831','罷吟吟','邵雍','宋','宋诗','song-poetry','','[]','久欲罷吟詩，還驚意忽奇。',48,'全唐诗/poet.song.22000.json','["久欲罷吟詩，還驚意忽奇。", "坐中知物體，言外到天機。", "得句不勝易，成篇豈忍遺。", "安知千萬載，後世無宣尼。"]'),
('a288952b-3152-4255-a120-fdcd55a5a8eb','黄金吟','邵雍','宋','宋诗','song-poetry','','[]','身上有黄金，人無走陸沉。',48,'全唐诗/poet.song.22000.json','["身上有黄金，人無走陸沉。", "求時未必見，得處不因尋。", "辨捷非通物，涵容是了心。", "會彈無絃琴，然後能知音。"]'),
('04273189-f87f-43ae-9975-1eba7ee6d004','鷓鴣吟','邵雍','宋','宋诗','song-poetry','','[]','事體一番新，纔新又却陳。',48,'全唐诗/poet.song.22000.json','["事體一番新，纔新又却陳。", "新陳非利物，義理不由人。", "歲月休驚晚，鶑花續報春。", "餘樽幸無恙，宜唱鷓鴣頻。"]'),
('cd502ffe-c3c2-42a3-9feb-399cf20cc113','閑中吟  其一','邵雍','宋','宋诗','song-poetry','','[]','閑中氣味長，長處是仙鄉。',48,'全唐诗/poet.song.22000.json','["閑中氣味長，長處是仙鄉。", "富有林泉樂，清無市井忙。", "爛遊千聖奧，醉擁萬花香。", "莫作傷心事，傷心易斷腸。"]'),
('51a28438-840e-4bc9-bda2-cad0d6988167','閑中吟  其二','邵雍','宋','宋诗','song-poetry','','[]','閑中氣味真，真處是天民。',48,'全唐诗/poet.song.22000.json','["閑中氣味真，真處是天民。", "富有林泉樂，清無市井塵。", "爛遊千聖奧，醉擁萬花春。", "莫作傷心事，傷心愁殺人。"]'),
('7c8e203b-9f6a-4d77-b165-369a615fbc69','閑中吟  其三','邵雍','宋','宋诗','song-poetry','','[]','閑中氣味全，全處是天仙。',48,'全唐诗/poet.song.22000.json','["閑中氣味全，全處是天仙。", "富有林泉樂，清無市井喧。", "爛觀千聖奧，醉擁萬花妍。", "莫作傷心事，傷心事好旋。"]'),
('3751711d-7001-4b66-ae07-877cfea56aaf','蒼蒼吟','邵雍','宋','宋诗','song-poetry','','[]','人人共戴天，我戴豈徒然。',48,'全唐诗/poet.song.22000.json','["人人共戴天，我戴豈徒然。", "須識天人理，方知造化權。", "功名歸酒盞，器業入詩篇。", "料得閑中樂，無如我得全。"]'),
('84c44851-3a5b-47ab-aaf3-0c2557f7d66d','團團吟','邵雍','宋','宋诗','song-poetry','','[]','如鑑又如鈎，迴旋莫記秋。',48,'全唐诗/poet.song.22000.json','["如鑑又如鈎，迴旋莫記秋。", "難窮天上理，易白世間頭。", "團處人人喜，虧時物物愁。", "有生無不喘，何必待吳牛。"]'),
('45480eab-ef6d-43b4-a493-88b9a688bffe','代書吟','邵雍','宋','宋诗','song-poetry','','[]','見別一年餘，歲殘相憶初。',48,'全唐诗/poet.song.22000.json','["見別一年餘，歲殘相憶初。", "重煩君欵密，遠寄我空疎。", "衰朽百端有，憂愁一點無。", "閑吟四十字，聊用答來書。"]'),
('093f7abe-51f6-4da0-ac02-409e5f2951ef','失詩吟','邵雍','宋','宋诗','song-poetry','','[]','胸中風雨吼，筆下龍蛇走。',24,'全唐诗/poet.song.22000.json','["胸中風雨吼，筆下龍蛇走。", "前後落人間，三千有餘首。"]'),
('ac382d2a-1f9a-47a6-bc44-1243135d83d4','不去吟','邵雍','宋','宋诗','song-poetry','','[]','行年六十六，不去兩般事。',48,'全唐诗/poet.song.22000.json','["行年六十六，不去兩般事。", "用詩贈真宰，以酒勸象帝。", "面未發酡顔，心先動和氣。", "俯仰天地間，自知無所愧。"]'),
('75419cfc-4c9e-49d7-b70d-37baaf096979','經世吟','邵雍','宋','宋诗','song-poetry','','[]','羲軒堯舜，湯武桓文。',80,'全唐诗/poet.song.22000.json','["羲軒堯舜，湯武桓文。", "皇王帝伯，父子君臣。", "四者之道，理限于秦。", "降及兩漢，又歷三分。", "東西俶擾，南北紛紜。", "五胡十姓，天紀幾焚。", "非唐不濟，非宋不存。", "千世萬世，中原有人。"]'),
('27b69857-4db9-4155-8a83-ec5dcac77e94','知人吟','邵雍','宋','宋诗','song-poetry','','[]','君子知人出于知，小人知人出于私。',58,'全唐诗/poet.song.22000.json','["君子知人出于知，小人知人出于私。", "出于知，則同乎理者謂之是，異乎理者謂之非。", "出于私，則同乎己者謂之是，異乎己者謂之非。"]'),
('39d3608b-3045-4be9-ac8c-eaca4434c501','言行吟','邵雍','宋','宋诗','song-poetry','','[]','能言未是難，行得始爲艱。',24,'全唐诗/poet.song.22000.json','["能言未是難，行得始爲艱。", "須是真男子，方能無厚顔。"]'),
('6b3f6e3c-c4f7-4870-b558-5246cd5698b2','光陰吟','邵雍','宋','宋诗','song-poetry','','[]','三百六旬有六日，光陰過眼如奔輪。',32,'全唐诗/poet.song.22000.json','["三百六旬有六日，光陰過眼如奔輪。", "周而復始未嘗息，安得四時長似春。"]'),
('b5a7a561-a62e-4186-bdab-5451b6fe7623','舉酒吟','邵雍','宋','宋诗','song-poetry','','[]','閑與賓朋飲酒盃，盃中長似有花開。',64,'全唐诗/poet.song.22000.json','["閑與賓朋飲酒盃，盃中長似有花開。", "清談纔向口中出，和氣已從心上來。", "物外意非由象得，坐間春不自天迴。", "施之天下能如此，天下何憂不放懷。"]'),
('bdc9a2df-6f2d-40b9-bb2d-714887b84b09','酒少吟','邵雍','宋','宋诗','song-poetry','','[]','此物近來貧，時時得數斤。',48,'全唐诗/poet.song.22000.json','["此物近來貧，時時得數斤。", "如茶辜老朽，似藥負交親。", "未飲先憂盡，雖斟不敢頻。", "何由同九日，長有白衣人。"]'),
('23a75b96-3df2-4f22-9c48-c11651d50ac2','觀棋絕句  其一','邵雍','宋','宋诗','song-poetry','','[]','未去交爭意，難忘黑白心。',24,'全唐诗/poet.song.22000.json','["未去交爭意，難忘黑白心。", "一條無敵路，徹了沒人尋。"]'),
('2d7c40be-2f75-4d08-bee6-fc42697801b6','觀棋絕句  其二','邵雍','宋','宋诗','song-poetry','','[]','未去交爭意，難忘黑白情。',24,'全唐诗/poet.song.22000.json','["未去交爭意，難忘黑白情。", "一條平穩路，痛惜沒人行。"]'),
('2c9f2cf8-2aff-46ba-b591-d1f48018b753','老去吟','邵雍','宋','宋诗','song-poetry','','[]','老去無成鬢已斑，縱心年幾合清閑。',64,'全唐诗/poet.song.22000.json','["老去無成鬢已斑，縱心年幾合清閑。", "如何得意雲山外，更欲遊心詩酒間。", "大字寫詩酬素志，小盃斟酒發酡顔。", "春雷驚起千年蟄，筆下蒼龍自往還。"]'),
('cf9f63dd-c204-4fab-a4ea-6d93885ea53b','亂石吟','邵雍','宋','宋诗','song-poetry','','[]','天津多亂石，石裏閑尋覓。',48,'全唐诗/poet.song.22000.json','["天津多亂石，石裏閑尋覓。", "真玉固難求，似玉亦難得。", "徒有碌碌青，亦有磷磷白。", "柰無清越聲，更無溫潤色。"]'),
('7732061b-4f14-40e2-b769-271f382c5484','未有吟  其一','邵雍','宋','宋诗','song-poetry','','[]','未有一分功，先有十分敵。',24,'全唐诗/poet.song.22000.json','["未有一分功，先有十分敵。", "所得無分毫，所喪無紀極。"]'),
('bfe500c0-e49e-4a1c-ad24-edfaa41b3120','未有吟  其二','邵雍','宋','宋诗','song-poetry','','[]','未有一分讓，先有十分爭。',24,'全唐诗/poet.song.22000.json','["未有一分讓，先有十分爭。", "所喪者實事，所得者虛名。"]'),
('cf6e6826-f878-49a8-b8f1-88376ddc5f46','誡子吟  其一','邵雍','宋','宋诗','song-poetry','','[]','至寶明珠非有纇，全珍良玉自無瑕。',32,'全唐诗/poet.song.22000.json','["至寶明珠非有纇，全珍良玉自無瑕。", "爲珠爲玉尚如此，何況爲人多過差。"]'),
('830deccd-c540-4c28-bfa8-200b61ad1434','誡子吟  其二','邵雍','宋','宋诗','song-poetry','','[]','有過不能改，知賢不肯親。',24,'全唐诗/poet.song.22000.json','["有過不能改，知賢不肯親。", "雖生人世上，未得謂之人。"]'),
('e623e616-c00c-44f4-a0e3-fece82f75f2b','誡子吟  其三','邵雍','宋','宋诗','song-poetry','','[]','周孔不足法，軻雄不足師。',24,'全唐诗/poet.song.22000.json','["周孔不足法，軻雄不足師。", "還同棄常饍，除是適蠻夷。"]'),
('4e7d0a63-88a1-4224-a88f-d0ab59040e68','乾坤吟  其一','邵雍','宋','宋诗','song-poetry','','[]','意亦心所至，言須耳所聞。',24,'全唐诗/poet.song.22000.json','["意亦心所至，言須耳所聞。", "誰云天地外，別有好乾坤。"]'),
('2c63312f-3807-42a7-afe7-6164b767ecae','乾坤吟  其二','邵雍','宋','宋诗','song-poetry','','[]','道不遠于人，乾坤只在身。',24,'全唐诗/poet.song.22000.json','["道不遠于人，乾坤只在身。", "誰能天地外，別去覓乾坤。"]'),
('317da0de-58d5-414f-8305-86c6f6183392','胡越吟','邵雍','宋','宋诗','song-poetry','','[]','胡越同心日，夫妻反目時。',24,'全唐诗/poet.song.22000.json','["胡越同心日，夫妻反目時。", "人間無大小，得失在須斯。"]'),
('7bd370b0-5eb6-47a9-b899-44236bbce640','善處吟','邵雍','宋','宋诗','song-poetry','','[]','善處憂難作，能持事自修。',24,'全唐诗/poet.song.22000.json','["善處憂難作，能持事自修。", "腹心無外物，蠻貊亦懷柔。"]'),
('5d576c1f-7766-4781-9346-7c9727e80bfa','百年吟','邵雍','宋','宋诗','song-poetry','','[]','百年嗟荏苒，千里痛蕭條。',24,'全唐诗/poet.song.22000.json','["百年嗟荏苒，千里痛蕭條。", "忍逐東流水，無期任所飄。"]'),
('56b74996-3d8f-4d53-8163-d6a1002e2a7f','歲杪吟','邵雍','宋','宋诗','song-poetry','','[]','一日去一日，一年添一年。',48,'全唐诗/poet.song.22000.json','["一日去一日，一年添一年。", "饒教成大器，其那已華顛。", "志意雖依舊，聰明不及前。", "若非心有得，亦恐學神仙。"]'),
('b2d43807-a89b-4828-9f87-56324df604e1','觀棋小吟','邵雍','宋','宋诗','song-poetry','','[]','誰言博奕尚優游，利害相磨未始休。',64,'全唐诗/poet.song.22000.json','["誰言博奕尚優游，利害相磨未始休。", "初得手時宜顧望，合行權處莫遲留。", "二年乃正三監罪，七日能尸兩觀囚。", "天下太平無一事，南陽高卧更何求。"]'),
('fc2e2cd8-a134-4028-81d5-a37f18b1bbe0','又借出詩','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中樂，媧皇笙萬攢。',24,'全唐诗/poet.song.22000.json','["安樂窩中樂，媧皇笙萬攢。", "自從閑借出，客到遂無歡。"]'),
('561b8131-457d-4b7f-9841-8876810999d9','和王規甫司勳見贈','邵雍','宋','宋诗','song-poetry','','[]','何止千年與萬年，歲寒松桂獨依然。',64,'全唐诗/poet.song.22000.json','["何止千年與萬年，歲寒松桂獨依然。", "若無揚子天人學，安有莊生內外篇。", "已約月陂尋白石，更期金谷弄清泉。", "誰云影論紛紜甚，一任山巔復起巔。"]'),
('efc3afb8-52bf-4811-bca9-47e58e091ba8','答友人勸酒吟','邵雍','宋','宋诗','song-poetry','','[]','人人誰不願封侯，及至封侯未肯休。',64,'全唐诗/poet.song.22000.json','["人人誰不願封侯，及至封侯未肯休。", "大得却須防大失，多憂元只爲多求。", "規模焉敢比才士，度量自知非飲流。", "少日何由能强此，況今年老雪堆頭。"]'),
('07a2472f-88d0-4607-94f2-9143fe519783','冬至吟','邵雍','宋','宋诗','song-poetry','','[]','何者謂之幾，天根理極微。',48,'全唐诗/poet.song.22000.json','["何者謂之幾，天根理極微。", "今年初盡處，明日未來時。", "此際易得意，其間難下辭。", "人能知此意，何事不能知。"]'),
('080ba408-6e4d-45b0-a3f4-436fdf007e55','盃盤吟','邵雍','宋','宋诗','song-poetry','','[]','林下盃盤大寂寥，寂寥長願似今朝。',32,'全唐诗/poet.song.22000.json','["林下盃盤大寂寥，寂寥長願似今朝。", "君看擊鼓撞鍾者，勢去賓朋不易招。"]'),
('90a1b323-4a5a-4d95-9041-5db9dfc47e7a','歡喜吟','邵雍','宋','宋诗','song-poetry','','[]','揚善不揚惡，記恩不記讎。',24,'全唐诗/poet.song.22000.json','["揚善不揚惡，記恩不記讎。", "人人自歡喜，何患少交遊。"]'),
('8ad733ac-7da4-455c-b536-d58fd63b7db5','善人吟','邵雍','宋','宋诗','song-poetry','','[]','良如金玉，重如丘山。',20,'全唐诗/poet.song.22000.json','["良如金玉，重如丘山。", "儀如鸞鳳，氣如芝蘭。"]'),
('dadf2c79-886a-4d1e-82ec-edc27d80a7f6','議論吟','邵雍','宋','宋诗','song-poetry','','[]','事苟非，自有異。',16,'全唐诗/poet.song.22000.json','["事苟非，自有異。", "事苟是，安有二。"]'),
('fbb377d4-a86d-4021-9c68-2a3284f634c2','推誠吟','邵雍','宋','宋诗','song-poetry','','[]','天雖不語人能語，心可欺時天可欺。',64,'全唐诗/poet.song.22000.json','["天雖不語人能語，心可欺時天可欺。", "天人相去不相還，只在人心人不知。", "人心先天天弗違，人身後天奉天時。", "身心相去不相遠，只在人誠人不推。"]'),
('bfe1a981-ea81-4bd3-8fe9-d896a7f49491','堯夫吟','邵雍','宋','宋诗','song-poetry','','[]','堯夫吟，天下拙。',80,'全唐诗/poet.song.22000.json','["堯夫吟，天下拙。", "來無時，去無節。", "如山川，行不徹。", "如江河，流不竭。", "如芝蘭，香不歇。", "如簫韶，聲不絕。", "也有花，也有雪。", "也有風，也有月。", "又溫柔，又峻烈。", "又風流，又激切。"]'),
('5444a192-f1f4-4cf0-a97e-f631871866d2','意外吟','邵雍','宋','宋诗','song-poetry','','[]','事出意外，人難智求。',40,'全唐诗/poet.song.22000.json','["事出意外，人難智求。", "自非妄動，惡用多愁。", "既有誤中，寧無暗投。", "能知此說，天下何憂。"]'),
('03f1f951-298e-46fd-9431-39df71cb07f3','當斷吟','邵雍','宋','宋诗','song-poetry','','[]','斷以决疑，疑不可緩。',20,'全唐诗/poet.song.22000.json','["斷以决疑，疑不可緩。", "當斷不斷，反受其亂。"]'),
('82305129-e41f-4838-83ef-faced05bc048','憂夢吟','邵雍','宋','宋诗','song-poetry','','[]','至人無夢，聖人無憂。',40,'全唐诗/poet.song.22000.json','["至人無夢，聖人無憂。", "夢爲多想，憂爲多求。", "憂既不作，夢來何由。", "能知此說，此外何修。"]'),
('3024c82a-368c-421d-b644-a5ec85c95502','人情吟','邵雍','宋','宋诗','song-poetry','','[]','人達人情，無寡無廣。',20,'全唐诗/poet.song.22000.json','["人達人情，無寡無廣。", "天下之事，如指諸掌。"]'),
('e656cddc-c736-459e-bdcc-be0c44586937','人事吟','邵雍','宋','宋诗','song-poetry','','[]','人無取次，事莫因循。',40,'全唐诗/poet.song.22000.json','["人無取次，事莫因循。", "因循失事，取次壞人。", "人無率爾，事貴丁寧。", "率爾近薄，丁寧近誠。"]'),
('6b86e372-165f-4760-9e2b-6097be0773d2','師資吟','邵雍','宋','宋诗','song-poetry','','[]','未知道義，尋人爲師。',70,'全唐诗/poet.song.22000.json','["未知道義，尋人爲師。", "既知道義，人來爲資。", "尋師未易，爲資實難。", "指南響道，非去非還。", "師人則恥，人師則喜。", "喜恥皆非，我獨無是。", "好爲人師，與恥何異。"]'),
('53d751ad-e877-4976-868d-9c92b39f49c2','天人吟','邵雍','宋','宋诗','song-poetry','','[]','天學修心，人學修身。',60,'全唐诗/poet.song.22000.json','["天學修心，人學修身。", "身安心樂，乃見天人。", "天之與人，相去不遠。", "不知者多，知之者鮮。", "身主于人，心主于天。", "心既不樂，身何由安。"]'),
('8a977985-2681-4b9c-b520-44a35e3b35a9','樂毅吟','邵雍','宋','宋诗','song-poetry','','[]','樂毅事燕時，其心有深皆。',108,'全唐诗/poet.song.22000.json','["樂毅事燕時，其心有深皆。", "破齊七十城，迎刃不遺矢。", "豈留即墨莒，却與燕有二。", "欲使燕遂王，天下自齊始。", "豈意志未申，昭王一旦死。", "惠王固不知，使人代其位。", "强燕自此衰，何復能振起。", "自古君與臣，濟會非容易。", "重惜千萬年，英雄爲流涕。"]'),
('fc43a6bb-1dc4-4303-bc66-01bc0519db8c','十分吟  其一','邵雍','宋','宋诗','song-poetry','','[]','所謂十分人，須有十分真。',48,'全唐诗/poet.song.22000.json','["所謂十分人，須有十分真。", "非爲能寫字，非謂能爲文。", "非謂眉目秀，非謂衣服新。", "欲行人世上，直須先了身。"]'),
('8f04fbb0-a5b3-4747-a03d-13adc763a4df','十分吟  其二','邵雍','宋','宋诗','song-poetry','','[]','所謂十分人，須有十分事。',48,'全唐诗/poet.song.22000.json','["所謂十分人，須有十分事。", "事苟不十分，終是未完備。", "事父盡其心，事兄盡其意。", "事君盡其忠，事師盡其義。"]'),
('b801a3bc-a9f8-43b5-a14d-9e0e1d9ddb91','十分吟  其三','邵雍','宋','宋诗','song-poetry','','[]','人壽百來年，其過豈容易。',48,'全唐诗/poet.song.22000.json','["人壽百來年，其過豈容易。", "雖然瞬息間，其間多少事。", "號爲能了事，必先能了身。", "身苟未能了，何暇能了人。"]'),
('407027af-3ff4-4f64-96e1-0be26b0a2d06','生日吟','邵雍','宋','宋诗','song-poetry','','[]','辛亥年，辛丑月。',36,'全唐诗/poet.song.22000.json','["辛亥年，辛丑月。", "甲子日，甲戌辰。", "日辰同甲，年月同辛。", "吾於此際，生而爲人。"]'),
('b2d440ce-0035-4908-91e1-65b711ddeed8','誡子吟','邵雍','宋','宋诗','song-poetry','','[]','雞能警旦，馬能代行。',40,'全唐诗/poet.song.22000.json','["雞能警旦，馬能代行。", "犬能守禦，牛能力耕。", "人稟天地，萬物之靈。", "妬賢嫉能，不如不生。"]'),
('b852fe09-dfda-4c68-abeb-77e78878b357','有常吟','邵雍','宋','宋诗','song-poetry','','[]','天地有常理，日月有常明。',36,'全唐诗/poet.song.22000.json','["天地有常理，日月有常明。", "四時有常序，鬼神有常靈。", "聖人有常德，小人無常情。"]'),
('da1702fa-b4ec-406f-98b5-8348276114b7','歲暮吟','邵雍','宋','宋诗','song-poetry','','[]','世上紛華都不見，眼前惟見讀書尊。',64,'全唐诗/poet.song.22000.json','["世上紛華都不見，眼前惟見讀書尊。", "百千難過尚驚惕，三十歲前尤苦辛。", "少日只知艱險事，老年方識太平身。", "家風幸有兒孫繼，足以無心伴白雲。"]'),
('251e38aa-18de-442d-8101-593aca6e3278','春天吟','邵雍','宋','宋诗','song-poetry','','[]','一片春天在眼前，眼前須識好春天。',64,'全唐诗/poet.song.22000.json','["一片春天在眼前，眼前須識好春天。", "春秋冬夏能無累，雪月風花都一連。", "能用真腴爲事業，豈防他物害暄妍。", "我生其幸何多也，安有閑愁到耳邊。"]'),
('7e756244-dad4-456c-9402-9ef54d5413bc','庶幾吟','邵雍','宋','宋诗','song-poetry','','[]','以聖責人，固未完備。',40,'全唐诗/poet.song.22000.json','["以聖責人，固未完備。", "以人望人，自有餘地。", "責人無難，受責非易。", "其殆庶幾，猶望顔子。"]'),
('52e496d2-4154-4af0-9799-6723f1c9a4ff','人物吟','邵雍','宋','宋诗','song-poetry','','[]','人盛必有衰，物生須有死。',48,'全唐诗/poet.song.22000.json','["人盛必有衰，物生須有死。", "既見身前人，乃知身後事。", "身前人能興，身後事豈廢。", "興廢先言人，然後語天地。"]'),
('2be4c25a-6a9e-4350-a8f9-d88f9d7c1537','詫嗟吟','邵雍','宋','宋诗','song-poetry','','[]','昨日炙手，今日張羅。',20,'全唐诗/poet.song.22000.json','["昨日炙手，今日張羅。", "人間常事，何詫何嗟。"]'),
('43a94db3-ffcc-4ca4-b1b3-0f7f78c34aed','左衽吟','邵雍','宋','宋诗','song-poetry','','[]','自古禦戎無上策，唯憑仁義是中原。',64,'全唐诗/poet.song.22000.json','["自古禦戎無上策，唯憑仁義是中原。", "王師問罪固能道，天子蒙塵爭忍聞。", "二晉亂亡成茂草，三君屈辱落陳編。", "公閭延廣何人也，始信興邦亦一言。"]'),
('63a608b3-95f6-400e-80f8-1b981cc85ef0','教勸吟','邵雍','宋','宋诗','song-poetry','','[]','若聖與人吾豈敢，空言猶足慰虛生。',64,'全唐诗/poet.song.22000.json','["若聖與人吾豈敢，空言猶足慰虛生。", "明開教勸用常道，永使子孫持善名。", "此日貽謨情未顯，他時受賜事非輕。", "庶幾此意流天下，天下何由不太平。"]'),
('df25ef58-01bb-4fe2-a5bd-7f50a0c701c0','不善吟','邵雍','宋','宋诗','song-poetry','','[]','悲哉不善人，稟此凶戾德。',24,'全唐诗/poet.song.22000.json','["悲哉不善人，稟此凶戾德。", "非唯敗人家，又能敗人國。"]'),
('5914dc83-877b-413d-802a-6e43dba55a20','多事吟','邵雍','宋','宋诗','song-poetry','','[]','多事招憂，多疑招悶。',20,'全唐诗/poet.song.22000.json','["多事招憂，多疑招悶。", "多與招吝，多取招損。"]'),
('6366bb6a-a893-4563-af7b-b56d17558d4b','處身吟','邵雍','宋','宋诗','song-poetry','','[]','君子處身，寧人負己，己無負人。',30,'全唐诗/poet.song.22000.json','["君子處身，寧人負己，己無負人。", "小人處事，寧己負人，無人負己。"]'),
('337f3548-89f5-40ed-bf86-a510955568fb','觀性吟','邵雍','宋','宋诗','song-poetry','','[]','千萬年之人，千萬年之事。',36,'全唐诗/poet.song.22000.json','["千萬年之人，千萬年之事。", "千萬年之情，千萬年之理。", "惟學之所能，坐而爛觀爾。"]'),
('9140d41b-223b-4a12-a536-7a282093e072','觀物吟','邵雍','宋','宋诗','song-poetry','','[]','居暗觀明，居靜觀動。',40,'全唐诗/poet.song.22000.json','["居暗觀明，居靜觀動。", "居簡觀繁，居輕觀重。", "所居者寡，所觀則衆。", "匪居匪觀，衆寡何用。"]'),
('9da14f19-6824-4c82-8670-7c1bf1d2a40f','答和吳傳正贊善二首  其一','邵雍','宋','宋诗','song-poetry','','[]','洛陽城裏一愚夫，十許年來不讀書。',32,'全唐诗/poet.song.22000.json','["洛陽城裏一愚夫，十許年來不讀書。", "老去情懷難狀處，淡煙寒月映松踈。"]'),
('2e3e773f-4a9f-4b4f-a5e5-f5de6b9348ca','答和吳傳正贊善二首  其二','邵雍','宋','宋诗','song-poetry','','[]','樂靜豈無病，好閑終有心。',24,'全唐诗/poet.song.22000.json','["樂靜豈無病，好閑終有心。", "爭如自得者，與世善浮沉。"]'),
('c964adcb-3dbf-4e7b-b80f-9c73782bbc88','是非吟','邵雍','宋','宋诗','song-poetry','','[]','是短非長，好丹非素。',40,'全唐诗/poet.song.22000.json','["是短非長，好丹非素。", "一生區區，未免愛惡。", "愛惡不去，何由是非。", "愛惡既去，是非何爲。"]'),
('0ced7a25-d657-4d24-af62-217b3b670045','洗心吟','邵雍','宋','宋诗','song-poetry','','[]','人多求洗身，殊不求洗心。',48,'全唐诗/poet.song.22000.json','["人多求洗身，殊不求洗心。", "洗身去塵垢，洗心去邪淫。", "塵垢用水洗，邪淫非能淋。", "必欲去心垢，須彈無絃琴。"]'),
('e2dd556b-9efa-4650-a04d-8f8d7f1c1fac','見物吟','邵雍','宋','宋诗','song-poetry','','[]','見物即謳吟，何嘗曾用意。',24,'全唐诗/poet.song.22000.json','["見物即謳吟，何嘗曾用意。", "閑將篋笥詩，靜看人間事。"]'),
('2c1f4cf2-9b61-40ff-8bb7-9d61b2051616','力穡吟','邵雍','宋','宋诗','song-poetry','','[]','春時耕種，夏時耘耨。',40,'全唐诗/poet.song.22000.json','["春時耕種，夏時耘耨。", "秋時收治，冬時用受。", "雨露不愆，既苗既秀。", "水旱爲災，尚罹其咎。"]'),
('8fc97dd7-419c-48e7-a3f0-60421e36f70c','六十六歲吟','邵雍','宋','宋诗','song-poetry','','[]','六十有六歲，暢然持酒盃。',48,'全唐诗/poet.song.22000.json','["六十有六歲，暢然持酒盃。", "少無他得志，老有此開懷。", "往往英心動，時時秀句來。", "尚收三百首，自謂敵瓊瓌。"]'),
('918202e1-d268-445e-ae4f-26371d6a3850','寬猛吟','邵雍','宋','宋诗','song-poetry','','[]','寬則民慢，猛則民殘。',20,'全唐诗/poet.song.22000.json','["寬則民慢，猛則民殘。", "寬猛相濟，其民自安。"]'),
('740f7b6c-b894-4364-b898-facecbfe3fc7','小道吟','邵雍','宋','宋诗','song-poetry','','[]','藝雖小道，事亦繫人。',20,'全唐诗/poet.song.22000.json','["藝雖小道，事亦繫人。", "苟不造微，焉能入神。"]'),
('f58c1694-05c0-4616-ab7f-2faa6cdc8b76','得失吟','邵雍','宋','宋诗','song-poetry','','[]','人有賢愚，事無巨細。',20,'全唐诗/poet.song.22000.json','["人有賢愚，事無巨細。", "得不艱難，失必容易。"]'),
('c647f9f1-7771-4abd-beaa-4a4d6822aed9','薰蕕吟','邵雍','宋','宋诗','song-poetry','','[]','善惡之間，薰蕕可究。',20,'全唐诗/poet.song.22000.json','["善惡之間，薰蕕可究。", "近薰必香，近蕕必臭。"]'),
('092606f5-a2b7-4c9e-9d60-95574700e7ec','好惡吟','邵雍','宋','宋诗','song-poetry','','[]','惡死好生，去害就利。',20,'全唐诗/poet.song.22000.json','["惡死好生，去害就利。", "天下之人，其情無異。"]'),
('54e7b4c8-cf58-42d6-95a6-7f746d439b6c','歲暮吟  其一','邵雍','宋','宋诗','song-poetry','','[]','此情人不知，亦嘗歎遲暮。',24,'全唐诗/poet.song.22000.json','["此情人不知，亦嘗歎遲暮。", "雖則歎遲暮，柰何難分付。"]'),
('625f28dd-490b-44e4-85fc-5835a2c0ab7b','歲暮吟  其二','邵雍','宋','宋诗','song-poetry','','[]','此情人不知，亦嘗歎遲久。',24,'全唐诗/poet.song.22000.json','["此情人不知，亦嘗歎遲久。", "雖則歎遲久，柰何人不受。"]'),
('0db13258-0c15-4c08-9d23-4c19e46cd4e6','安分吟','邵雍','宋','宋诗','song-poetry','','[]','輕得易失，多謀少成。',20,'全唐诗/poet.song.22000.json','["輕得易失，多謀少成。", "德無盡利，善無近名。"]'),
('6972bb73-c6a8-49fa-a672-94c85496848d','由聽吟','邵雍','宋','宋诗','song-poetry','','[]','由聽而失，以聽爲賓。',20,'全唐诗/poet.song.22000.json','["由聽而失，以聽爲賓。", "而今而後，何復信人。"]'),
('86db51bb-3362-49b7-b4a5-5da5cb196ce9','詩畫吟  其一','邵雍','宋','宋诗','song-poetry','','[]','畫筆善狀物，長于運丹青。',84,'全唐诗/poet.song.22000.json','["畫筆善狀物，長于運丹青。", "丹青入巧思，萬物無遁形。", "詩畫善狀物，長于運丹誠。", "丹誠入秀句，萬物無遁情。", "詩者人之志，言者心之聲。", "志因言以發，聲因律而成。", "多識于鳥獸，豈止毛與翎。"]'),
('c3685eea-81f4-4f2c-891c-c3da98670e6f','詩畫吟  其二','邵雍','宋','宋诗','song-poetry','','[]','多識于草木，豈止枝與莖。',204,'全唐诗/poet.song.22000.json','["多識于草木，豈止枝與莖。", "不有風雅頌，何由知功名。", "不有賦比興，何由知廢興。", "觀朝廷盛事，壯社稷威靈。", "有湯武締構，無幽厲欹傾。", "知得之艱難，肯失之驕矜。", "去巨蠹奸邪，進不世賢能。", "擇陰陽粹美，索天地精英。", "籍江山清潤，揭日月光榮。", "收之爲民極，著之爲國經。", "播之于金石，奏之于大庭。", "感之以人心，告之以神明。", "人神之胥悅，此所謂和羹。", "既有虞舜歌，豈無臯陶賡。", "既有仲尼刪，豈無季札聽。", "必欲樂天下，捨詩安足憑。", "得吾之緒餘，自可致昇平。"]'),
('07979a77-9d89-4595-8b75-c9ebdf7dc32c','詩史吟','邵雍','宋','宋诗','song-poetry','','[]','史筆善記事，長于炫其文。',288,'全唐诗/poet.song.22000.json','["史筆善記事，長于炫其文。", "文勝則實喪，徒憎口云云。", "詩史善記事，長于造其真。", "真勝則華去，非如目紛紛。", "天下非一事，天下非一人。", "天下非一物，天下非一身。", "皇王帝伯時，其人長如存。", "百千萬億年，其事長如新。", "可以辨庶政，可以齊黎民。", "可以述祖考，可以訓子孫。", "可以尊萬乘，可以嚴三軍。", "可以進諷諫，可以揚功勳。", "可以移風俗，可以厚人倫。", "可以美教化，可以和踈親。", "可以正夫婦，可以明君臣。", "可以贊天地，可以感鬼神。", "規人何切切，誨人何諄諄。", "送人何戀戀，贈人何懃懃。", "無歲無嘉節，無月無嘉辰。", "無時無嘉景，無日無嘉賓。", "樽中有美祿，坐上無妖氛。", "胸中有美物，心上無埃塵。", "忍不用大筆，書字如車輪。", "三千有餘首，布爲天下春。"]'),
('0c218597-a570-49a0-b3af-acb8bb9a0206','演繹吟  其一','邵雍','宋','宋诗','song-poetry','','[]','萬事入沉吟，其來味更深。',48,'全唐诗/poet.song.22000.json','["萬事入沉吟，其來味更深。", "雖然曾過眼，須是更經心。", "過眼未盡見，經心肯儘尋。", "儘尋能得見，方始是真金。"]'),
('422facff-20e1-49ee-aa75-e4b80d118e60','演繹吟  其二','邵雍','宋','宋诗','song-poetry','','[]','何者是真金，真金入骨沉。',48,'全唐诗/poet.song.22000.json','["何者是真金，真金入骨沉。", "飽曾經煅煉，足得不沉吟。", "到手何須眼，行身敢放心。", "放心然後樂，天下有知音。"]'),
('03446d97-9695-42ae-8de8-e76dc15a9241','演繹吟  其三','邵雍','宋','宋诗','song-poetry','','[]','何者謂知音，知音只在心。',48,'全唐诗/poet.song.22000.json','["何者謂知音，知音只在心。", "肝脾無效驗，鍾鼓漫搜尋。", "既若能開物，何須更鼓琴。", "來儀非爲鳳，只是感人深。"]'),
('48975e63-e48b-42f1-955f-f89039e8c614','演繹吟  其四','邵雍','宋','宋诗','song-poetry','','[]','何者謂來儀，來儀意不低。',48,'全唐诗/poet.song.22000.json','["何者謂來儀，來儀意不低。", "有身皆衎衎，無物不熙熙。", "一國若一物，四方猶四支。", "巍巍乎堯舜，何得而名之。"]'),
('4ddf241b-62f3-4b93-9d88-df08fd5f90cd','史畫吟','邵雍','宋','宋诗','song-poetry','','[]','史筆善記事，畫筆善狀物。',96,'全唐诗/poet.song.22000.json','["史筆善記事，畫筆善狀物。", "狀物與記事，二者各得一。", "詩史善記意，詩畫善狀情。", "狀情與記意，二者皆能精。", "狀情不狀物，記意不記事。", "形容出造化，想像成天地。", "體用自此分，鬼神無敢異。", "詩者豈于此，史畫而已矣。"]'),
('73790579-a6ac-43b1-9cab-1f445e88c9d8','好勝吟','邵雍','宋','宋诗','song-poetry','','[]','人無好勝，事無過求。',40,'全唐诗/poet.song.22000.json','["人無好勝，事無過求。", "好勝多辱，過求多憂。", "憂辱並至，道德弗遊。", "不止人患，身亦是仇。"]'),
('538718de-ddb4-40ff-b385-75e34f7263c6','治心吟','邵雍','宋','宋诗','song-poetry','','[]','心親于身，身親于人。',30,'全唐诗/poet.song.22000.json','["心親于身，身親于人。", "不能治心，焉能治身。", "不能治身，焉能治人。"]'),
('d10fa47b-01c2-4cfd-9303-281888e80c9d','吾廬吟','邵雍','宋','宋诗','song-poetry','','[]','吾亦愛吾廬，吾廬似野居。',48,'全唐诗/poet.song.22000.json','["吾亦愛吾廬，吾廬似野居。", "性隨天共淡，身與世俱疎。", "遍地長芳草，滿床堆亂書。", "自從無事後，更不著工夫。"]'),
('3e36064e-41c2-4916-8128-16596433f0e4','人靈吟','邵雍','宋','宋诗','song-poetry','','[]','天地生萬物，其間人最靈。',36,'全唐诗/poet.song.22000.json','["天地生萬物，其間人最靈。", "既爲人之靈，須有人之情。", "若無人之情，徒有人之形。"]'),
('36bab0a6-32c5-4d9f-a123-7008c73287b7','過眼吟','邵雍','宋','宋诗','song-poetry','','[]','紛紛過眼不須驚，利害相磨卒未平。',64,'全唐诗/poet.song.22000.json','["紛紛過眼不須驚，利害相磨卒未平。", "伎倆雖多無實效，聰明到了是虛名。", "溫涼寒熱四時事，甘苦辛酸萬物情。", "除却此心皆外物，此心猶恐未全醒。"]'),
('c0dbc3e6-43c6-4d97-92aa-5c85d0c712c9','災來吟','邵雍','宋','宋诗','song-poetry','','[]','災自外來，猶可消除。',30,'全唐诗/poet.song.22000.json','["災自外來，猶可消除。", "災自內來，何由支梧。", "天人之間，內外察諸。"]'),
('dd389354-a02f-45d4-8b0c-e5c2bc755bc0','內外吟','邵雍','宋','宋诗','song-poetry','','[]','目耳鼻口，人之戶牖。',40,'全唐诗/poet.song.22000.json','["目耳鼻口，人之戶牖。", "心膽脾腎，人之中霤。", "內若能守，外自不受。", "內若無守，外何能久。"]'),
('5997acdd-45ca-4c04-9e20-cdc5ce8804c1','名利吟','邵雍','宋','宋诗','song-poetry','','[]','重之以名，見人之情。',42,'全唐诗/poet.song.22000.json','["重之以名，見人之情。", "厚之以利，見人之意。", "情意內也，內重則外輕。", "名利外也，內賤則外貴。"]'),
('d35f5d90-e487-400d-93e3-831377d5fdb4','名實吟','邵雍','宋','宋诗','song-poetry','','[]','內無是實，外有是名，小人故矜。',30,'全唐诗/poet.song.22000.json','["內無是實，外有是名，小人故矜。", "外無是名，內有是實，君子何失。"]'),
('2a0aca6b-6d36-4d3d-96a8-587f0aaa384c','性情吟','邵雍','宋','宋诗','song-poetry','','[]','君子任性，小人任情。',20,'全唐诗/poet.song.22000.json','["君子任性，小人任情。", "任性則近，任情則遠。"]'),
('3c625ce2-7470-44bf-a863-555321a20d7d','丁寧吟','邵雍','宋','宋诗','song-poetry','','[]','人無忽略，事貴丁寧。',20,'全唐诗/poet.song.22000.json','["人無忽略，事貴丁寧。", "忽略近薄，丁寧近誠。"]'),
('f5b23501-d16e-4b48-943b-2c5c6c602e85','疑信吟','邵雍','宋','宋诗','song-poetry','','[]','人無輕信，事無多疑。',20,'全唐诗/poet.song.22000.json','["人無輕信，事無多疑。", "輕信招釁，多疑招離。"]'),
('9eed39da-32e4-4a2e-a961-e539ae137566','治亂吟','邵雍','宋','宋诗','song-poetry','','[]','君子小人，亦常相半。',20,'全唐诗/poet.song.22000.json','["君子小人，亦常相半。", "時止時行，或治或亂。"]'),
('482444cc-3901-40eb-b21c-676762db6320','有時吟','邵雍','宋','宋诗','song-poetry','','[]','龍不冬躍，螢能夜飛。',20,'全唐诗/poet.song.22000.json','["龍不冬躍，螢能夜飛。", "小人君子，而皆有時。"]'),
('4f76bdd9-3b26-4a0d-83fd-b7c72c049473','忠厚吟','邵雍','宋','宋诗','song-poetry','','[]','小人斯須，君子長久。',20,'全唐诗/poet.song.22000.json','["小人斯須，君子長久。", "斯須傾邪，長久忠厚。"]'),
('0ea9cf44-dce7-4bac-8f34-5a46dd43ef07','窮冬吟','邵雍','宋','宋诗','song-poetry','','[]','十二月將終，還驚歲律窮。',48,'全唐诗/poet.song.22000.json','["十二月將終，還驚歲律窮。", "藏冰方北陸，解凍未東風。", "草昧徒尋綠，花梢强覓紅。", "探春春不見，元只在胸中。"]'),
('16cb2410-48e4-47d8-9a21-7ef4d80e5ed5','知非吟','邵雍','宋','宋诗','song-poetry','','[]','今日已前事，知非心可憑。',48,'全唐诗/poet.song.22000.json','["今日已前事，知非心可憑。", "虛言安足道，實行又何矜。", "無藥醫衰老，有詩歌聖明。", "縱然時飲酒，未肯學劉伶。"]'),
('ad72a21a-f43a-4ea9-a418-1d48ce7e3e32','冬至吟','邵雍','宋','宋诗','song-poetry','','[]','冬至子之半，天心無改移。',48,'全唐诗/poet.song.22000.json','["冬至子之半，天心無改移。", "一陽初起處，萬物未生時。", "玄酒味方淡，大音聲正希。", "此言如不信，更請問庖犧。"]'),
('a6bc180d-48b2-4a49-ab00-51fe11e23e3a','頭白吟','邵雍','宋','宋诗','song-poetry','','[]','頭白已多時，況能垂白髭。',48,'全唐诗/poet.song.22000.json','["頭白已多時，況能垂白髭。", "不如猶甚幸，竊比未全衰。", "潤屋雖無鏹，承家却有兒。", "敢言貧淨潔，似我亦應稀。"]'),
('d7f67d5e-881f-4530-b82e-ffdf09cb4b01','談詩吟','邵雍','宋','宋诗','song-poetry','','[]','詩者人之志，非詩志莫傳。',48,'全唐诗/poet.song.22000.json','["詩者人之志，非詩志莫傳。", "人和心盡見，天與意相連。", "論物生新句，評文起雅言。", "興來如宿構，未始用雕鎸。"]'),
('360fa498-44f4-406e-8dbb-af275c24ae10','繩水吟','邵雍','宋','宋诗','song-poetry','','[]','水能平而不能直，繩能直而不能平。',32,'全唐诗/poet.song.22000.json','["水能平而不能直，繩能直而不能平。", "安得繩水爲人情，而使天下都無爭。"]'),
('0a75023d-14a2-4b12-8537-3739ea63af0f','刑名吟','邵雍','宋','宋诗','song-poetry','','[]','君子多近名，小人多近刑。',24,'全唐诗/poet.song.22000.json','["君子多近名，小人多近刑。", "善惡有異同，一歸與任情。"]'),
('8804d473-78f8-449e-9714-3e957b8ab03a','陰陽吟','邵雍','宋','宋诗','song-poetry','','[]','陽行一，陰行二。',32,'全唐诗/poet.song.22000.json','["陽行一，陰行二。", "一主天，二主地。", "天行六，地行四。", "四主形，六主氣。"]'),
('040599b3-7307-42f5-8e72-4ecf1a01f922','人事吟','邵雍','宋','宋诗','song-poetry','','[]','人有去就，事無低昂。',30,'全唐诗/poet.song.22000.json','["人有去就，事無低昂。", "跡有疎密，人無較量。", "能此四者，自然久長。"]'),
('ae885a9c-7aa1-42a9-a06e-81bbd4734639','內外吟  其一','邵雍','宋','宋诗','song-poetry','','[]','衣冠嚴整，謂之外修。',30,'全唐诗/poet.song.22000.json','["衣冠嚴整，謂之外修。", "行義純潔，謂之內修。", "內外俱修，何人不求。"]'),
('94f040ce-f7cf-496b-8548-2d6a4f976d13','內外吟  其二','邵雍','宋','宋诗','song-poetry','','[]','衣冠不整，謂之外隋。',30,'全唐诗/poet.song.22000.json','["衣冠不整，謂之外隋。", "行義不修，謂之內惰。", "內外俱惰，何人不唾。"]'),
('738df5c5-457e-4555-9313-1c5edba0bec1','盛衰吟','邵雍','宋','宋诗','song-poetry','','[]','克肖子孫，振起家門。',30,'全唐诗/poet.song.22000.json','["克肖子孫，振起家門。", "不肖子孫，破敗家門。", "猗嗟子孫，盛衰之根。"]'),
('22f40dc4-be8e-47e2-903c-010c2c321f7c','死生吟','邵雍','宋','宋诗','song-poetry','','[]','學仙欲不死，學佛欲再生。',60,'全唐诗/poet.song.22000.json','["學仙欲不死，學佛欲再生。", "再生與不死，二者人果能。", "設使人果能，方始入于情。", "賞哉林下人，不爲人所惜。", "哀哉公與卿，重爲人所惑。"]'),
('80e5d162-f305-44d3-807f-aa6b7a90b9b2','生日吟','邵雍','宋','宋诗','song-poetry','','[]','三萬五千日，伊予享此身。',48,'全唐诗/poet.song.22000.json','["三萬五千日，伊予享此身。", "當時纔作物，此際始爲人。", "久負陰陽力，終虧父母恩。", "一盃爲壽酒，床下列兒孫。"]'),
('98b8ac96-a046-4db8-8f20-83ef8a20e814','時事吟  其一','邵雍','宋','宋诗','song-poetry','','[]','時之來兮其勢可乘，時之去兮其勢遂生。',38,'全唐诗/poet.song.22000.json','["時之來兮其勢可乘，時之去兮其勢遂生。", "前日之事兮今日不行，今日之事兮後來必更。"]'),
('87783da2-debf-42c1-bae9-a921e3868b40','時事吟  其二','邵雍','宋','宋诗','song-poetry','','[]','時久則患生，事久則弊生。',22,'全唐诗/poet.song.22000.json','["時久則患生，事久則弊生。", "弊患相仍，人何以寧。"]'),
('5ec7028a-6eef-4169-af49-ad7d6e00a8fc','不知吟','邵雍','宋','宋诗','song-poetry','','[]','不知陰陽，不知天地。',30,'全唐诗/poet.song.22000.json','["不知陰陽，不知天地。", "不知人情，不知物理。", "强爲人師，寧不自愧。"]'),
('ec474a3b-2d39-40ef-afc6-f2ba2084632b','水火吟','邵雍','宋','宋诗','song-poetry','','[]','水火得其御，交而成既濟。',48,'全唐诗/poet.song.22000.json','["水火得其御，交而成既濟。", "水火失其御，焚溺可立至。", "不止水與火，萬事盡如此。", "只知用水火，不知水火義。"]'),
('099c53f7-2d81-4a1f-9d40-e0293052eb04','中原吟','邵雍','宋','宋诗','song-poetry','','[]','中原之師，仁義爲主。',20,'全唐诗/poet.song.22000.json','["中原之師，仁義爲主。", "仁義既無，四夷來侮。"]'),
('c939c618-01a1-49b8-abc8-a2a0c36c602a','喜飲吟','邵雍','宋','宋诗','song-poetry','','[]','堯夫喜飲酒，飲酒喜全真。',72,'全唐诗/poet.song.22000.json','["堯夫喜飲酒，飲酒喜全真。", "不喜成酩酊，只喜成微醺。", "微醺景何似，襟懷如初春。", "初春景何似，天地纔絪紜。", "不知身是人，不知人是身。", "只知身與人，與天都未分。"]'),
('c5e5854f-d06f-4ab2-b8eb-eca58bde0e89','所感吟','邵雍','宋','宋诗','song-poetry','','[]','人生無定準，事體有多端。',48,'全唐诗/poet.song.22000.json','["人生無定準，事體有多端。", "客宦危疑處，家書子細看。", "既曾憂險阻，方信喜平安。", "男子平生事，須于痛定觀。"]'),
('4eea704d-4343-4c10-92d2-ddb88cbff47d','行止吟','邵雍','宋','宋诗','song-poetry','','[]','時止則須止，時行則可行。',24,'全唐诗/poet.song.22000.json','["時止則須止，時行則可行。", "時行與時止，人力莫經營。"]'),
('159653f1-9831-406c-bd0c-c043a00ad1aa','太平吟','邵雍','宋','宋诗','song-poetry','','[]','太平時世園亭內，豐稔歲年村落間。',32,'全唐诗/poet.song.22000.json','["太平時世園亭內，豐稔歲年村落間。", "情味一般難狀處，風煙草木盡閑閑。"]'),
('e8cfed63-cf03-4fb1-a827-e1b4efe289c7','探春吟','邵雍','宋','宋诗','song-poetry','','[]','草色依稀綠，花稍隠約紅。',24,'全唐诗/poet.song.22000.json','["草色依稀綠，花稍隠約紅。", "一般難道說，如醉在心中。"]'),
('9307aff0-40fa-4665-afbf-9d661f466322','不出吟','邵雍','宋','宋诗','song-poetry','','[]','冬夏遠難出，止行南北園。',24,'全唐诗/poet.song.22000.json','["冬夏遠難出，止行南北園。", "如逢好風景，亦可至三天。"]'),
('e53aed6e-d779-4563-af0c-b1c4a4622080','不善吟','邵雍','宋','宋诗','song-poetry','','[]','不良之人，稟氣非正。',40,'全唐诗/poet.song.22000.json','["不良之人，稟氣非正。", "蛇蝎其情，豺狼其性。", "至良之人，稟氣清明。", "金玉其性，芝蘭其情。"]'),
('4d19ac2d-ed62-42f8-be69-ce18bf679875','不同吟','邵雍','宋','宋诗','song-poetry','','[]','君子之人，與己非比。',40,'全唐诗/poet.song.22000.json','["君子之人，與己非比。", "聞善則樂，見賢則喜。", "小人之人，與己非惡。", "聞善則憎，見賢則怒。"]'),
('1d00371d-6f3d-4e03-b374-28b68e3cdf5d','得失吟','邵雍','宋','宋诗','song-poetry','','[]','時難得而易失，心雖悔而何追。',28,'全唐诗/poet.song.22000.json','["時難得而易失，心雖悔而何追。", "不知老之已至，不知志與願違。"]'),
('917393b1-ade7-479d-b8e8-dc09e27fdf6a','痛矣吟','邵雍','宋','宋诗','song-poetry','','[]','痛矣時難得，悲哉道未傳。',24,'全唐诗/poet.song.22000.json','["痛矣時難得，悲哉道未傳。", "今年年已盡，明日是明年。"]'),
('8ec7c88d-f72a-46e8-be6b-b740eebe9eb4','歲除吟','邵雍','宋','宋诗','song-poetry','','[]','半百已華顛，如今更皓然。',48,'全唐诗/poet.song.22000.json','["半百已華顛，如今更皓然。", "自知爲士子，人訝學神仙。", "風月難忘酒，雲山不著錢。", "行年六十六，明日又添年。"]'),
('921e2044-5e48-4b18-9a72-062a6f8b3766','筆興吟','邵雍','宋','宋诗','song-poetry','','[]','窗晴氣和暖，酒美手柔軟。',24,'全唐诗/poet.song.22000.json','["窗晴氣和暖，酒美手柔軟。", "興逸情撩亂，筆落春花爛。"]'),
('c7ca54a6-3734-409b-b8b5-5438732c1ea5','影論吟','邵雍','宋','宋诗','song-poetry','','[]','性在體內，影在形外。',40,'全唐诗/poet.song.22000.json','["性在體內，影在形外。", "性往體隨，形行影會。", "體性不存，形影安在。", "影外之言，曾何足怪。"]'),
('e1973b69-6355-40a9-a71d-41a5f73b218b','憂喜吟','邵雍','宋','宋诗','song-poetry','','[]','大喜與大憂，二者莫能寐。',24,'全唐诗/poet.song.22000.json','["大喜與大憂，二者莫能寐。", "二者若能寐，何憂事不治。"]'),
('ec889108-8527-4b19-9ad5-114420616520','窺開吟  其一','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破時。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破時。", "一身都是我，瘦了又還肥。"]'),
('e748bd6a-54d2-48d3-a0cd-ebbae8f6ac47','窺開吟  其二','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破時。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破時。", "能將函谷塞，只用一丸泥。"]'),
('57a6a20e-be19-4ad2-b862-5769c295e082','窺開吟  其三','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破時。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破時。", "正如携寶劍，切玉過如泥。"]'),
('1aa187a3-00e1-452b-a7c4-045f0841b5c6','窺開吟  其四','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破時。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破時。", "渴多逢美酒，病後遇良醫。"]'),
('75bcc780-560f-47fd-aa63-c01bd0cb5131','窺開吟  其五','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破時。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破時。", "能將一箇字，善解百年迷。"]'),
('554c4153-3033-449f-a22e-890df7693c0c','窺開吟  其六','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破時。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破時。", "情中明事體，理外見天機。"]'),
('3ec5e214-ccf6-40f4-a30e-95a264960a9b','窺開吟  其七','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破時。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破時。", "可嗟兼可唾，堪鄙又堪嗤。"]'),
('c90ae5d2-3d1f-4223-89e5-6417ff8709fc','窺開吟  其八','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破初。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破初。", "不堪將勸誡，止可與嗟吁。"]'),
('2d020f18-11b1-4802-9139-0bd3a9277e9a','窺開吟  其九','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破前。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破前。", "止堪令執筆，不可使持權。"]'),
('58a570b0-2ffe-422e-838a-518e28b41520','窺開吟  其一○','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破休。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破休。", "止堪初看望，不可久延留。"]'),
('c445934e-93f8-489d-a893-2934946061c3','窺開吟  其一一','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破時。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破時。", "欲知花爛熳，便是葉離披。"]'),
('cf2f029e-c832-44ce-aaab-4d72361ea2c8','窺開吟  其一二','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破時。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破時。", "有權能處置，更狡待何爲。"]'),
('b35584f4-e6a5-47f9-b2fe-5308ffd69fc8','窺開吟  其一三','邵雍','宋','宋诗','song-poetry','','[]','物理窺開後，人情照破間。',24,'全唐诗/poet.song.22000.json','["物理窺開後，人情照破間。", "敢言天下事，到手又何難。"]'),
('9f162432-867b-40fc-ac08-b86eb4fa8f86','喜歡吟','邵雍','宋','宋诗','song-poetry','','[]','平生喜飲酒，飲酒喜輕醇。',48,'全唐诗/poet.song.22000.json','["平生喜飲酒，飲酒喜輕醇。", "不喜大段醉，只便微带醺。", "融怡如再少，和煦似初春。", "亦恐難名狀，兩儀仍未分。"]'),
('2a33a5cc-550a-4a8d-b1a3-fce75eca9c96','貴賤吟','邵雍','宋','宋诗','song-poetry','','[]','繫自我者，可以力行。',40,'全唐诗/poet.song.22000.json','["繫自我者，可以力行。", "繫自人者，難乎力爭。", "貴爲萬乘，亦莫之矜。", "賤爲匹夫，亦莫之凌。"]'),
('5fb3a2f6-8b77-456a-94d2-57f5885ff625','措處吟','邵雍','宋','宋诗','song-poetry','','[]','在未定之時，當難處之地。',24,'全唐诗/poet.song.22000.json','["在未定之時，當難處之地。", "方事之危疑，見人之措置。"]'),
('2b3df2a7-a335-4c20-935f-800d074dbb12','費力吟','邵雍','宋','宋诗','song-poetry','','[]','事無巨細，人有得失。',20,'全唐诗/poet.song.22000.json','["事無巨細，人有得失。", "得之小心，失之費力。"]'),
('2af7684a-de75-42b5-b59c-b1d2b30ac465','不老吟','邵雍','宋','宋诗','song-poetry','','[]','人無不老理，日有再中時。',24,'全唐诗/poet.song.22000.json','["人無不老理，日有再中時。", "不老必無也，再中應有之。"]'),
('7ade2924-351e-4f8d-9dfb-b32644302515','代書寄陳章屯田','邵雍','宋','宋诗','song-poetry','','[]','執別而來二十春，忽飛書意一何勤。',64,'全唐诗/poet.song.22000.json','["執別而來二十春，忽飛書意一何勤。", "四方豈是少賢士，千里猶能思故人。", "世態見多知可否，物情諳久識疎親。", "我今老去甘衰朽，無補明時卧洛濱。"]'),
('1808cdd8-dc6f-465a-a612-b2f78e7a559a','長短吟','邵雍','宋','宋诗','song-poetry','','[]','君子喜淳誠，小人喜欺罔。',24,'全唐诗/poet.song.22000.json','["君子喜淳誠，小人喜欺罔。", "淳誠歲時長，欺罔日月短。"]'),
('91f74f86-77f0-4f9c-a8f9-1b801b6708bb','迷悟吟','邵雍','宋','宋诗','song-poetry','','[]','君子改過，小人飾非。',30,'全唐诗/poet.song.22000.json','["君子改過，小人飾非。", "改過終悟，飾非終迷。", "終悟福至，終迷禍歸。"]'),
('c6e1d767-9ef4-41be-b345-0ad95a5211b1','正性吟','邵雍','宋','宋诗','song-poetry','','[]','未生之前，不知其然。',40,'全唐诗/poet.song.22000.json','["未生之前，不知其然。", "既生之後，乃知有天。", "有天而來，止物之性。", "君子踐形，小人輕命。"]'),
('994da9a6-0c8f-4551-8c7e-bb76ebe34bb5','幽明吟','邵雍','宋','宋诗','song-poetry','','[]','明有日月，幽有鬼神。',40,'全唐诗/poet.song.22000.json','["明有日月，幽有鬼神。", "日月照物，鬼神依人。", "明由物顯，幽由人陳。", "人物不作，幽明何分。"]'),
('fa2b0496-ba16-429f-9f64-7fc53ee78e44','無靦吟','邵雍','宋','宋诗','song-poetry','','[]','事曾經見，物曾持鍊。',20,'全唐诗/poet.song.22000.json','["事曾經見，物曾持鍊。", "天地之間，俯仰無靦。"]'),
('41afb866-6803-4de8-8aa5-fbf656089c65','事體吟','邵雍','宋','宋诗','song-poetry','','[]','語言須中節，義理貴從宜。',24,'全唐诗/poet.song.22000.json','["語言須中節，義理貴從宜。", "可革仍三就，當行必再思。"]');
